INSERT INTO `book_chapter` VALUES (1334318503432396800, 1334318497132552192, 2, '第三章 另一次元空间的顾客', 5072, 0, '2022-05-15 11:46:52', '2022-05-15 11:46:52');
INSERT INTO `book_content` VALUES (3348337, 1334318184854036480, '&nbsp;&nbsp;&nbsp;&nbsp;初春的红日刚刚爬起来，一道身影逆着微光看着这住了十二年的庄子，心中微涩。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她将这座庄子环顾了一遍又一遍，仿佛要将庄子里的一草一木都刻在心里，不再忘却。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐，该出发了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘思路被打断，转过头不再回头看，从踏出这个庄门开始，她便知道有些事回不去了！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一辆豪华气派的鎏金红木马车停在闲庄大门外，鎏金的厢顶，镶金嵌宝的窗牖，香云水纹缎的帷裳处处彰显着土豪般的气派。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“呵、呵、呵”苏妈妈瞧着眼前这辆豪华马车，满心欢喜，双眼乐成了一道缝。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“苏妈妈这马车？”纤尘眉头微蹙，觉得眼前这辆马车豪华得太过张扬。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐，这是舅老爷的一份心意，如今，小姐的娘家舅舅再不是过去的小商小贩，可是大周界富甲一方的大商贾，小姐，我们十二年没回冉府，这次我们要风风光光、气气派派地回去，可不能让冉府的人小瞧了我们。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘轻摇了摇头，她知道舅舅是想给她撑面子，只是现在还不是撑面子的时候，“苏妈妈，下了山我们就换一辆马车。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈不解，为何小姐会驳了舅老爷的一番好意，抬眼一脸茫然地望向纤尘，“小姐这是为何呀？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘也不做旁的解释，回过身将闲庄大门锁上，不急不缓问道：“苏妈妈可知纤尘在闲庄学艺十二载，一直让舅舅瞒着冉府，谎报纤尘一直在舅舅家跑堂是为何？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈了然，眼眶瞬间灌满泪水。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她撇过脸将滚落脸颊的泪水擦去，语重心长，声音有些哽咽，“小姐，我知道您是个有大主意的人，你不想让冉府的人知道你学了大本事，也不想让冉府的人知道如今的沈家今非昔比，您韬光养晦只想为替夫人报仇；只是，只是小姐，报仇的那条路可不好走！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“不好走也得走。”纤尘心思沉稳不易喜形于色，淡淡然说着，就好像在和苏妈妈闹家常。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈看不出纤尘脸上的悲与伤，但是她能感觉到纤尘发自骨子里的坚定，心酸得又一把老泪横流。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈是纤尘母亲的陪嫁丫鬟当年的事她最清楚。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那天，老爷又来到院里，再次与夫人提起让出嫡母大夫人之位，夫人不同意就和老爷吵了起来，苏妈妈见老爷和夫人吵架，就将在院子里玩耍的小纤尘带回了屋。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;透过屋里的门缝，她们看见，老爷一记重重的耳光将夫人扇倒在地，随后拂袖愤然离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“娘亲……”小姐见到这一幕，猛然推开房门冲了出去将倒在地上的夫人扶起，“娘亲，爹爹为什么打你？”小姐稚嫩的声音触动了夫人的心，夫人再也没忍住一把抱过小纤尘，母女两哭在了一起。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姥爷才走没多久，姚氏又带着几个五大三粗，满身横肉的仆人进了院子，夫人见势不妙又让苏妈妈强行将小姐带回了屋。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“姐姐，我劝你还是自愿让出嫡母大夫人之位，免受那皮肉之苦，否则就不要怪妹妹。”姚氏的声音轻缓，说出来的话却如吐着信子的毒蛇。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“呸”夫人轻蔑地向姚氏啐了一口唾沫，姚氏气急便吩咐下人动手，夫人奋起反抗就要冲向姚氏，那姚氏被吓得后退时脚没踩稳摔倒在地。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一时间，血从姚氏的下体流出，大家都慌了神。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏小产，她一口咬定是夫人推了她，下人们也配合姚氏，一口咬定是夫人推了姚氏，夫人有口难辩，绝望中，夫人跳了院子里的那口水井。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;父亲打母亲，母亲被姚氏逼死，这一幕幕一桩桩都被刚满四岁的小纤尘看了个真切，为母报仇的种子也是那一刻，在她心里生了根。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐，夫人有您这样一个女儿，在天之灵也可以安息了，只是奴婢担心小姐，那冉府里的姚氏可不简单，她可是只披着羊皮的狼！”苏妈妈说着，手里的拳头情不自禁都紧捏了起来，恨得咬牙切齿的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的脸上倒是平静如水，她只是顿了顿，眼里闪过一丝犀利，苏妈妈说得没错，那姚氏一直披着贤良淑德的外衣，掩饰着自己吃人的本性，这样一个有心机、有城府的人对付起来确实不简单。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;然，那又如何？纤尘看向苏妈妈展出一个宽慰的笑来，“苏妈妈，那姚氏是披着羊皮的狼，我就是揭开羊皮打死狼的猎人，我不会有事的，你尽管放心”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈抹了一把眼泪，“放心，放心，奴婢知道小姐学了一身真本事，奴婢放心！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这十二年来，纤尘起早贪黑苦学医术，勤练武功，吃过多少苦，受过多少累，苏妈妈心里都清楚，她更知道如今的小姐已得闲庄庄主真传。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在纤尘心里苏妈妈早已不是什么奴婢而是她的家人，她拿出绢帕来替苏妈妈擦去脸颊的泪水，“别哭了苏妈妈，我们要开开心心的回去。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈收住泪，脸上挤出个笑来，“对，小姐说得对，我们要开开心心的回去，回去为夫人争口气。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;二人款步向马车走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;两匹俊美健壮的马儿，拉着一辆宽敞的土豪车厢奔跑在下山的小路上，车夫悠然地扬起马鞭，控制着马车匀速前进。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;山下，一辆马车马蹄飞速的敲击着地面，溅起尘土飞杨，向着山上疾驰而来，虽然是阳春三月，山上绿树成阴凉风徐徐而那赶车的人却是满头大汗。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“架…架…架…！”那人频繁地赶着马，满脸焦灼，时不时用手肘擦去额前豆大的汗水，不难想象他有急事，他在与时间赛跑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“吁……！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“吁……！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;幸好，两位驾马的人，同时拉紧了缰绳，拉停了马儿，避免了一次两辆马车交汇相撞的翻车事故。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;马车骤然停下带来的惯性冲击，让疾驰而来的那辆马车里的人不受控的滚到了车厢口，险些就要摔出马车。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“主子！”，阿峰赶紧蹿进车厢扶起顾子毅，“主子，您没事吧？都是属下的错……”阿峰心里又愧又急。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我没事，你快去拉马。”顾子毅打断阿峰，马儿受惊未定，若此时没人拉好缰绳恐马儿再次受惊乱跑带来危险，阿峰也明白这一点，快速扶起顾子毅便又回到自己的位子上拉起了马缰。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此路是通往闲庄的路，纤尘的耳朵敏锐，听到那马车里的人说话，声音气咽声丝，仿佛就剩下一口气吊着命，便断定这辆马车是赶去闲庄求医的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;师父云游在外，自己又离开了庄子，如今的闲庄空无一人，不能让人家白跑一趟，纤尘递了个眼神给苏妈妈。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈会意，掀开帘子问：“客家可是要去闲庄？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“正是，请问大娘闲庄还远吗？”阿峰拱手施礼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“不远，只是庄子上的主人都已离庄，很长一段时间也不会再回庄子，客家若是求医就去闲城的同善医行吧！”苏妈妈说完便关上了帘子吩咐车夫赶马。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“什么？”阿峰先是一愣，即刻就回过神来，“请等等，大娘可知闲庄的主人去了何处？我家主子不是生病而是中毒，此毒唯有闲庄之人可解，还请大娘指个明路，在哪里可以找到闲庄的主人？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘一听，车里的人是中毒，而且还是唯有闲庄可解的毒，柳眉微蹙，那人莫不是中了东阴人的腐尸酥骨油之毒？缓缓开口问道：“你家主子中的何毒？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的声音很是温柔，像三月里的春风，一扫阿峰焦灼的心带来的烦躁，只是主子中了什么毒，他不便对外人提起，“这个在下不便说。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;能让东阴人使用腐尸酥骨油来暗杀的人，大多身份尊贵，这样的人身边的侍卫一向小心谨慎，纤尘也不再追问，而是自己掀开帘子下了马车，端端向顾子毅的马车走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰只见一位紫衣仙女从眼前飘过，刚回过神来，那仙女已经上了自家马车，“姑娘，姑……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见仙女不顾马车里浓烈的腐尸臭，已经为自家主子查看起了伤口，阿峰也闭上了嘴。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;果真是中了东阴人的腐尸酥骨油之毒，手臂大面积腐烂，看来这毒是三天前中的，再不施救，他性命难保，“你们跟我走。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘向阿峰丢下这句话，便又回了自己的马车，吩咐车夫“我们回庄子。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;车夫是沈家的长工，为人忠厚老实，纤尘吩咐回庄，他二话没说，调转马头就打马回庄。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;听到纤尘对车夫说“回庄子”，阿峰心里一阵惊喜，心想这位姑娘定是闲庄的人，也扬起马鞭便跟在后面，直到闲庄。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;闲庄虽是一座用全竹打造出来的院子，布置的却十分雅致，花香满园，流水潺潺，亭台楼阁错落有致，主要由一间主房，两间耳房，一个小厨房和一间接诊室组成。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;进了庄子，纤尘便安排阿峰扶着他的主子到接诊室里躺下休息，又安排苏妈妈去准备浓盐水来，自己则在一堆子的瓶瓶罐罐里扒拉着。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;终于找到一个天青釉的小瓶子和一个玉白瓶子，她从白玉瓶子里倒出一粒药丸，“公子，这个是腐尸酥骨油之毒的解药，你快吃下。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348338, 1334318186313654272, '&nbsp;&nbsp;&nbsp;&nbsp;阿峰将躺在床上的顾子毅扶起，靠到床头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅现在身体的情况很糟糕，全身无法动弹不说疼痛从骨髓里散发出来，他的意识已经开始模糊，他不知道自己还能坚持多久。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰带他来闲庄治疗，也是抱着死马当成活马医的侥幸心态，他不怀疑纤尘，接过纤尘递来的药丸，毫不迟疑，眉头都没皱一下便吞了下去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;解药下肚，片刻之后，一股清凉游走在他的体内，他顿感浑身轻松，中毒后那种万虫噬骨一样的疼痛也渐渐退了下去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;接着纤尘又从天青釉的瓶子里取出一粒药丸，“公子，再把这颗药吃了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅同样毫无迟疑吞下药丸。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吞下这粒药丸后，他感觉这粒药丸很是神奇，身体里仿佛有一股暖流从他的胃里舒展开来，缓缓进入他的七经八脉之间，好像给他的身体带来了能量，“姑娘，我刚刚吃的什么药？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅的声音很虚弱，纤尘也柔声耐心回他，“温胃强心丸，由一些温胃的药和强心的药浓缩在一起混合而成的大蜜丸。”接着，纤尘很认真地看向顾子毅“你吃下后有感觉哪里不舒服吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“没有，我只觉得此药仿佛能给我的身体带来能量。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘莞尔一笑，“哦，那是因为它温胃强心，可提高身体的耐受力，预防过会我给你刮腐时，你体力不支引起的晕厥。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哦…！”对医学七窍通了六窍，一窍不通的顾子毅，轻轻地哦了一声，其实他也没太听明白什么是身体的耐受力，只当那就是能给他身体补充能量的药丸。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅吃下药丸，纤尘便去准备刮腐用的器材和药材。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;高浓度的盐水、糖盐水、药丸、刮腐用的小竹片、剪掉腐坏筋膜的小剪刀、麻沸散、用于防护的油纸衣、口罩、猪小肠做的手套……一个都不少，齐齐端进接诊室。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘将一个小木棒递给顾子毅，“这是咬牙棒，刮腐时会很疼，即便我用了麻沸散，刮腐的过程依旧很疼，疼到受不了的时候，你就将这个棒子放进嘴里，避免大叫时咬到自己舌头。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我不要。”顾子毅一脸嫌弃，笑话，他堂堂纪国的战神，在沙场上出生入死，受过多少伤，这点痛算什么？他不屑用这个咬牙棒。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘也不多说，将咬牙棒塞到顾子毅手里，“你不用，就拿在手里把玩吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;话毕，她转身就将油纸做成的防护服套在了衣服外，又带上油纸做的口罩和猪小肠做的手套。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅和阿峰第一次来闲城，也是第一次见到纤尘身上套的这身怪异的衣服，两人都惊得张大了嘴，盯着纤尘看了又看。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;每个初来闲城的患者都会被自己身上的这衣服惊讶到，纤尘早习以为常。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你们不用这样看着我，这些都是我师父发明的，师父给这身衣服起了个名字，叫防护服，它是用油纸做的，我手上带的叫手套，是用猪小肠做的，闲城同善医行的大夫给病人做外伤处理时都会穿上这身衣服，主要起到自我保护的作用。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;听完纤尘简单介绍了她这身行头，顾子毅和阿峰是懂非懂，两人非常有默契地点点头，异口同声“哦”了一声。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘也不纠结他们究竟听没听懂，因为这不重要，便吩咐阿峰“扶好他，我要开始了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘先将麻沸散抖落在顾子毅的伤口上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;等麻沸散起效的这段时间，纤尘像医生交代病情一样对顾子毅说：“东阴人的腐尸酥骨油之毒非草药之毒，实则是苗疆的一种蛊虫，此虫极小嗜血，见血后开始大量繁殖，繁殖期间产生的排泄物就是致命的毒素，我必须要将你每一寸腐肉都刮干净，刮去你手臂上所有的虫子，这毒才算真正解完，刮腐期间即便有麻沸散辅助依旧会很疼。”纤尘再次强调。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯，我知道了你刮便是。”顾子毅侃然正色挺直了腰板，完全一副不惧疼痛的模样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;当纤尘的小竹片刮在顾子毅的伤口上时，他才真正体会到什么是剥肤切骨之痛，紧咬牙关硬是没用那咬牙棒，纤尘都担心他会将自己的牙都咬碎了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;腐肉一点一点刮完，纤尘又用浓盐水冲洗顾子毅手臂上的伤口，浓盐水淋在顾子毅血淋淋的新肉上，疼得他身子都在颤抖，豆大的汗水像雨水一样从他的额间滴落，阿峰的一心也跟着一阵阵揪着疼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“腐尸酥骨油里的蛊虫怕火更怕盐水，遇浓盐水即死，所以我用浓盐水给你清洗伤口，只为彻底杀死残留的蛊虫，就快了，你再忍忍。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘边安抚顾子毅，边小心翼翼剪去他伤口处那些还沾粘着已经腐坏了的筋膜。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一炷香的时间，终于刮完腐，上好药包扎完，汗水已经湿透了顾子毅所有的衣裳，虚脱的他差点就要晕过去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“他出汗太多，快喂他喝碗盐糖水。”阿峰闻言，赶紧将事先准备好的盐糖水喂给顾子毅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;喝完盐糖水的顾子毅才缓过一点劲来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;许是解了毒，顾子毅一直紧绷的神经终于松了下来，疲惫和困意袭来无法抵挡，倒头便睡了过去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;刮腐之痛，痛不欲生，纤尘见过不少刮腐之人的鬼哭狼嚎，甚至还有宁死也不愿再接受刮腐之人，顾子毅硬是咬着牙一声都没吭挺了过来，纤尘暗自佩服顾子毅的铮铮男儿铁骨，禁不住细看了一眼睡下的顾子毅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这一眼，纤尘才发现顾子毅的美，他轮廓分明，皮肤如麦，脸上虽是一脸的病容，却依旧无法掩饰那沙场上铺天盖地的男儿气息，高挺的鼻和绝美的唇形，无一不在彰显着他的高贵与不凡，剑眉紧锁仿佛还有什么揪心的事藏在心里，让人忍不住想要去探索，想要去帮他抚平那皱着的眉心。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哎呀，自己都在胡思乱想什么？纤尘收回心神对阿峰说：“我给他包扎时上了麻沸散，可缓解他手臂的疼痛，估计他能睡上一会，你也可以休息一下。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘出了接诊室，苏妈妈进来收拾，阿峰是个有心的人，主动帮苏妈妈做事，当上了苏妈妈的帮手，他边帮苏妈妈清理废物边和苏妈妈攀谈。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;麻沸散的药效过了没多会，顾子毅便从疼痛中醒来，他用那只未受伤的手，强撑起自己虚弱的身子靠到了床头，透过接诊室的小窗，正好可以看到窗外的好风景。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;窗外桃花、杏花竞相开放，一阵风吹来，暗香相送，红白花雨随风飘落，坐在小亭里的纤尘，手捧着书，枕在石桌上看得很是专注，身处在花雨之中，她秀发微动，裙摆摇曳就像是位画中仙，看得顾子毅心里生出丝丝眷恋来，一时竟忘了疼痛。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“主子，您醒啦！”&nbsp;阿峰的突然进入，打断了顾子毅看风景。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嘶……”手臂上的痛再次袭来，顾子毅一扫脸上的眷恋，恢复了一如既往的冷峻的神色，“你都了解到些什么？”。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“主子，那位小姐是闲庄庄主唯一的弟子，在闲城大家都管她叫少庄主，不过奇怪的是，她是我们纪国人，这次出远门就是要回京都省亲。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰将他在苏妈妈那里打听到的信息，一五一十说给了顾子毅听。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗖”的一下，顾子毅挺直了背，他也感到匪夷所思，闲城一直不待见纪国，拒收纪国医者前去学医，那女子怎么可能是他们纪国人？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他竖起耳朵继续追问：“你说，她是闲庄庄主唯一的徒弟，还是我们纪国人，你确定？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯。”阿峰确定地点点头，“我去问过他们赶马的车夫，那车夫也说姑娘来自纪国。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅沉默。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;闲城医术甲天下，闲城不仅是大周十国人人敬仰的医学圣地，还控制着大周十国各国百分之八十的药材共计，闲城对大周十国各国都很友好，唯独对纪国，既不收纪国的学者也不同纪国往来，就连药材共计都是先满足其他国家，最后才轮到纪国。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;闲庄医术甲闲城，大周十国，各国无人不知无人不晓，闲城的主人其实就是闲庄的庄主，若闲庄少主真是纪国人，那为何纪国在闲城地位还会如此低下？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;直觉告诉顾子毅，闲庄定有不少故事，他又继续追问阿峰“你还探出了些什么？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰摇摇头“没了，主子，那苏妈妈警惕性很强，属下只打探到这些。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅本想吩咐阿峰去查，转而，他又想，还是先处理了盘踞在交州的东阴人再说。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一说到东阴人，还得从一个月前纪国的朝廷说起，一天早朝有人禀报，京中四品官员文侍郎，全家老小和仆从一百多人号人全部被杀，一个活口都没有。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;杀人者，还明目张胆在墙上留下血书——“小示惩戒，东阴人留。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;东阴人的猖狂与凶残顿时让朝堂之上，人心惶惶。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪武帝早有剿灭东阴人之心，无奈前几次围剿都以失败告终。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那远在交州的东阴人，仿佛有千里眼，顺风耳，每次纪国皇庭派遣军队对他们进行围剿，他们都能提前知晓，最后还能打纪国士兵个措手不及，导致每次围剿都损失惨重。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348339, 1334318187706163200, '&nbsp;&nbsp;&nbsp;&nbsp;纪国朝堂之上，呼吁剿灭东阴人的声音一天高过一天，然，朝堂之上却无人愿意主动请缨领兵前去剿灭东阴人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;理由无它，一则是怕心狠手辣的东阴人报复，累及家人；二则是纪国历年剿灭东阴人从未成功过，东阴人的凶悍诡异让朝堂之上的武将们不敢托大。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪国边境已许久无战事，纪国的战神，纪武帝最骁勇善战的儿子，三殿下瑞王顾子毅也已经闲散在家许多时日。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;是他再次披上战甲的时候了，高高在上的纪武帝，看着朝堂之上默不作声的文武百官，他心里已经有了盘算。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这些天，纪武帝心情颇有些烦闷，朝堂上这帮家伙，一提起东阴人，他们就同仇敌忾唾沫横飞，恨不能用口水都能将东阴人淹灭了；一提起派人去剿灭东阴人，大家又都默契地埋下头哑口不言。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“怂包，你们一个个都是怂包！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪武帝在朝堂发了一通脾气后，便将剿灭东阴人这个烫手山芋，丢给了顾子毅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅领兵出征。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;毫无例外，保密工作做得再好，东阴人还是已提前知晓，这次是领兵前来剿灭他们的将领是纪国的战神顾子毅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;东阴人在顾子毅行军进入交州城的一条必经之路上设下了埋伏，这条路是条山路，易守难攻，前几次纪国派来剿灭他们的士兵都折损在了这里，这次，他们也要将顾子毅和他的兵埋葬在这座山崖下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅他们遇到偷袭，东阴人知道带队的是一位王子还是纪国的战神，无人不在亢奋种，争先恐后想要夺取顾子毅的脑袋，以光耀自己的脸面。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅这次带的又全是他悉心督导出来的精锐，个个实力不差，双方实力相当，打得如火如荼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;最终，顾子毅还是带兵突围成功，只是他这次损失惨重，他自己中了东阴人的腐尸酥骨油之毒，不得不将突围出来的属下托付给交州将军曹卫照顾，自己则被阿峰带去了闲庄求医。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅心想，交州是闲城前往纪国京都的必经之地，少庄主要前往京都，必然经过交州，若能让少庄主在交州多做些停留，助自己一臂之力，那盘踞在交州的东阴人又何愁不能剿灭？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;想到这里顾子毅便吩咐“阿峰，快扶我去小亭。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在阿峰的搀扶下，顾子毅来到小亭，纤尘察觉到有人来，合上书抬眼看向顾子毅，“怎么不好好躺在床上休息，是手臂太疼受不了吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅看了一眼包扎成白粽子的手臂，不屑地笑了笑，“没有，刮腐之痛我都忍过来了，这点痛算得了什么？”接着，他便拱手抱拳向纤尘施礼，“纪国顾子毅，感谢姑娘的救命之恩。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪国，顾子毅？纤尘在脑海里搜索。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原来眼前这个挺拔俊朗的佳公子就是纪国的三皇子瑞王殿下顾子毅，传说他是纪国的战神，在保家卫国的战斗中十战十胜，敌国的将领听到他的名字都会瑟瑟发抖，也正是因为他的存在，纪国的边疆这些年来还算太平。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;怪不得自己会在他脸上看到铺天盖地沙场上的男儿气息。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘又在心里暗自苦笑，没想到自己救的这个病人，境遇竟和自己差不多，也是一个不招父亲待见，死了娘亲的人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那顾子毅虽然战功赫赫却不得纪武帝的宠爱，纪武帝宠爱云妃更宠爱云妃之子康王殿下顾子琛，这是大周十国众人皆知的事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘也暗自庆幸自己救的是瑞王，而不是纪国其他的王爷，至少他知道瑞王和康王关系不会太好。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那康王，正是冉府姚氏所出之女冉花楹未来的夫君，也就是纤尘未来的妹夫，然，纤尘对姚氏有恨，姚氏也未必容得下纤尘，若让康王知道纤尘是闲庄之人，难免不会传入姚氏的耳朵里，引起姚氏对自己的警惕。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪国边疆安定，瑞王搬师回朝，纪武帝就将瑞王的兵权虎符收了回去，转手就将虎符兵权交给康王，从此瑞王便以连连在外做战身心疲累为由不再上朝。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪武帝这样一通骚操作，瑞王和康王很难没有嫌隙，纤尘猜想即便瑞王知道自己是谁，也不会主动去与康王提起自己。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;也许是同命相怜的缘故，纤尘对顾子毅生出一丝好感，她起身回礼，“哪里、哪里，瑞王殿下客气了，我是个医者救死扶伤是医者的本份。”&nbsp;顾子毅听到纤尘唤自己瑞王殿下，暗吃一惊“你知我的身份？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘莞尔一笑，“纪国战神顾子毅赫赫有名，你都报上了名讳我岂有不知之理？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;同名同姓的人不在少数，不过在纪国，百姓不能与皇室重名，姑娘能猜到自己是瑞王也是情理之事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哈哈哈……”顾子毅爽朗一笑，“姑娘说的是，没想到我顾子毅的名字这么响亮，竟也传到了闲城，这座世外桃源。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘浅笑不语，伸手示意顾子毅坐下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅坐到纤尘对面，开门见山直奔主题“姑娘可是这闲庄的少主？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“是。”纤尘微微点了点头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅又问：“听说姑娘是我们纪国人，这次要回京都省亲？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘无奈地笑了，“是苏妈妈告诉你们的？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“少庄主莫怪，即便不是苏妈妈说，本王也能想办法查到，若少庄主真是要回京都省亲，本王希望少庄主能帮本王一个忙，事后，本王定当重谢！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;话闭，顾子毅又起身向纤尘拱手深施一礼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他态度诚恳礼数周全，让人不好直接拒绝，纤尘只好问道：“什么忙，殿下不防先说来听听，纤尘本事不大，不敢冒然答应殿下。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅晓之以理动之以情，大到江山社稷，小到寻常百姓家的柴米油盐酱醋茶，是念百姓之疾苦，独怆然而涕下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他自己都快把自己感动了，然，纤尘只是淡淡地看着他，脸上平静得像一片无风的湖面。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;待他一张一合的两片唇停了下来，纤尘才简明扼要地问：“瑞王殿下是想让我助您剿灭东阴人？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;面对纤尘平静的反应，顾子毅很受挫，突然觉得自己刚才动情的游说有点囧，脸色微红。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;片刻他又调整好情绪恢复常态，一本正经道：“正是，还请少庄主看在同是纪国人，交州百姓深受东阴人之害的份上，助本王一臂之力。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘沉默垂下眼，脸上没有丝毫表情流露，就像一尊优雅的石像。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅看不出纤尘的心思，心里有些忐忑，不知对方是愿意，还是不愿意？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;东阴人，这个烧杀抢掠无恶不做的杀手组织，师父脸上的疤痕就是拜东阴人所赐，舅舅还只是交州肉铺的小商贩时没少挨东阴人的欺负，纤尘早想将他们除之。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;当年东阴人误伤师傅，他们的头目木鲁木图便负荆请罪来到闲庄求原谅，并以东阴人永生不踏入闲城半步，不骚扰闲城百姓，更不占闲城半粒米的便宜为诺，求得了师父的原谅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;交州与闲城接壤，东阴人日益壮大起来，日后必成闲城一患，师父早有铲除东阴人之心，无奈，人家盘踞在纪国交州又从未招惹过闲城，出师无名，师父也只能作罢。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这次顾子毅上门求助，无疑是给了自己替师父完成心愿的机会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一番思量后，纤尘抬眼看向顾子毅，“瑞王如此为民着想，救交州百姓于水火，做为纪国的子民，我理应助瑞王一臂之力，只是瑞王需答应我一个条件。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅没想到纤尘会答应的这么爽快，恍然如见石像复活般激动不已，双手撑在石桌上，屁股一抬，身子向前一倾，脖子伸得老长像是被人往前提着一样，深邃的眸子求真般地望着纤尘，“真的，少庄主说的可是真的，你真的愿意助我？。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;若不是他们之间还隔着石桌，纤尘真怀疑那顾子毅会不会忍不住，上前给自己一个熊抱？纤尘本能地将身子往后挪了挪，一直到后背顶到小亭的栏杆，无法再往后挪为止。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅还沉浸在激动的喜悦中，没有发现纤尘与自己拉开的距离，接着就如江湖中人充满豪气道：“少庄主有什么条件但说无妨，只要是我顾子毅能做到的，赴汤蹈火在所不辞！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这些沙场上的男儿都喜欢赴汤蹈火吗？纤尘摇头，“赴汤蹈火那倒不至于，我这次回京都省亲不想被打扰，希望殿下能替我保密，不要向旁人提及我懂医，更不要告知其他人我是闲庄少庄主，殿下也请勿再叫我少庄主，唤我纤尘即可。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;闲庄少庄主，这名号影响有多大？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;大周十国，闲庄少庄主的地位丝毫不亚于一个国家的皇子，公主，然，她又不是王子，公主。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在纪国她就是块肥肉，一块肥肉会招惹来多少苍蝇蚊子又会招惹多少是非？顾子毅心里明白，他二话没说干脆道：“好，本王答应你！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;得君一诺，纤尘便与顾子毅筹谋如何剿灭东阴人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;剿匪贵在偷袭，偷袭贵在突袭，突袭贵在把握时机，而他们的时机就在眼前。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348340, 1334318189169975296, '&nbsp;&nbsp;&nbsp;&nbsp;东阴人知道顾子毅中了他们的腐尸酥骨油之毒，这种毒解起来很麻烦，大周十国也唯有闲庄的人会解，闲城不待见纪国，自然闲庄之人也未必会替顾子毅解毒。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;即便顾子毅有幸解毒也绝不会这么快就能赶回交州，此刻正是东阴人防备最弱的时候。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他们二人一致觉得，连夜赶回交州突袭东阴人成功的机会更大。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;事不宜迟，说走就走。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘带着苏妈妈上了顾子毅的马车，她的那辆豪华马车正好让车夫赶回了沈宅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;马车飞驰在闲城通往交州的小路上，顶着骄阳，伴着暮色，披星戴月马不停蹄。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;因为上次被东阴人偷袭的缘故，顾子毅隐隐觉得交州县衙内有东阴人的内应，故而，他这次回交州未惊动驿站、府衙之人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;马车踏着晨曦的曙光，将乔装成商人的顾子毅和纤尘他们带进了交州城。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他们在交州最繁华的街道，找了一家兼着饭馆的客栈落脚。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这里是交州最热闹的地方，闲城一年一度的海货节也带动了这里的经济，现下正赶上闲城的海货节即将开幕，这条街上来来往往的人流也比往日多了一倍。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;客栈外的街道上，一个女子跪坐在地上，她的身边立了个草席，草席上写着——卖身葬父。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;女子见有马车停靠客栈门口，便向着马车的方向嘤嘤哭了起来，希望能得到马车里的人注意。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那女子鲜亮的衣着倒是引起了纤尘的注意，阿峰扶着顾子毅进了客栈，纤尘则带着苏妈妈款款向那卖身葬父的女子走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你抬起头来，让我好好看看你。”那卖身葬父的女子闻声便抬起了头，一双自带三分眉色的眸子带着七分疑惑看向纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;近距离将此女子再次打量一番后，纤尘更是肯定了自己心里的想法，此女卖身葬父是假，想借机攀附有钱人是真。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这些年来，纤尘对她那远在京都的爹爹也有所了解，他爹除了姚氏这个正妻外就只纳了一个妾，而这个妾还是姚氏在本家替他寻的一个姑娘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他爹一向风流却一直未再纳妾，并不是他爹对那姚氏有多爱；而是他爹不敢。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不错，冉羽涅不敢，他怕姚氏，怕姚氏背后强大的家族实力，他如今要屹立在正二品大行台尚书令的位子上不倒，就必须依靠姚氏家族的帮衬。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;猫儿贪腥了，他也只能去一些花花场所寻个花问个柳，姚氏不开口，他就绝不敢将女人带会冉府。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;眼前这女子脸上画着精致的妆容，衣服的颜色鲜亮还未退败，领口有两颗盘扣掉了线。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;虽然还只是三月，但是交州比其它地方热得早，女子们已经是轻衣着装，这两颗盘扣，线掉得是恰到好处，随着海上的风吹来，那松垮垮的盘口迎着风时敞时闭，露出一抹时隐时现的春色。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她天生一双狐狸媚眼，秋水盈盈我见犹怜，纤尘已经猜到此女卖身葬父是假，借卖身葬夫之机进入有钱人家是真。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这样一个媚入骨的女子，绝对不会满足卖身进有钱人家，只当个丫鬟奴仆这么简单，她定会使出浑身解数爬上当家人的床，从此过上有钱人家姨太太的好日子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘又将此女细细地打量了一番。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;透过她的眼眸，纤尘看见她的眸子里装满了狐之媚惑却少了狐之灵气，看来是个有小聪明却无大智慧的女子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这样的女子甚合纤尘的心意，她嘴角勾出满意的微笑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我可以买你，我爹爹位高权重，不过我买你，你就只是我的奴婢与我家府中无关，只要你听话我会给你个好前程，你可愿意跟我走？”纤尘问那女子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐这……”女子犹豫了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;女子想着凭自己的姿色，若被某个贵人看上，抬进家做个妾，从此，自己就能过上不仇吃穿的好日子，被眼前这位小姐买走，那自己做妾的想法岂不是会落了空？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘仿佛看穿了她的心思，“你不必现在回我，你可以好好想想。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她又故意抬眼看了不远处一个客栈门口还有一个卖身葬父的女子，接着又说：“不过，相信除我之外，不会有人会像我一样，愿意扶持一个买来的丫头上位，机会不等人，你也需快些回我。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘说完转身对苏妈妈说道：“苏妈妈，长途跋涉我也乏了先扶我回客栈。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈搀着纤尘回客栈，女子目送纤尘她们离去，心里开始动摇，回想着纤尘抛给她的信息，她父亲位高权重定是个大官，她说的扶持自己上位又是什么意思？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰已经将纤尘和苏妈妈的房间写好，回到房间里苏妈妈终于忍不住了，“小姐，那女子一身的狐媚子气，这样的女子买入家中只会让家宅不宁，你买她干啥？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“苏妈妈，你都说了这样的女子会让家宅不宁，你说我买她干啥？”纤尘不答反问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;面对纤尘的反问，苏妈妈愣了，她不明白小姐的意思，纤尘继续道：“苏妈妈，冉府这些年来太平静，父亲就只纳了一个妾，冉府需要那样一个女子搅动搅动，我才好浑水摸鱼你说是不是？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈似懂非懂，不过她知道，她家小姐是个有大主意的人，即便她不知道小姐买那个狐媚子具体做什么，但是她知道小姐这么做定是有她的理由，苏妈妈也不再多问只道：“小姐，苏妈妈信您，您要怎么做就怎么做！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;咚咚……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;敲门声响起，是顾子毅和阿峰，他们前来找纤尘商议偷袭东阴人之事，苏妈妈识趣的离开了房间。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;围桌而坐，纤尘开门见山地问：“瑞王您现在还有多少人可用？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我带了两百精兵，交州府有驻军两千；但是我担心交州府里有东阴人的细作，故而，交州府的驻军我不敢用，上次偷袭东阴人，我们还没开始行动，就被东阴人反偷袭死伤惨重，估摸着我的精兵最多还有一百来人能用。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“一百精兵，你的一百精兵实力如何？”纤尘追问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“他们常年跟着我作战，是我从战场上挑选出来并培养的高等级将士，论武功和战斗力他们都不亚于东阴杀手。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘在心里先是将纪国的皇上腹诽了一通，纪武帝还真不是个玩意儿，偏心偏得是毫无顾忌，这兵权一收，就只给人家两百精兵来剿东阴人，这不是让人来送死的吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她双手环胸一只手不自觉地托起了下巴，手在下巴上下搓了搓，思量片刻突然眼睛一亮，“东阴人是个杀手组织，他们善于偷袭，善于用毒，善于单打独斗，然，他们不善于团队做战，你有一百名精锐士兵，我手上有比他们更厉害的毒，对付他们足够了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰担心纤尘盲目乐观，更担心主子冒然做出什么危险的决策，毕竟他们现在可用的人不多，便提醒道：“东阴人的头领木鲁木图可是大周十国武行榜的前三强，对付这样一个强者，我们显然不占优势。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯，这个我也想到了，那木鲁木图的武功很高，就算我们三人联手也未必是他的对手，不过我手上有毒，用毒是我的强项，只要我们配合好不怕不能活捉了他。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘说的胸有成竹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅看出了些许端倪，“看来纤尘姑娘对东阴人是十分的了解呀？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他就差没问出，纤尘姑娘莫不是早有了除去东阴人之心。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“那是自然，交州接壤闲城，这么大个危险在家门口我们能不了解吗？”纤尘说得在情在理，顾子毅也不再多想，三人商定今夜就动手。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰乔装出门，秘密联系安顿在曹将军军营里的那些精锐士兵。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;夜的到来！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月黑风高，潮起云涌，丑时正是大家熟睡的时候，一群黑衣人整装待发。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;东阴人的老巢在交州的黑水崖口，一个连着大陆的小岛，为了预防偷袭，他们在上岛的必经之路上设了瘴毒。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;将士们事先吃了纤尘给的避毒丹，又听说瑞王手里有腐尸酥骨油的解药，大家没了后顾之忧，也不再惧怕东阴人，个个精神抖擞向着东阴人的老巢潜伏而去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;夜如墨黑，像一片黑缎遮挡了星月，潮汐的声音掩盖了顾子毅一队人马的脚步声，他们靠着岸边礁石的掩护，步步靠近东阴人的老巢。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;再近些，便没了礁石，不远处就是东阴人的岗哨台，夜太深，两个哨兵靠在岗哨台的栏杆上打起了盹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘拿出一个吹筒，向着那两个哨兵快速吹出毒针，这两个哨兵还没来得及吭上一声，就晕死过去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这么远的距离都能射中，看来少庄主的内力修为不低，顾子毅向纤尘投去赞赏的目光，还毫不吝啬地给她竖了一个大拇指。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘点点头，算是回应顾子毅的赞赏，也算是告知顾子毅那两人已经解决可以行动了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅环顾一眼身边的士兵，向他们做了个“行动”的手势，士兵们纷纷猫着身，按序潜入了东阴人的老巢。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348341, 1334318190570872832, '&nbsp;&nbsp;&nbsp;&nbsp;悄悄潜入，夜屠羔羊。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;东阴人还在睡梦中就被人割了喉，悄无声息一切都是那么顺利。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;意外突然发生。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一个起夜，刚上完茅房的东阴人半梦半醒，睡眼迷离，还提着裤子突然被兵器的冷光晃到，一个激灵猛然清醒，吹响了预警的口哨。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原来，这里每个东阴人胸口都挂着个口哨，这个口哨的作用就是用来预警的，口哨声响，这些经过专业训练的杀手即便在睡梦中也会立即醒来，一场混战就此展开。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘、顾子毅和阿峰快速脱离混战，直奔东阴人头目木鲁木图的房间。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图虽名字听起像个莽夫，实则是个张得眉清目秀颇有些书卷气的男子，他是一个名字和长相超级不符的人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此人喜好杀戮，更喜好辣手摧花，即便是他胯下的女人晚上还在他床上与他巫山云雨，也许一到天明就被他杀了喂虫子，大家都说木鲁木图恨女人，可没人知道他为什么如此恨女人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图察觉到危险，裹衣飞出暖窝，那床上的女子被惊醒，还未反应过来怎么回事，就被木鲁木图一剑毙命。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅他们赶到，正巧看到这一幕，纤尘怒道：“木鲁木图你真冷血！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;刚离暖窝的木鲁木图，身体罩在一件松垮垮，半透不透的袍子里，腰间随意打上的一个结，仿佛马上就要散开，随时准备乍现他的无限春光。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘害羞地撇过脸，不好意思去直视木鲁木图。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图心里吃惊，潜入他老巢的人里竟然有个女子，脸上却是漫不经心放荡不羁的模样，撩着他那随意散落肩头的齐腰长发，淫笑道：“小娘子莫不是吃醋了，那就让本公子也好好疼疼你，保你醉生梦死要了还想要。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图半透不透的衣着，本就让脸皮子薄的纤尘觉得又羞又囧，再被他的污言秽语一激更是涨的小脸通红，一时竟说不出话来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅愤怒了，仿佛是自己受了奇耻大辱，二话不说随即一道剑光挥出，拨云见日，白光闪过全力向那木鲁木图击去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图手持鱼纹剑，不屑地扫了一眼顾子毅，轻飘飘一闪身，就躲过了顾子毅全力的一击，讽刺道：“纪国的战神也不怎么样嘛，手下败将，怎么闲城的人救了你，你就迫不及待赶来送死了？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我蒙着面，你竟知道我是谁？”顾子毅问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他一招落空也不敢轻敌，快速调整了刚刚暴怒的心态，手持寒水剑对视着木鲁木图。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图又随意拨弄着他的长发，完全无视眼前这三个人，漫不经心道：“双兔傍地走安能辨出是雄雌，能从我手下逃走的人，他们所出的招式我都能记得，你上次侥幸从我手里逃走，你一出手我便知道你是谁，如何？战神不如扯下蒙面让我看看。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;真不愧为是大周十国，武行榜前三强的牛人，顾子毅一把扯下蒙面，提起剑也毫不示弱，纤尘和阿峰也提起剑对准了木鲁木图。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你既知道我是纪国的战神，那你就应该知道我不会输，今天就是你的忌日。”说罢，顾子毅带着浩瀚杀气又向木鲁木图击去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在绝对强者面前，没有以多欺少这一说，阿峰和纤尘紧随其后，三人联手实力不俗，木鲁木图不敢懈怠也是全力应战。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;铛铛铛……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;刀光剑影，快如闪电。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅从小习武又在沙场上摸爬滚打好些年，武功自然不在话下，身手也算敏捷，只是在木鲁木图这个强者面前，他的武功和身手就显得差了不少，即便有纤尘和阿峰的助力，几个回合下来，他们三人明显已经吃不消。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那木鲁木图挥剑行云流水与他们对战就像在做一副水墨丹青画，游刃有余连大气都没喘上一口。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘看在眼里急在心里，几次三番她都想向那木鲁木图射去毒针，无奈对方身手太快，自己根本找不到瞄准他的机会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;近距离搏杀，自己更没有下手的机会，全力应战能不被他伤到，就已经谢天谢地了，哪里还能腾出时间来射毒针？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;噗…的一脚，毫不怜香惜玉，纤尘第一个被木鲁木图一脚踢飞。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“纤尘……！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;眼看纤尘就要飞出窗外，顾子毅纵身一跃飞向纤尘及时在窗口将纤尘接住，回望窗外竟是悬崖，崖底礁石如锋，让人一阵后怕。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅去救纤尘，留下阿峰一人难敌强敌，木鲁木图向阿峰挥出一剑，剑气如鼎震向阿峰，阿峰提剑挡胸，剑断人飞，撞到石柱上又弹了下来，一口鲜血喷出，瘫倒在地一时无法动弹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图又漫不经心地看向顾子毅和纤尘，纤尘在顾子毅身边耳语，木鲁木图一声讥笑，“小娘子，他就要死了，你还与他说什么？是话别吗？不如你到我身边来，我保证让你舒舒服服的死去，还给你留个全尸。”&nbsp;木鲁木图的嘴可比粪坑还臭。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅蓄势破口大骂：“木鲁木图，你眼睛灌脓，瞎了秋波，嘴里生疮，烂了嘴巴，看不清自己是坨屎，说不出一句人话，恶臭连连世人唯恐避之不急，谁还会来抱你？活该你今生今世、永生永世都没人爱……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冷不防被顾子毅骂，木鲁木图先是一愣，接着就像只吃人的猛兽，睁着血红大眼狰狞地瞪向顾子毅，眼看提剑就要向顾子毅劈去<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘知道，此刻顾子毅已经完全吸引了木鲁木图的注意力，他暂时不会顾及自己这边，机会稍纵即逝，纤尘瞄准木鲁木图，快速按下了隐藏在袖子里的针筒暗器开关。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;嗖！的一下一根毒针射了出去，成功射进了木鲁木图的脖颈处，蓄势待发的木鲁木图只觉得脖颈处一疼，如蚂蚁咬了一口，接着就是自己身体不受控的僵硬起来，他原本向顾子毅挥去的剑也停在了半空。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;像木鲁木图这样的强者，纤尘的实力太弱，用内力射出毒针定能被他发现并成功截获，唯有用特殊的暗器发射装置，才有可能一击命中。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;大周十国机甲大师——郑玄甲一直隐居在闲城。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘手里的针筒发射器，就是郑玄甲去年送给纤尘的生日礼物，此发射装置十分玄秒小巧，只有人的小指头粗，长度不过两寸，却可以装下十根淬上毒的绣花针，只需按下筒顶端的发射按钮，筒里的针射出的力度和速度都比自己用内力射出的针强上许多。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;激怒木鲁木图的后果有多严重？顾子毅不是不知道，不过纤尘对他耳语，要他吸引木鲁木图的注意力，顾子毅才临时想起用骂的方式来挑衅木鲁木图，引起他的注意。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;眼看木鲁木图爆发着向自己袭来，顾子毅还心有余悸，这会看到木鲁木图如同被人点了穴一样僵硬地定在那里，顾子毅又新奇地看向纤尘，“你对他用的什么毒？为什么他一动不动的？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅不知道纤尘用的什么毒，木鲁木图却知道自己中了什么毒，这是落崖谷特有的尸僵之毒，木鲁木图身子不能动，只有眼珠子转向纤尘，“丫头，你和落崖谷主什么关系？”木鲁木图眼睛里透出了难得的恐惧。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;落崖谷主是个什么人？纤尘脑子里一头雾水一片迷茫。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图从纤尘迷茫的眼神中看出纤尘根本不认识落崖谷主，那唯有一个可能，她是闲庄的人，这个世上除了谷主也唯有闲庄庄主手上会有这个毒，“丫头，闲庄庄主是你什么人？”木鲁木图又问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘未答，她可不想连累闲城，更不想连累师父，<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你是那个女人的徒弟对不对？”&nbsp;木鲁木图追问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;别人都猜到了纤尘也不再隐瞒，冷笑一声，“不错，不过今天是我的个人行为与她无关与闲城无关。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你既然是她的徒弟，就应该知道我与你师父之间有过协议，我们互不侵犯，你违背了协议。”&nbsp;木鲁木图在为自己争取生的机会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“不，没有，闲庄没有违背协议，我是纪国人，从我踏出闲庄大门，踏入纪国土地的那一刻起，我和闲庄就再也没有任何关系，我现在只是纪国一名普通的女子，杀你，只为纪国百姓除害。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哈哈哈……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图看着纤尘一阵狂笑，他的笑越笑越凄苦，越笑越悲凉，最后这个杀人不眨眼的恶魔竟然笑得泪水横流。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图知道自己中了尸僵之毒栽在顾子毅手里绝不会好活，他在临死前竟然又想起了她，那个在他心里比他生命还重要的女人，那个伤她伤得体无完肤的女人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那女人的身影在他脑海里挥之不去！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“阿图，放开我吧，我宁可当宫里的金丝雀也不要跟你去漂泊；阿图，求求你帮我杀了那个女人，杀了她我就把我的身子给你；阿图对不起，我爱他，他能给我的是你永远也给不了的……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;呜呜呜……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图的笑彻底变成了哭，他突来的转变让纤尘和顾子毅都像丈二的和尚摸不着头脑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;临了，临了，木鲁木图哭红的眼里竟然闪现出滔天的恨意，“女人没有一个是好东西。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348342, 1334318192026296320, '&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图想起那个他视如珍如宝的女人，悔恨交加。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;为了她，他愿意冒着得罪落崖谷主的风险去暗杀闲庄庄主，他不是不知道闲庄庄是落崖谷主一生的挚爱，他也知道自己和落崖谷主是亲如兄弟的好友；可是为了她，她愿意得罪好友，哪怕是要了自己的命只要能博她一笑他也心甘情愿。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;然而她呢？从来都只当他是一个呼之即来挥之即去的一颗棋，他恨自己陷得太深，深到即便他明知道她在利用自己，他还心甘情愿被他利用。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他麻木的认为只要自己对她来说还有点利用价值，那么自己在她心里就会有一席容身之地。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他为她杀人为她铲除异己，这么些年过去，她从来没有回馈自己只字片语的温情，事到如今只剩下嫌弃，嫌弃他给她带来了不安。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图流着泪在心里问自己，如果她知道自己死了，会为自己落泪吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;转而他又摇了摇头，他心里明白，她不会，她不会为自己落泪，因为自己只是她的一颗棋，有谁会为了一颗棋被毁而落泪的？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图他恨那个女人，恨天下所有的女人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;咔！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;猝不及防木鲁木图含恨咬舌自尽。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;尸僵之毒非常玄妙，中毒之人全身如尸体般僵硬无法动弹，唯有脖子以上例外，活动自如可以开口说话。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这个毒，给了中毒之人和施毒者申辩和审问的机会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘和顾子毅原本还想着，活捉了木鲁木图就可以从他嘴里问出些东西，没想到他们还没来得及审问，人家就咬舌自尽了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;东阴人做事从不记录在册，不计收也不计支，只认银子不过问雇主，这也是他们这些年能快速崛起的原因，因为雇他们杀人的雇主，不用担心会留下可查找的痕迹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图一死，东阴人的所有信息都被他带去了阴曹地府。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅知道，即便是在木鲁木图的房间里也不一定能找到什么有用的信息；但是他就是不死心，将这里翻了个底朝天。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰醒来，也协助顾子毅翻找。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;功夫不负有心人，阿峰在一个暗格里发现了一封信，“主子，这里有封信。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅闻声而去，纤尘也跟了过去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;打开信封，哐当……一个小物件从信封里滑落。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅弯腰将落在地上的小物件捡起来，捏在手指上看了又看。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此物件玲珑别致甚是精美，是一个骨白的骰子里镶嵌了一颗滴血般的红豆，让人看上一眼就爱不释手。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“玲珑骰子！”&nbsp;纤尘看到顾子毅手里的骰子脱口而出，“纤尘姑娘知道这骰子的意思？”顾子毅问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯。”纤尘点点头，心想，师父也有一个比这个骰子更精美的骰子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘自然没将心里想的说出来，指着顾子毅手里的骰子道：“师父说这种骰子代表着相思入骨的意思，殿下，说不定这信里能给我们解释，我们先看看信里的内容如何？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;打开信，三个人就傻眼了，那信上没有落款，没有署名唯有短短的五个字“杀了闲雅云。”和一朵在落款处画的梅花。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这封信的纸张已经泛黄，边角已经起毛，看来这封信已经有了些年头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这信上的内容纤尘不看还好，一看她心里就一沉，顿时生出许多疑惑来，因为闲雅云正是她师父的名讳。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘陷入沉思。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原来当年东阴人暗杀师父，并不是误杀而是有人雇佣？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那为什么当年木鲁木图会亲自来闲庄负荆请罪，还口口声声说自己是杀错了人，误将师父看成了他当年的仇人？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图一个人扛下所有的罪过，他是在害怕什么吗？还是他另有目的？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘思量，木鲁木图不是莽夫在接到暗杀师父的雇佣时，定会平衡利弊，他既然敢接受这个雇佣，定不会惧怕事后闲城的清算。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;师父手里也有个比这个骰子更精美的玲珑骰子，送师父骰子的人是谁，会是木鲁木图嘴里说的那个落崖谷主吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;难道木鲁木图是惧怕落崖谷主？因为刚刚在提到落崖谷主时，纤尘在木鲁木图的眼里看到了恐惧。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;转而，纤尘又想，落崖谷主是谁？他和师父什么关系？木鲁木图为何会怕他？既然木鲁木图怕落崖谷主，为何当年他不将雇佣之人说出来，而是将所有的一切都自己揽了下来？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;突然纤尘一个激灵，她想到了木鲁木图这样做的原因。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图知道，当年师父逃脱东阴人的暗杀后定不会放过他，更不会放过幕后的雇佣之人，他也知道自己动不了师父，便带着诚意来闲庄负荆请罪，许下东阴人永不侵犯闲城的重诺，他笃定，师父定会看在闲城百姓的安危上，放弃对此事的追究，他一口否认是雇佣杀人，他这样做的目的也只为保护那幕后的雇主。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那雇主和木鲁木图会是什么关系？纤尘猜想能让木鲁木图用自己的命来保护的人与他的关系定是非同一般。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘又将目光落在了顾子毅手里的玲珑骰子上，心想木鲁木图要保护的人定是他心上的人，而这个人估计就在纪国的京都且位高权重，要不然东阴人也不会安全盘踞在交州十几年。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘暗暗发誓，她定要找到这个雇主，为师父那毁掉的半张脸报仇。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅看到纤尘盯着自己手里的骰子出神，忙问道：“纤尘姑娘，这骰子有什么问题吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的思绪被打断回过神来看了一眼顾子毅，也不拐弯抹角直接开口问道：“不知殿下可否将这信和骰子先借纤尘一用？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这些都是证据，纤尘断不会为难顾子毅，让他将收缴的证据给她，唯有借出来将信临摹一份，再仿刻一个一模一样的骰子，方便自己日后寻那雇主。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅从刚刚纤尘的失神中就已经猜到，这封信纤尘可能还知道些什么，只是她不说，他也不多问，贴心道：“剿灭东阴人后，本王最近定会诸事缠身，有些东西带在身上也不方便，就有劳纤尘姑娘替本王保管。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说罢，顾子毅就将信折好放入信封交给了纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘没想到顾子毅这么爽快，话还说得这么贴心，她清澈的眸子里充满感激地看向顾子毅，接过顾子毅手上的信拱手一礼“多谢殿下。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“纤尘姑娘不必客气。”顾子毅又看了看手里的骰子，问道：“纤尘姑娘说这个骰子代表相思入骨？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯”纤尘又点点头，指着那个骰子对顾子毅细说道：“瑞王您看，这个骰子是用骨头做的，骨头镂空，里面放了一颗相思红豆，有句诗不知殿下听过没，‘玲珑骰子安红豆,入骨相思知不知’里面说的玲珑骰子就是这个骰子，它代表了情深入骨的相思之情。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅细细端详了一番这颗骰子，确实如纤尘所说，骰子是用动物骨头镂空雕刻而成，里面放着颗红豆，红白相间十分精巧，关键是这个寓意很好，他很喜欢。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯，好，我知道了。”顾子毅将这颗骰子的模样刻进了心里，这才将骰子递给了纤尘，“诗我没听过，不过骰子和诗我都记下了，很好，很好。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘不知道顾子毅说的那句“很好、很好”是什么意思，她也没太再意只当顾子毅是觉得诗写得好，骰子刻的很精美。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图已死，东阴人大势已去，顾子毅点燃一把火烧掉了木鲁木图的房间，其他的东阴人见头领的大营被烧，战斗气势也泄了下去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;敌消我长，顾子毅的精锐很快就攻破了东阴人的老巢，剿灭了东阴人，大火也蔓延开来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;寅时三刻，顾子毅带兵偷袭东阴人的老巢大获全胜，返回交州城。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;远远望去，只见交州黑水崖那个连着大陆的小岛上火光滔天，照亮了天际，将那片天都染成了绛红。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“快看，黑水崖那边着火啦！”百姓中不知谁第一个发现了那片染红了天际的火光，大喊了起来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;消息很快传开，百姓们纷纷上街看那黑水崖口滔天的火光，清晨天刚泛起的鱼肚白被淹没在那片火光之中，交州的街道上站满了人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不知又是谁传来的消息，是他们纪国的战神瑞王殿下带兵剿灭了东阴人，还烧了东阴人的老巢。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;常年受东阴人骚扰的交州百姓激动的又是哭又是笑，打心底里感激他们的战神为他们百姓除了这一大害。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;锵锵咚咚……锵锵咚咚……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;敲起锣打起鼓，交州的百姓如同赶走食月的天狗般激动又如同庆祝丰收一样高兴，欢呼迎接着他们的战神凯旋归来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看到黑水崖那片天空一片绛红，有人欢喜有人愁。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;交州县令坐立不安，便想去海防将军府找曹将军。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;正巧，曹将军已经忙忙慌慌来到县衙府，张县令见到曹将军立即禀退下人忙问：“曹将军，你说说这是个什么情况？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军苦着一张脸，愁容满面满是悔恨，“哎，都是我大意，他的那些兵在我眼皮子底下离了营，我竟浑然不知。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“曹将军，瑞王的那些兵，不都是安顿在你的军营里吗，他来调兵你怎能能不知？”张县令诧异。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348343, 1334318193443971072, '&nbsp;&nbsp;&nbsp;&nbsp;面对张县令的质问，曹将军火了，他的声音也提高了几度，横眉冷对，“你说这话什么意思？我们都是一条船上的蚂蚱，我要是知道他前来调兵能不提前告诉你？能不去通知东阴人？他剿灭了东阴人对我，对我们来说又有什么好处？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;张县令是文官，曹将军是武将，他们两每每争论起来那就是秀才遇到兵，张县令是有理也说不清，曹将军习惯性立马声音提高八度趾高气扬浑然不讲道理，蛮横的想用他那高猛的声音压倒一切。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;若是平日里张县令便一走了之，等他这个莽夫在这里嚎叫，可是现在不一样，&nbsp;现在不是激化内部矛盾的时候。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;张县令一脸的无奈，软着口气道：“曹将军误会了，我哪有什么其它的意思，我的意思是那瑞王殿下这次回来，既没有惊动我县衙府内任何一个人，也没有惊动你们交州军营里任何一个人，就连他的兵被调遣出去都是秘密行之，你说，他是不是已经怀疑上我们了？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军恍然大悟，“还是张大哥想得周全，不错，你说的不错，那瑞王定是已经怀疑上我们了，张大哥你说那接下来我们该怎么办？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军就是这种没脑子的莽夫，火气一上来便是天王老子都要骂上一骂，这下觉得张县令说得有理，他又马上可以对张县令称兄道弟，一脸焦灼地看向张县令。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;张县令没好气地剜了一眼曹将军，“让我想想。”他转过身捋起他的山羊小胡子，不想去看曹将军那肥头大耳的模样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;瑞王的兵，暂时都安顿在曹将军的军营里，因为想着瑞王若回来调兵就定会去军营，他们想着瑞王回来若去了军营，还能有他们不知道的道理？所以他们就疏忽了对瑞王士兵们的看守与防范。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;瑞王这次回来没有去军营调兵，定是派人暗中联络了军营里他的那些士兵，他的那些士兵定也是偷偷潜出的军营，只有这样，曹将军才会浑然不知，瑞王的那些士兵已经从他眼皮子底下无声无息离开了军营。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“瑞王殿下果然高明，看来，他在上次进交州突遇偷袭时就已经怀疑上我们了。”张县令突然说道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;接着他转过身看向曹将军，依旧捋着他的山羊小胡子道：“他是故意将他的士兵安顿到将军军营里去的，这样一来我们自然就觉得他的士兵都在自己的眼皮子底下，便会放松了对那些士兵的防范。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;张县令顿了顿，“他这样做其实还有一个好处，那就是即便他猜不透军营里是否有问题，他将那些士兵托付给你，他就笃定你会将他的士兵安顿的很好。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;脑子转不过弯的曹将军一脸茫然反问：“这话怎么说，如果他当初怀疑自己也会将他的那些士兵托付给我吗？他就不怕我对他的那些兵下毒手？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哼”张县令冷哼一声，不屑地看了一眼曹将军反问：“你下毒手了吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我……”曹将军被堵得哑口，他回想起那日瑞王给他说过的话，“曹将军，我知道镇南大将军非常看中曹将军，将军既是镇南大将军都看中的人定是纪国的栋梁，定是本王值得托付的人，我将自己的兄弟托付给你，你好好照顾他们，若本王回不来了，他们就是你的兄弟了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那日，顾子毅的那些话，可是说进了曹将军的心坎也把他美了好些天，他心里就期盼着瑞王中毒死去，他的那些精锐士兵就直接收编进入自己的军营，曹将军对瑞王的那些精锐士兵可是喜欢得紧，对他们也是真的好，紧着好吃的，好喝的伺候，还积极为那些伤患治疗。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军的白日梦还没做几天，大梦初醒愤然道：“好一个顾子毅，他当初对我说的那些话其实就是故意诓我的，亏我还如此信任他。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;张县令摇头，没脑子的莽夫就是蠢，就像猴子天生是爬树的，猪你就是拽着尾巴往上提，尾巴都拽断了它也爬不上树来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;张县令已经猜到，顾子毅当初这么做，定是笃定无论交州军营有没有问题，他将自己的士兵放在军营里都是安全的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;军营里若没有问题，那么曹将军定是会好好保护纪国的士兵；如果军营里有问题，曹将军看在形式还不明确，这帮精锐士兵最终的归宿权也是落在自己手里，曹将军哪怕是逢场作戏也会把戏做足了对那些士兵好。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;再则，顾子毅若真的回不来了他将那些兵留给了曹将军，未必不是在曹将军的军营里安插了纪武帝的探子，同时也是给了那些士兵活下去的机会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“高，实在是高！”顾子毅心思缜密，张县令不得不佩服，纪国的战神不仅有勇，他的这番谋略也非一般人可以媲美。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“高什么高，张大哥你就说说接下来我们该怎么办吧？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军一介武夫，功夫还不错却是个有勇无谋易操控的人，他遇到问题就只会找张县令，这会已经急得像是热锅里的蚂蚁，焦头烂额在县令府里踱来踱去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“怎么办？你说怎么办？”张县令声音突然提高目光如炬看向曹将军。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军愣了愣不知道张县令为何会反问自己，他要想得出来他还会这么着急吗？旋即，他就看见张县令双眼微眯，眼里露出屠夫般的狠戾凶光，“事到如今也只有……”他话没说完；但是曹将军已经看懂了他的手势。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军心里一紧，没想到文人起了杀心比他这个武将还狠，他点了点头，事到如今为了自保也只能先除去顾子毅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;二人商量完计策，心怀鬼胎掩饰着内心的恐慌，强装着欢喜，出门迎接战神瑞王的胜利归来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;第一次，交州的百姓觉得穿着夜行衣的男儿也是英勇威武神采四溢的，纷纷对着那些黑衣男儿连连叫好，有些激动的百姓还冲向前，向那些士兵示好，场面一度失控。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;有些年龄大一些的百姓是这样的——<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;来小伙子，这些蛋都是家里的鸡才下的，你们拿着，这是大妈的一点心意。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;来小伙子，这些干果都是大婶自己腌渍的，你们拿着尝尝。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;来小伙子，这些鱼干你们拿着，这是我们铺子里伙计们的一点心意。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;还有些小姑娘是这样的——<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她们手拿香囊追着队伍前行，若有自己看上眼的男子，她们便将手里的香囊硬塞到人家怀里，还不忘补充一句“香囊驱蚊，若公子喜欢可以来找我再做一个，香囊里有奴家的地址和名字。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;交州民风开化，女子可以用香囊来表达自己的爱意；但是收了别人的香囊也不一定非要接受对方的爱意，爱情讲究个你情我愿，若不喜欢你就不要去找人家便是。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘早已离开顾子毅的队伍，悄悄回到客栈换上一身女儿装，紧跟着也出了门。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她记得顾子毅对她说过，他怀疑交州府内有东阴人的奸细，而且他猜测此奸细在交州府内地位不低，故而，顾子毅才乔装回交州寻一家客栈住下，不敢惊动府衙内任何一个部门的人，也不敢调用交州的海防士兵。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘出去，不为看热闹而是去看看在这热闹的人群里，能不能找到奸细的蛛丝马迹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;张县令和曹将军前来迎接顾子毅，二人卑躬屈膝大礼相迎，不远处的纤尘却在他们的脸上看到了隐隐因恐惧而感到不安的神色。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘柳眉微锁。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;十二年的强化观察训练，她对自己观颜读心的能力很有信心，她已从张县令和曹将军的神色里读到了惊慌和恐惧，难道是交州这两大官员同时都出了问题？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘很吃惊，若交州两大首脑性的人物同时都出了问题，那么交州的情形就很严重，她不敢懈怠，紧盯着二人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这时，就见曹将军对身边的一个将领递了个眼神，那个将领便隐匿到人群里偷偷离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;没人注意到那个将领的离去，唯有纤尘，纤尘偷偷跟在那个将领身后，跟着他七绕八拐来到一个巷子，巷子里已有人在那里等候。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;等候的那人见那个将领到来，不耐烦地道：“赵参将，有什么事不能在军营里说，非得约我在这里说？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嘘……”那位叫赵参将的赶紧拉住了那人的手，做了个禁声的手势，东看西瞄回头望了两眼，感觉没人才小心翼翼地道：“魏参将你小声点，将军有令，今晚就集结兄弟们在县衙府等候，咔嚓。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;接着那人就做了个抹脖子的动作。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;魏参将明白赵参将的意思，脸上写着为难，眉头紧拧“赵参将，那可是三殿下，我们这样做不等同于造反吗？这可是满门抄斩的大罪呀，万一，万一有个意外怎么办？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;听魏参将这么一说，那赵参将也面露惧色，沉了沉脸，随即他心里又一横，目露侥幸道：“不会有万一，将军已经安排好，今晚县府大人设宴，宴请瑞王和他的士兵们大胜归来，大人会在酒水里下毒，一切都在大人和将军的掌控之中。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348344, 1334318194870034432, '&nbsp;&nbsp;&nbsp;&nbsp;那个叫赵参将的又不屑道：“将军还说了，瑞王是个不受宠的皇子，事后，就说他们都死在了东阴人放的那把大火里，皇上定也不会深究。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;魏参将脸上难色更盛，犹豫道：“他可是我们纪国的战神呀！我，我于心不忍。”。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此刻的赵参将脸上就像个调色板，闪过恐惧，闪过无奈，也闪过狠戾和不屑，最后不耐烦道：“不忍也没用，我们跟着将军不管是愿意还是不愿意，没少做那些昧着良心的事，将军这次倒了我们还能活否？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将一句话说到了点子上，魏参将想了想，点点头悻悻而去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;偷听完他们所有对话的纤尘，心想，看来这魏参将本性不坏，可以从他身上突破扭转乾坤，纤尘悄然离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一个石子巧妙地打在阿峰的左肩，阿峰顺方向看去，他看见了纤尘，纤尘对他眨了眨眼睛，阿峰会意想必是纤尘发现了什么有事找他，随即他就离开了人群，向着纤尘离开的方向跟去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“纤尘姑娘可有事吩咐？”阿峰跟着纤尘来到一处隐蔽的巷道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘四下看了看，确定巷道里没人，为防止意外被人偷听了去，她还是很谨慎，招手示意阿峰附耳过来，将自己刚刚听到的消息说给了阿峰。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰听完为之一震，“多谢纤尘姑娘，阿……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘知道阿峰是想说些客套话来感谢自己，现在哪里是感谢的时候，赶快将此信息告诉瑞王殿下，让他尽快商量出对策才是最重要的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她即刻打断阿峰“你快回去，将此事说于殿下听让他早做准备，若有用得到我的地方，来客栈找我便是。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰拱手一礼告辞纤尘回到顾子毅身边，此刻顾子毅也被张县令和曹将军迎进了县衙府，围观的百姓们不得进入县衙府大家都姗姗退去，纤尘也已经回到了客栈。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈见纤尘回来，连忙端来茶水给纤尘倒上一杯茶，“小姐，事情可都办完了？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘接过茶，吹了吹漂浮在上的茶叶，摇摇头正要开口说话，便听到房外客栈小伙计边敲门边说“客官，有位姑娘来找。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;有姑娘来找？纤尘愣了愣很快就反应过来，定是昨日那个卖身葬父的女子，便吩咐苏妈妈去开门。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈打开门，那女子怯怯地跟了进来，女子今日穿了件绛红色的布衣，衣服颜色看起来很新，想必是她精心挑选过的，脸上依旧精心修饰过，只是她用的胭脂水粉质量都不佳，近看脸上还看得到没晕开的粉粒。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘从那女子进门，就又一次将那女子再打量了一番，她抿了口茶，不紧不慢开口问道：“你想好啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那女子点点头，“想好了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;女子心想，她在交州已经无依无靠，若能去京都，进了大户人家，不怕自己找不到上位的机会，为了有一天能进入富贵门第，她可是学了不少本事，什么交州小调，推拿按摩，就连字她也识得一些……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘放下手里的茶盏，她嘴角微勾向那女子展出一抹微笑，眼里却带着警告和敲打，“做我的丫鬟，我的要求不高只要你对我无二心，我便不会薄待了你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;女子赶紧跪到纤尘身边，抓着纤尘的裙角双眼剪水道：“奴婢定不会对小姐有二心，还望小姐给奴婢一个侍候您的机会。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;女子一双眸子自带狐媚之色，纤尘忍不住道：“你的眼睛真媚，不过这样的媚眼，你还是学会有的放矢的好，回府可不要让府上的嫡母大人看了去，引来不必要的灾祸。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那女子连连点头，“小姐放心，奴婢明白，奴婢定会好好收敛。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘这才问：“你叫什么名字？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我叫韩双双。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“韩双双这个名字不错，你先起来。”纤尘刚扶起韩双双，阿峰就带着一个男子前来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;因为着急办事，阿峰见纤尘的房门没关，便直接将那男子给带了进来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他看到纤尘屋里不仅有苏妈妈还有一个女子，愣了愣方觉自己唐突，又才解释道：“阿峰见门没关，没有支会便带人进来，太过唐突是阿峰失礼了！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘不动声色对苏妈妈道：“苏妈妈，将双双姑娘带下去，给她讲讲我这里的规矩。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈应声将韩双双带了出去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双边离去边用余光瞟了一眼说话的阿峰，这个男子相貌堂堂，气宇不凡，看着装却像是护卫，这样的护卫定不是普通大户人家请得起的，韩双双在心里暗自窃喜觉得自己赌对了，坚信纤尘是京都大员家的女儿也更坚定了跟随纤尘的心。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;待苏妈妈和韩双双都离开后，阿峰又才说道：“纤尘姑娘，这位是瑞王殿下两百精锐里的领军方海将军。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“方海见过纤尘姑娘。”方海拱手一礼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘欠身回礼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;二人简单礼数一番，阿峰接着又说：“方海将军在殿下求医的这段日子里，一直混迹在交州军营与那魏参将也颇有些熟悉，策反魏参将之事，殿下想请姑娘协助方海将军，一同去趟军营。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘看向方海，身长七尺八寸，身材魁梧，皮肤黝黑，剑眉星目英武不凡，“方海将军我们什么时候去军营？”纤尘问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“随时。”方海语言简练。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哞……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这时，客栈门口有牛叫的声音传来，纤尘闻声嘴角微扬“方海将军，我也已经准备好了，我们现在就出发。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“好。”方海一脸正气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;三人离去，阿峰直接回到顾子毅身边，纤尘和方海来到门口，纤尘对门口那牵牛的小伙计说：“东东把牛牵到交州军营去。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海疑惑“纤尘姑娘牵牛去军营做甚？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘反问：“方海将军可知道牛肉在交州代表什么？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海摇头不知，纤尘边走边解释，“交州沿海，畜牧业欠缺，牛肉很是稀缺，牛肉在交州代表了诚意和贵重，普通老百姓走访，能带去一块牛肉那已经是很好的礼物了，沈家肉铺的牛肉用的全是品质上等的肉牛，它的价格更是普通牛肉无法比的，是交州权贵和大型饭店里的贵宠，我让沈家的伙计带着他们独有的肉牛前去，便是想让军中的将士们看到瑞王殿下的诚意。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海赞赏的看了一眼纤尘，“姑娘考虑甚是周全。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;守营的士兵看到方海带着一个女子和一个沈家伙计牵着一头牛前来，是丈二和尚摸不着头脑，挠着脑袋迎过来问：“方将军，县大人和将军不是给你们准备了庆功宴吗？你怎么有时间到军营里来了？这两位是……？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不等方海开口，纤尘先自报了家门，“我是沈家肉铺的少东家，瑞王殿下知交州的将士们守卫交州海域辛苦，特在我沈家肉铺定了肉牛犒劳诸位将士，这不，方将军就是带我前来找魏参将大人商议肉牛一事。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那守营的士兵听到瑞王定了沈家肉铺的肉牛来犒劳大家，眼里都放着光，忍不住咽了咽口水，欣喜道：“魏参将就在营里，方将军、少东家你们跟我来。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“不必了，你把它牵到厨房去，魏参将的营帐我熟悉，我带少东家过去便是。”说着方海就接过东东手里的牵牛绳，将牵牛绳交给了那位守营的士兵。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;守营的士兵看到手里的牵牛绳如同看到一盘香喷喷的牛肉，欢喜道：“好，那我就牵牛去厨房了，就有劳方将军带少东家去找参将大人。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海带着纤尘进了魏参将的营帐，魏参将正独自坐在营帐里回肠九转犹豫不决，到底要不要执行将军的命令？他手里端着茶盏，茶盏里的水都凉了，见方海突然到访，心里一紧慌忙起身，不小心将手里的茶盏都打翻在地。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“方、方将军，您，怎、怎么有空，来、来军营里来了？”魏参将脸上难掩惊慌之色，就像自己偷了人被逮了个现行一样，说话都结结巴巴的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海捡起地上打碎的茶盏，啧啧嘴道：“魏兄可是在想什么大事，想得如此出神，竟将自己心爱的茶盏都打碎了，不心疼吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;魏参将强稳心神，不想让方海看出什么破绽来，“没，没想什么，一个茶盏而已，不心疼。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海这些日子和交州军营的弟兄们相处下来，没有发现军营里的端倪，还认为东阴人的细作应该在交州府衙里，突然听到阿峰说交州不是细作，而是县老爷和边防将军都被东阴人收买，他们还要联手对付殿下，一时惊得咋舌，不敢相信消息的来源是真的，这会子他看到魏参将失态的反应完全信了阿峰的话。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海扬眉嘴角微勾，他已看穿魏参将的惊慌，抛给魏参将一个寓意深长的笑，“可我上次与魏兄饮茶时，听魏兄说过，这杯子是难得的上品汝窑瓷器，是你媳妇嫁进府中时带进门的嫁妆，你非常珍惜，一般情况下都舍不得用，今个儿是个什么的特殊日子，魏兄将它打碎了都不心疼了？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;魏参将心虚地搓了搓手，故做镇定道：“方将军前来可是有什么事？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘看到魏参将喉结打颤，目光闪烁，双手不停地揉捏着衣角，心里暗叹，这个魏参将心里承受力可真差，别人还没怎么做，他自己就先乱了阵脚，也许这就叫——做贼心虚。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348345, 1334318199571849216, '&nbsp;&nbsp;&nbsp;&nbsp;纤尘见魏参将如此心虚，心想若自己再往前推上一推，他心里的防线定会崩塌！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;想到这里，纤尘就走到那堆碎瓷片前，拿起一片瓷片看了看，自言自语道：“多好的茶盏就这样碎了，多好的家庭也这样碎了怎么办？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的话里透着一股不寒而栗的阴冷，听得魏参将禁不住打了个哆嗦。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;父母和妻儿的模样突然浮现在魏参将的脑海里，他顿感如芒在背，瞬间身上冷汗涔涔，他知道纪国对叛臣贼子的处罚有多重，他似乎明白了些什么，双腿仿佛失去了力气，扶着椅背，强撑着自己的身体没有瘫软下去，慌忙问道：“你们，你们都知道些什么？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在来军营的路上，纤尘已经从方海的嘴里了解到魏参将的为人，魏参将与赵参将不同，赵参将好耍喜欢逛花楼，魏参将是个顾家的人，对士兵也算宽厚，他家上有老父老母下有一双可爱的儿女，夫妻二人恩爱有佳。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;再说，纤尘也听到过赵参将与魏参将的对话，她知道魏参将本心是不想谋害顾子毅的，他不忍，只是无奈他没跟到一个好的上司。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘理解魏参将，作为一个下属面对上司的命令不想执行却又不得不执行的难处，对于魏参将这样一个良心未泯，孝顺父母又爱戴妻儿的男人，纤尘还是希望能给他一次重新选择的机会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘一改刚刚的阴冷之色，换上一脸的和颜悦色，“参将大人，我们什么都不知道，你不要太紧张，我们是奉瑞王之命前来犒劳将士们的，瑞王仁慈，念及将士们保家卫国驻守海疆不容易，特赏大家一百头肉牛。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一百头肉牛，这是个什么概念？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海刚刚还从纤尘的嘴里了解到，沈家肉铺里的肉牛价值不菲，这丫头一开口，就替王爷承诺，拿出一百头牛肉来犒劳交州的士兵，方海倒吸一口凉气，心里在替他家王爷滴血。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;魏参将更是惊掉一地下巴，他不傻，他知道沈家肉牛的价值，更知道牛肉在交州代表着诚意，王爷出手如此阔错，一次拿出一百头沈家肉牛来犒赏士兵，足见王爷的诚意，便问道：“殿下，殿下有什么吩咐？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海也不卖关子，顺着纤尘的话说下去：“殿下说，兄弟们若接受了他的牛，过往一概不咎，大家还是纪国的好战士，好臣民，就看魏参将是选择牛还是选择这只茶盏。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海拿起一片碎了的瓷片在眼前晃了晃。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;魏参将一听，便明白过来方海的来意，方海的话已经很明确，瑞王是要让他做出选择，是选择跟他还是选择跟曹将军。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;既然瑞王派方海来找自己，这就说明瑞王已经洞悉到曹将军的反意，魏参将虽然不知道瑞王是如何察觉到曹将军的反意，不过他可以肯定，瑞王既然已经有所察觉，就会有所防范，曹将军这次反水就定不会成功。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他原本就不赞同曹将军的所作所为，现在有机会遇到明主，而且人家还说了既往不咎，他自然会选择弃暗投明。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“交州左参将魏孤青，愿誓死效忠瑞王殿下，请问殿下有什么安排，魏孤青定会全力以赴。”魏参将立即单膝下跪拱手行礼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘和方海面面相觑，策反成功，他们开始和魏参将部署晚上的行动。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;事后，方海回到顾子毅身边，将策反成功和部署之事说给了顾子毅听，阿峰听到纤尘替王爷承诺了一百头肉牛的犒赏，咋舌，“啧啧……那丫头夸下那么大的海口，你咋不拦着点，一百头肉牛这可不是小数目！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海一脸无辜，“临走时，殿下交代尊重纤尘姑娘的决定，那丫头事先也没与我商量呀！”方海一摊手表示自己也非常无奈。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰一阵肉痛，那一百头肉牛的价格比他们二百精锐三个月的军饷还多，顾子毅却没有觉得可惜，相反他觉得纤尘做得很好，嘴角上扬，忍不住笑出了声，“呵呵……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;自兵权被收后，方海和阿峰已经很久都没见过瑞王笑了，还笑得这么开心，两人同时诧异地看向顾子毅，异口同声道：“殿下您笑什么，是不是太生气了？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我笑自然是因为我高兴！”顾子毅立即敛笑容严，分别看了眼还一脸茫然的方海和阿峰，大有恨铁不成钢的意味，“一百头肉牛换两百条士兵的性命你们说我亏吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;经顾子毅这么一点拨，方海和阿峰顿悟，曹将军手里可是有交州东西郊两处人马，西郊营地偏远驻守在那里的士兵一时半会过不来；但是仅仅是东郊营地及魏参将这边的士兵就有两千人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;瑞王的士兵刚经历过一场硬战，即便瑞王的士兵再强，也敌不过魏参将这边两千士兵的围攻。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那一百头肉牛是殿下的诚意也是殿下给魏参将的一颗定心丸，不仅换得了两百条精锐士兵的性命，还换来了两千交州士兵的心，这样说来，他们殿下不亏反赚。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海和阿峰二人开始还嫌弃纤尘出手太阔绰，为他们王爷感到不值，现在又佩服起她来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今夜，注定又是一个不平凡的夜。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月明星稀，海上明月将交州府衙内照了个府内明月光。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;交州府衙内热闹非凡。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;台上张县令起身端酒恭维道“瑞王殿下剿灭东阴人，为我纪国除去一个毒瘤，功在千秋呀！老臣敬殿下一杯。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅一饮而尽，接着，他刚喝完张县令敬的酒，曹将军又来，“瑞王殿下年轻有为，真不愧是我纪国的战神，老臣佩服，老臣先干为净。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;张县令和曹将军轮番敬着顾子毅的酒，两人看着顾子毅爽快喝下，心照不宣的对视，眼里有按耐不住的窃喜闪过。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;主台下士兵们也大口喝酒，大块吃肉，划拳声不绝于耳。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;喧嚣声没持续多久便戛然而止，交州县衙府内瞬间安静了下来，这份安静来得有些诡异，瑞王已经趴在了桌子上，他的那些精锐士兵也都趴在了桌子上，大家仿佛都醉得不轻，都沉沉地睡了过去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“殿下，醒醒，快醒醒，瑞王殿下，您醉了吗，快醒一醒？”为了稳妥，曹将军还故意推了推趴在桌上的顾子毅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅像条死狗一样，趴在桌上没有半点反应。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见瑞王没有反应，张县令又向身边一个衙兵使了一个眼色，那衙兵会意，到台下去推了推几个趴着的士兵，他们依旧没有任何反应。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;张县令和曹将军二人来到台前，看到眼前这黑压压趴着的人头，又互视一眼这才松了口气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“迷迭露”无色、无味，即便是大量使用也不易被人察觉，只是这毒，毒不死人，只能让人暂时昏睡过去，瑞王他们已经全部中毒昏睡过去，瑞王大势已去，曹将军气定神闲地喊道：“来人！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;事先带着自己的兵，隐藏在县衙府内的魏参将，带着他的兵快速集结到曹将军面前。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘也伪装成士兵混在了队伍里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“交州左参将魏孤青等候将军发令。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看到魏参将带来的这些兵，张县令点点头满意地捋着他的小山羊胡子，曹将军脸上也露出一抹得意，对着魏参将做了个抹脖子的手势。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“是”魏参将会意领命，旋即，他看了一眼身边的纤尘，纤尘也看了他一眼，二人心有灵犀地同时上台对上了曹将军。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;其他士兵则开始控制县衙府内其他的人，包括一些下人和一些为数不多的衙兵。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;魏参将的临阵倒戈，让张县令和曹将军措手不及，张县令是文官没有什么功夫底子，三两下就被士兵擒住，嘴里还不停地叫着“来人，来人呀！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此刻张县令哪里还叫得出人？他的人早已经被魏参将的人控制住。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军原是镇南将军王——邱奎岚将军手里的一员猛将，凭着自己一身功夫杀敌无数坐上了交州海防将军之位，也算是个有真功夫的人，面对魏参将和纤尘的进攻他还能应付，只是他一人如何能敌这数百士兵？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军想着，只要自己突围出去就有机会反败为胜，西郊营地还有一万士兵可供自己用，到时候他给魏参将冠个谋反的罪名不怕弄不死他。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他环顾一眼四周，瑞王和他的那些士兵还趴在桌子上，心生一计，“魏参将，你看看瑞王和他的那些兵都已中毒，左右都是个死，你与我为敌又有何好处？不如我们和解，我既往不咎大家还是兄弟如何？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“曹将军，我忍你很久了，你身为交州的海防将军非但不保护交州百姓，还与东阴人联手欺压百姓，如今又陷害瑞王，我不是你的什么兄弟，我今天就要为民除害。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军没想到魏参将不吃他那一套，气急败坏怒喝：“魏孤青，你以下犯上是要造反吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;突然一柄剑从曹将军的身后架在了他的脖子上，“曹将军，那你呢，毒害本王算不算是造反？”这声音不急不缓却如同鬼魅，带着阴曹地府般死亡的气息。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348346, 1334318200997912576, '&nbsp;&nbsp;&nbsp;&nbsp;曹将军身子一僵，怎么可能，这是瑞王的声音？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他开始明明还推了瑞王好几下，确定瑞王是中了毒一点反应都没有，不是说迷迭露最少也会让人昏睡一个时辰吗？瑞王怎么这么快就醒了？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他不可置信，想回头看看身后的人究竟是不是瑞王，脖子刚一转动，就发现那柄剑抵在自己脖子上的力道更重了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;许是顾子毅看出了曹将军的疑惑，主动帮他解惑，冷哼一声，“哼，曹将军，你真当本王中毒了吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军脑子里嗡嗡炸响，什么意思，难道他没中毒？怎么会？酒里的毒他是吩咐自己最信得过的赵参将去做的，赵参将呢，怎么没看到赵参将的身影？曹将军这才想起整个酒宴上他都没看到赵参将的身影。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军已被控制住，顾子毅收回手里的剑，只见他双手在空中拍了两拍，那些还趴在桌上的士兵集体醒来，方海和阿峰也押了一个人出来，那个人不是别人正是赵参将。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此刻，曹将军看到赵参将方知大势已去，他深叹口气，仰天闭眼，两滴夹杂着复杂情愫的泪水滚落了下来，“你是怎么知道的？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军知道自己就要死了，在临死之前，他还是想知道，自己和张县令商议出来的这个天衣无缝的计划，顾子毅是怎么看出破绽的？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅故意凑近曹将军，脸上带着鬼魅般的邪气，“你想知道吗？本王偏不告诉你。”他的声音如同来自地狱，森冷的恐怖气息是压倒曹将军精神力的最后一根稻草，曹将军身子一软就瘫坐了下去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将被押了上来，他看到顾子毅就一把鼻涕一把泪，嘴里不停地求饶，“瑞王殿下，我冤枉呀，冤枉，我只是个参将，将军要我做什么我不得不做呀，这些都是将军逼我做的，求求殿下饶了我吧……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这人将所有的过错都推给了自己的将军，这样一个没有骨气的人，真不知道是怎么混进军营还当了参将的，顾子毅不屑多看赵参将一眼，转眼又看向被押在一起的张县令和曹将军。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;事已至此，张县令和曹将军心知唯有一死方可保全家人，他们没等顾子毅开口，双双就咬破了藏在嘴里的毒，片刻他们的身体就开始抽搐。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘见势不对，赶紧上前去给张县令和曹将军号脉，她的手才搭在曹将军的腕上，头已经摇了起来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“来不及了，他们服了竹桃散，这药烈起效又极快，我手上没有现成的解药。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;话音刚落，张县令和曹将军已经停止抽搐，乌黑的血就从他们的七窍流了出来，双双倒地身亡。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;张县令和曹将军双双服毒自尽，反倒让顾子毅心中生疑，剑眉紧锁感觉事有蹊跷。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅断定张县令、曹将军、东阴人这三者之间定没有看上去的那么简单，仿佛还有什么更深的秘密。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;无奈此二人已死，顾子毅又将目光投向了赵参将。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“说，这是怎么回事，你们是怎么勾结东阴人的，你们和东阴人还有什么秘密？”顾子毅的眼里闪着煞神般狠戾的光。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将早已被顾子毅身上散发出来的强烈煞气，吓得六神无主，小便失禁，双腿不听使唤抖得像筛糠，扑通一下就跪了下去，“殿下，殿下饶命呀，小的说，小的全说，……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将将这些年来，张县令和曹将军如何勾结东阴人，如何将京都的情报卖给东阴人等等信息和盘托出，真是做道了知无不言，言无不尽。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将知无不言，言无不尽说了一大通，顾子毅越听却越觉得疑惑，禁不住剑眉都拧在了一起。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将所说的信息里，有些是朝廷并没有下达到交州的信息，尤其是文侍郎给父皇献计一事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;因为当初文侍郎给父皇献的是如何剿灭东阴人之计，父皇知道东阴人是杀手组织，做事没有原则，他担心东阴人知晓文侍郎献计后会报复文侍郎，故而选在御书房单独召见的文侍郎，此事并没有在朝堂之上议出，知晓的人也不多，如此隐秘的消息曹将军又是怎么知道的？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅鹰鸷的眸子紧盯着赵参将，微眯的双眼带着不解和审视，“你说，京都四品侍郎文侍郎家的灭门案，与他献给皇上剿灭东阴人的计策有关？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这来自地域般阴冷恐怖的声音响起，赵参将就瑟瑟发抖，哪里还敢说半句假话，头点得跟鸡啄米一样，舌头都大了连带着声音都在打颤，“是，是的，这个灭门案很特别，没，没有雇主，我，我也是在陪同曹将军参加木鲁木图的答谢宴上听到的。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“答谢宴，什么答谢宴？”顾子毅再一紧追问道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“那答谢宴，就是木鲁木图专门为答谢曹将军将京都的情报告知他而设的宴席。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将，顿了顿继续道：“那日张县令也有陪同，我记得那日曹将军就将殿下前往交州的目的，行军的路线和兵力情况都告知了木鲁木图。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;木鲁木图还夸下海口‘那文侍郎献计灭我们，我就灭了他满门，那三殿下来交州剿我们，无论他是神还是人，我都让他有来无回。’”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;好大的口气，可惜那木鲁木图已然是个死人，没必要生一个死人的气，顾子毅既没有生气也没有胜利者的喜悦，脸上纹丝不动看不出一丝情绪，心里却惊涛骇浪疑惑更甚，他原本以为，东阴人料事如神，是他们在京都安插了暗探，如今看来不是，是有人将京都的信息通过曹将军转交给了东阴人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅捏着眉角揉了揉，闭上眼沉思了片刻，突然一个激灵，他被自己的想法吓到，难道，难道问题出在宫里……？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅不敢想，没有证据的事不可胡猜乱测，他继续又追问赵参将：“曹将军又是怎么知道这些消息的？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“这个小的就真不知道了，曹将军对消息的来源守的很死，我既没见过他收到的信鸽，也没见过他与什么特别的人接头。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看赵参将的模样也不像是在说谎，顾子毅深吸一口气，又重重将它呼出，知道此刻再问也问不出什么名堂，便挥挥手示意让阿峰将人带下去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将被带下去，魏参将带着他的士兵们开始清理县衙府，纤尘觉得，此刻也没自己什么事，便准备悄然离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她刚一转身却被顾子毅一把拽住了手，顾子毅将她拉近自己身边凑近她的耳朵说了句，“等我，晚上我会来找你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这突来的举措有些暧昧，纤尘脸上刹那间红霞飞过，黛眉微蹙，赶紧抽回手，腼腆埋下头，逃也似的离开了县衙府回到客栈。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;魏参将不爱溜须拍马自然没有受到曹将军的重用，许多事他都被蒙在鼓里，曹将军当初提拔他当上参将一职，也只是看上他一身真功夫，想着若真有一天再上战场，能有个，有真本事的人替他挡在前面。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;然，魏参将跟着曹将军这么多年，身上也不会太干净，他心里有担忧，相信他手里的兵心里也有担忧，谁都怕秋后算账，魏参将怕士兵们更怕，此刻顾子毅还需去军营里稳定军心。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅带着方海和几个精锐士兵跟着魏参将和他的兵去了军营。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一路上顾子毅与魏参将有说有笑，主要还是顾子毅说的多一些。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他对魏参将这次功劳加以肯定，还说要嘉奖魏参将，这让魏参将心生惭愧，同时魏参将也更加肯定了顾子毅的为人，觉得顾子毅是一个值得追随的人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈守在纤尘的房间里，担心着纤尘的安慰，焦灼地等着她回来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吱嘎…一声门响，是纤尘推开门的声音，苏妈妈闻声，一步并做两步向纤尘走去，脸上写满了担忧，拉着纤尘的手，她提着的心才算放了下来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐您可回来啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看到苏妈妈脸上布满的担忧和憔悴，纤尘心感愧疚，抚了抚苏妈妈鬓角的白发道：“让妈妈担心了，是纤尘不对，纤尘以后尽量不那么晚回来。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈知道自家小姐从小就有主见，做什么事定是有她的道理，也不追问她今天去做了什么，只轻拍了拍纤尘的手道：“小姐，吴管家来了，在我房里。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家来了，来的甚好，纤尘还想着去老宅看看吴管家，既然他来了，她便不用再往老宅跑一趟。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘换下那身士兵装，二人款步向苏妈妈的房间走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家是沈家的老人，兢兢业业为沈家办事，沈家迁家去闲城后，吴管家舍不得交州，更舍不得老宅便坚持留了下来，这些年，他一直替沈家打理着交州的老宅和沈家在交州的肉铺，纤尘打心底感激着吴管家。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;进了门，吴管家见到多年未见的纤尘，佝偻着身子迎了过来，双眼含泪，慈目地将纤尘看了又看，“小、小姐已经出落成大姑娘了，老管家见过小姐！”说着吴管家就要跪下去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“吴叔你怎么跟我也客气上了？这可万万使不得，你是纤尘的长辈，快快请起。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348347, 1334318202440753152, '&nbsp;&nbsp;&nbsp;&nbsp;吴管家虽然已年过五十，人也不算胖，身子还有些佝偻，却也是个成年男子，纤尘架起吴管家，硬是没让他的膝盖落到地上，“吴叔你膝盖不好，你也知道我不看中这些个虚礼，快快请起。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家也不再勉强，起身望着纤尘忍不住道：“小姐，可比当年的大小姐还靓呢，要是大小姐还在，看到小姐如今的模样那得多开心呀！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家一句话顿时让这里的空气都充满了悲伤，一提到自己的母亲，纤尘的心就如刀割般疼，那苏妈妈更是又流出一把心酸泪。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;悲伤的空气让人窒息，吴管家感觉自己不小心提到了大家的伤心事，心里也是难受，尴尬得不知所措，连忙佝偻着身子，从他刚刚坐着的那张椅子底下拖出一个篮子来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐这是我家老婆子的一点心意，她知道您要回京都，特地给您做了您爱吃的蛋黄酥，小姐您就带在路上应个急。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家将篮子提起，又从篮子里拿出一个蛋黄酥递给纤尘，“小姐，您先尝一个，尝尝好吃不？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴家婶子做的蛋黄酥可是交州一绝，一层酥皮，一层莲蓉，将整个海鸭蛋黄包裹在里面，一口下去酥油四溢，醇香沙糯，香酥化渣。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“好吃，真好吃，还是小时候的味道……”纤尘咬下一口蛋黄酥，香甜软糯，对蛋黄酥的好吃赞不绝口，打破了这里悲伤着的空气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;气氛一下融洽了起来，苏妈妈破涕为笑，“小姐从小就喜欢吃吴家婶子做的蛋黄酥，有劳吴家婶子想得周到，他吴叔把篮子给我吧，我替小姐收着。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家将篮子递给苏妈妈，纤尘看到吴管家手上尤其是右手虎口位置布满了老茧，这些老茧在烛火的跳动中，忽明忽暗述说着吴管家这些年来的操劳，再看那烛火中他更加佝偻的身影，纤尘心里泛起了涟漪。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“苏妈妈，顺便替我将纸和笔拿来。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈放好篮子，很快便拿来纸和笔，纤尘写下一封信，信里的内容是：特批吴刚携家眷吴文氏前来疗养，时限半年，落款冉纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘写好信，将信折好又从脖子上取下一个玉佩，“吴叔，东东哥已经长大，铺子上的事就交给东东哥吧，婶子身子不好，你的腰腿也是老毛病了，这个给你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘将玉佩和信件缠在一起，交给吴管家继续道：“拿着我的玉佩和手书，带着婶子去闲城同善医行找鬼医，让他给你们安排半年的疗养治疗。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐，这……”吴管家感动得热泪盈眶，闲城同善医行的疗养治疗，那可是大周十国权贵才享受得起的地方，小姐一挥手，就给了他们安排了半年的免费疗养治疗，吴管家感动得不知道该说什么，粗糙的大手一把抹过他那沟壑纵横的脸，将脸上的泪水擦去，吸了吸鼻子又要给纤尘跪下，“老管家，老管家谢过大小姐恩德！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘赶紧又扶起吴管家，“吴叔，你快起来，快起来！”接着又问“吴叔你过会是不是要去军营找东东哥他们？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“是的小姐，军营那边人手不够，过会我就要赶过去帮忙。”吴管家点点头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“那吴叔，我有件事要请你帮忙。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐有事，吩咐就是。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你等等。”纤尘又提笔在一张新的信纸上写了几个字，“困，不等了，有事明早再说”。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她将信折好后交给吴管家，“吴叔，麻烦你替我将这封信交给瑞王殿下。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天军营一下定了一百头肉牛，军营里的厨子不够用，将沈家肉铺的伙计全都征了过去，帮忙杀牛，吴管家若不是给纤尘送这蛋黄酥又想和小姐见上一面，他也早去了军营。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家将信放进胸口的袋子里，告退道：“时间不早了，小姐早些休息，我这就去军营帮忙了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家来到军营，正好听到军营里练武场的台子上，顾子毅正大声说道：“纪国的将士们，你们都是纪国的栋梁，纪国的边疆，交州的百姓都需要你们的保护，曹将军犯下的错不能让你们来承担，从现在起，过去的事就一笔勾销，大家喝完这碗酒，还是我纪国保家卫国的好儿郎，还是我纪国的栋梁！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅豪爽地喝完碗里的酒，再豪气地将碗摔到地上，陶碗落地发出碎裂的声音。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;将士们跟着效仿，喝完碗里的酒，纷纷都将碗摔到了地上，砰朗、砰朗……一时间陶碗碎裂的声音此起彼伏。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此起彼伏的摔碗声刚刚退去，“瑞王千岁、千岁、千千岁……”的高呼声又齐声响起，声音震耳欲聋如潮水般澎湃。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;好不容易等到解散，士兵们各自散去，吴管家才寻得一个机会见到顾子毅，“瑞王殿下，这是我家少东家托老夫交给殿下的信。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家毕恭毕敬，埋着头，双手将信呈给顾子毅，顾子毅接过信，面无表情看完问道：“吴掌柜，纤尘姑娘果真是你们沈家肉铺的少东家吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家不知道瑞王为何这么问，小姐和他都谈成了一百头肉牛的大生意，难道他还怀疑小姐是少东家的身份？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;转而，吴管家又想，在纪国，一个家族的少东家几乎都是男儿，估计也只有沈家例外，瑞王许是因为小姐是个女儿身才有所怀疑的吧？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家连忙回道：“小姐确实是我沈家肉铺的少东家，这点还请殿下毋庸置疑。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;置疑？他置疑吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他不过是觉得纤尘一下又多了个身份，很是好奇，不知道这丫头还有多少新身份罢了，顾子毅脸上闪过一丝笑意，“嗯，本王知晓了，你下去吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;吴管家走后，顾子毅走到离军营不远的海边，坐在一个礁石上，将纤尘的信拿了出来，看了又看，嘴里还喃喃道“字写得挺好，娟秀，字如其人，哦，不对，人更漂亮。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅难掩心喜，脸上一直挂着一抹浅笑，他又小心翼翼将信折好放进自己胸口的兜子里，轻抚了抚自己胸口的位置，就像在轻抚一件稀世珍品，“尘尘，困了你就好好睡一觉，明早我再来……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅放好信躺在礁石上看着星空想着纤尘，那头的纤尘，已经泡完澡美美地睡了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;次日卯时天还没亮，顾子毅就迫不及待来到纤尘客房的门口，隔着门他试探性地问“纤尘，起床了吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘常年练功夫，习惯了早起，顾子毅来时她正好已经洗漱完毕。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这人怎么这么早就来了，客栈里其他的客人都还在睡觉，纤尘怕顾子毅吵醒其他的客人，一步并做两步赶紧去给顾子毅开门，“殿下……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘一句“殿下，你怎么这么早就来了？”还没说完，就见顾子毅将她打量了一番，见她衣服穿戴完整就打断了她，“走，跟我走。”&nbsp;拽着她就往客栈门外跑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘以为发生了什么事，跟着顾子毅一路跑出客栈，又要开口问，是怎么回事，是不是出什么事了？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;话还没问出来，突然她就顿感脚下一空整个人就飞了起来，是顾子毅将她拦腰抱起，带着她连飞过几个房顶后将她带到一处海边的礁石滩上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;远方的天际，海平面上，一轮红日羞答答试探着冒出头来，“太好啦，赶上了海上升红日，纤尘你快看！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅非常激动，因为京都在内陆即便有日出，那轮红日也是从连绵不断的山那头升起。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅常年作战在外，地方也只是在山里、草原还有沙漠，那些地方的日出都与海上日出的美景不同。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅来交州的当天就中了东阴人的伏击中了毒，强忍着中毒的痛苦，他将士兵们安顿好后，次日凌晨才塌上去闲城求医的路，因为去闲城他走的说水路，故而顾子毅才在船上看到了海上红日初升的美景。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他对这美景恋恋不忘，知道纤尘今天就要起身赶往京都，就想着与纤尘分享这海上日出的美景，一大早便将纤尘带到了这里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘做为一个在海边长大的孩子，对海上日出的美景早已习以为常，只是顾子毅的激动又将她的思绪带回了小时候，初次见到海上日出的情景。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那时她来闲庄还不久，刚开始学会站梅花桩，一大早起来站桩子，看到远方的一轮红日初升，霞光染红天际，将天边的云都烧了个金红，她被那美景吸引，一分神就从梅花桩上摔了下来，还摔了个狗啃屎。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“呵呵……”想到小时候的囧态，纤尘禁不住笑了出来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘笑得落落大方，露出洁白的贝齿，霞光洒在她身上，也将她染成了一身金红，宛如下凡的仙子，美得让顾子毅移不开眼睛。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“顾子毅，你火急火燎把我带出来，就是带我来看日出的吗？”纤尘清如泉的眸子看向顾子毅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅从失神中反应过来，嘴上也挂着一抹笑意，“纤尘，你刚叫我什么？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘反应过来，不知道自己刚刚脑子里是哪根经搭错了，竟脱口而出叫出了顾子毅的名讳，她福了福身“瑞王殿下，是臣女失礼了。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348348, 1334318203833262080, '&nbsp;&nbsp;&nbsp;&nbsp;顾子毅双手扶在纤尘肩头，将纤尘拉到自己面前，深情地说：“不，你这样不是失礼，纤尘，我喜欢，我喜欢你这样叫我，你知道吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅没有用本王来称呼自己，而是用我和你这样的方式互相称呼，因为他不想和纤尘产生距离感，他希望他们之间的关系能近些，再近些。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说着，顾子毅就将纤尘拥入了怀里，他搂着纤尘，将头埋在她的耳边继续说：“叫我顾子毅，以后你就叫我顾子毅，这是我给你的特权，我以后就叫你尘尘好吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这是在表白吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘推开顾子毅，望向他。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅身体底子好，解毒后再配上纤尘的丹药调息，他现在身体已经大好，脸上也恢复了健康的麦色，他的手依旧还扶在纤尘的肩头，背对着霞光，金辉洒在他的身上，给他整个人都染上了一层绚丽的边框，将他原本就轮廓分明的脸雕琢得更加俊美，身型也更加挺拔伟岸，俊爽有姿，散发出铺天盖地的男儿气息，他这样的气息吸引着纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅正深情的看着纤尘，四目相对，两人之间有电光火花闪过。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;理智和感性开始斗争，纤尘稳了稳心神。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她对顾子毅确实有好感，她也能感觉到顾子毅对自己的好，只是情感对现在的她来说还是奢侈品，她无法回应顾子毅的好，便低下头向顾子毅福了福身，“瑞王殿下，这与礼不合。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“礼？我不在乎，合不合又能怎样？尘尘，不要与我生分，就唤我顾子毅好吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;情到浓时顺理成章，顾子毅已经抬起了纤尘的下巴，“尘尘……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一只温柔的手将自己的下巴抬起，眼看这只手的主人一张性感的唇就要盖在自己的唇上，纤尘的心似小鹿乱蹿，慌乱的厉害。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;理智和感性再次激战，终于理智又占了上风。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘偏过头，借福身行礼后退了几步，整个人脱离了顾子毅的怀抱，“谢殿下抬爱，那纤尘恭敬不如从命！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅僵了僵，刹那间他的心像被一双无形的大手捏了一下，有些钝痛，有些莫名的失落，慌乱得不知所措。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;昨夜顾子毅心不在焉在海边踱步，阿峰就猜到他心里定是想着纤尘姑娘，煞有介事地对他说：“主子，男人要想抓住一个女人的心，就要学会耍点小流氓，不能过，还要恰到好处。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰没谈过恋爱，这么有深意的至理名言定不会是他想出来的，顾子毅疑惑地看着阿峰，“说，谁给你说的？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰神秘兮兮地笑笑，“主子，不是别人给我说的，是我偷听来的。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原来是熙王殿下向康王殿下传授撩妹经验时，被他无意间听到的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;熙王殿下，何许人也？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪国情场圣手，纪武帝第五个皇子顾子祺，不爱朝政，不爱钱，只爱美人，他府上那可是名副其实的美女成群。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;传说熙王殿下勾搭美女，慢则半月，快则半天，就可将他瞄准的女子勾搭到床上去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;既然，阿峰说是五弟弟总结出来的情场经验，那定不会有错。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;昨夜，顾子毅面朝大海想了一夜，他想了许多，许多，就连开始调情的语言路数都1、2、3……列了出来：<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;比如——小丫头骗子，竟然是沈家肉铺的少主，哼，哼，把我当冤大头宰，一次卖我一百头肉牛，你这样赤裸裸的讹诈我，让我身心受损，你得赔我……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;呵呵，如果纤尘要问出陪什么，他便会向她索要一个吻。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;呵呵，想着都好甜蜜……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;再比如——他拽着她的手，将她强势搂在怀里，抚着她的秀发咬着她的耳朵在她耳边直接表白：纤尘我喜欢你，我要娶你……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;如果纤尘也喜欢自己，他会让太阳作证，告诉纤尘他爱她的心比太阳还热。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;呵呵，他再给她一个深情的吻。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;呵呵，想想都好甜……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;想了一夜甜蜜的顾子毅，原本脑子里装满了东西，没想到纤尘借福身行礼整个人脱离自己怀抱后，顾子毅的脑子里也一下就空了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;昨夜他想到的话一句都没想起来，只紧张地问了句，“尘尘，你家在京都什么地方，我要去找你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;瑞王问得到还挺干脆，纤尘想，父亲是正二品官员，他回到京都不用打听，也能知道自己是谁家的女儿，没必要瞒着他，便问道：“瑞王，若我是冉府的女儿，你还会来找我吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“冉府，哪个冉府？”顾子毅常年镇守边疆，脑子一时没转过弯来，顿了片刻才反应过来，“你说的冉府是大行台尚书令冉羽涅，冉大人的府中吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘点点头“正是。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅疑惑了，“我从未听说过，冉大人在外面还有一个女儿呀？”他就差没问出来，难道你是冉大人的私生女？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘仿佛看穿了顾子毅心里的疑惑，她心里一酸，脸上却看不出半点情绪来，“我是冉府的嫡长女，只不过，不是姚氏所生，我生母早已离世。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“对不起，勾起了你的伤心事。”顾子毅慌忙陪着不是。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘摇摇头，“这没什么，你还没回答我，我是冉府的女儿你还愿意来找我吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘对纪国朝堂有所了解，纪武帝宠爱康王，大家都认为康王会是未来的皇位继承人，站队康王的人不少，父亲就是其中一个，再加上康王又与她的二妹妹姚氏之女有婚约，父亲更是一股脑的支持着康王，成了康王势力的中流砥柱。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅常年带兵在外，如今边疆无战事，一回朝，纪武帝就收回了他的兵权，并将他的兵权交给了康王，顾子毅对康王没有半点介怀，纤尘不信，对父亲，纤尘猜顾子毅定然也是不喜欢的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;有人说爱屋及乌，那如果是厌屋会不会也及乌呢？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“尘尘，我会来找你的，我与你交往与冉府其它事无关，与朝堂之事也无关，我找你只因为那个人是你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他说得很诚恳，深邃的眸子里露出发自内心的真诚，这让纤尘有些意外，心里也倍感温暖。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;起初纤尘不排斥顾子毅，那是因为她觉得顾子毅和自己的遭遇差不多，都是没了娘，爹不爱的孩子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这几日交往下来，她发现他为人挺好，她愿意去交顾子毅这位朋友，如果顾子毅因为康王和冉府而对她有所顾忌，那她也不会为难朋友，以后就不和他交往便是。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她没想到顾子毅回答得这么干脆，一时间纤尘也不知道该对他说些什么，便回了顾子毅一个温婉的笑，“多谢。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;太阳已经挂在了天空，启明星也已经消失不见，纤尘和顾子毅这才向着客栈的方向走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“尘尘，我给你安排了马车，阿峰也跟你们一起回去，有她在你身边我也放心些。”顾子毅突然说。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘正想拒绝顾子毅的好意，嘴还没动又听见顾子毅说，“不要忙着回绝我，我也是有私心的，我觉得那东阴人的事情不简单，也许还会牵扯出纪国更多的秘密，赵参将留在交州恐不安全，我让阿峰先把他带回京都秘密看押，有你的马车做掩护，阿峰带着赵参将回去也要方便些。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原来如此，纤尘就不再拒绝，同意了顾子毅的安排。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;因为阿峰是乔装带走赵参将的，顾子毅也不便再在客栈出现，怕有人看见他出入客栈怀疑上那辆马车，纤尘就一个人回了客栈。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;回到客栈，乔装成车夫的阿峰已经架着马车来到了客栈门口，纤尘掀开帘子的一角，看到马车里被五花大绑嘴里还噻了布团的赵参将，心想，这可不行，他这样定会吓到苏妈妈和韩双双姑娘的，再说那个韩双双姑娘，自己还不太了解她万一半路出了什么幺蛾子怎么办？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一根毒针随即出现在纤尘手里，纤尘上车就向那赵参将后脑的哑门穴上施了一针。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将木讷地看向纤尘，不知道她对自己做了什么，只觉得后脑某个地方像蚂蚁咬了一般，即刻，自己的身子就没了力气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘正要去替赵参将解开绳子，阿峰一把抓住她的手，“小姐，不可解开，这人狡猾万一跑了呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“放心，他跑不了。”接着，纤尘柳眉微蹙看向阿峰，不知道阿峰是口误还是另有原因问道：“小姐，你怎么叫我小姐啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰挠挠头，“主子说我现在是你的车夫，自然不能再叫你纤尘姑娘，叫小姐可以避免被人猜疑。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅考虑事情还真周到，纤尘点点头，旋即又一把将那赵参将嘴里的布团扯下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那赵参将张口，就要问纤尘对自己做了什么，为什么自己身上一点力气都没有，他一张嘴，才发现自己根本就说不出话来，不由的就慌了起来，张着嘴，“啊、啊、啊……”啊了半响，也啊不出什么声来，以为自己被纤尘弄成了个哑巴，惊恐地看向纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这人可是证人，刚刚还好好的，现在怎么就说不出话啦？阿峰也慌了，看向纤尘问道：“他怎么啦，怎么就哑巴啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘不慌不忙解释道：“交州到京都还有月余的路程，你这样一直绑着他，万一被人撞见，误会我们，那我们岂不是自己给自己找麻烦，我给他施了针下了药，他只是暂时说不出话，全身也只是暂时失去力气动弹不得，我们就说他是个病人，带病人去京都求医这也不会招人怀疑。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348349, 1334318205984940032, '&nbsp;&nbsp;&nbsp;&nbsp;懂医的人就是牛，阿峰点点头，佩服道：“还是小姐本事大。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;经过强化训练出来的侍卫就是不一般，说改口就改口，这一口一个小姐叫得毫无违和感，“知道我本事大，那就帮我给他松绑吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰闻声便去给赵参将解绳子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这绳子一解，赵参将身子就不受控地瘫了下去，阿峰将他连拖带抱，抱到马车车厢尾部的转角位子坐下，借着车厢两边转角的支力，赵参将才勉强坐稳。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;继而，纤尘又看向赵参将，“赵参将，你是个聪明人，应该知道我们是在保护你，想必，那躲在曹将军背后之人权势滔天，绝对不会容下你这个活口存在，你要想真正保命，唯有配合好瑞王殿下，配合好我们，你现在就好好扮演一个病人，不要给我们添乱子方有活命的机会。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘话里的道理，赵参将不是不懂，所以他想到过逃跑，他想着只要逃离纪国他就安全了，没想到这丫头一根毒针就断了自己的念想，此刻的赵参将是想哭都哭不出来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;马车里一切安排妥当后纤尘才进了客栈，韩双双也已经收拾好行囊陪着苏妈妈在客房里等纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘看了一眼韩双双再次问了她一句，“你可真的想好了？你卖身给我后就是奴籍了，你若现在后悔，我还可以将卖身契还给你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;奴籍算什么，大户人家的奴婢丫头，可比普通人家的姑娘吃得好穿得好，再说，她在交州早已无依无靠，父亲留下来的那点银子她也快花光了，她又没那养活自己的本事，沦为奴婢那也是迟早的事，更何况若自己真有那个运气，成了一位高官家的姨娘，凭她的手段那奴籍自然而然也会被取消。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双点点头，“我想好了，我要跟随小姐，这辈子都忠心于小姐。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘知道像韩双双这样的女子是有野心的，与其说她忠心于自己，不如说她在忠心于她的野心，她不动声色莞尔一笑，“好，你忠心于我，我定不会薄待了你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘又看向苏妈妈“苏妈妈，可收拾妥当？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐放心，都收好了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“那我们就走吧。”纤尘带着苏妈妈和韩双双离开客栈上了马车。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;马车上早已有个男子坐在里面，那个男子看起来病怏怏有气无力的，苏妈妈和韩双双见到那个男子都很诧异。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈诧异的是，小姐怎么会带一个陌生男子回京都，这个陌生男子会是个什么人？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双诧异的是，此人不正是交州花楼的常客赵参将吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曾几何时她也对赵参将动过心思，她认为在交州赵参将是个比上不足比下有余的人物，定也不缺钱，一打听才知道，此人极不顾家，钱全花在吃、喝、嫖、赌上了，家里连件像样的家具都没有，她就打消了和赵参将好的念头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双见了赵参将诧异，赵参将见到她又何尝不诧异？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这女子，不就是这段时间一直在客栈边上卖身葬父的那女子吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;别说他对她还真有过好感，只是此女一心想要抱个粗大腿，不屑于他，再加上纪国法纪严明，强抢民女是重罪，花楼里年轻貌美的女子多了去，找女人那是用银子就能解决的事，没必要去触犯律法。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将骚扰过几次韩双双，无果，他便也放弃了她。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双和赵参将四目相对，他两诧异的目光都落在了纤尘眼里，纤尘不动声色只是嘴角微勾了勾，旋即闭上眼对车厢外的阿峰道：“阿峰，启程。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;马车向交州城门驶去，顾子毅站在远处目送他们离去，默默祈祷，祝福他们一路平安。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;心想往往不能事成，纤尘他们的马车刚使出交州城门没多会就遇上了山匪，是在距交州城门百里开外的一个山道上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这里隶属交州，交州县令又不作为，每年闲城的海货节都会吸引不少纪国的商贾前去闲城采办，这条山道是纪国其它地方前往交州的必经之路，交州又是纪国前往闲城的必经之路。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这些山匪就是看准这个时机，便在这条必经的山道上设下障碍，收取过路费。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“此路是我开，此树是我栽，要从此路过，留下买路钱。”&nbsp;几个扛着刀的彪形大汉，唱着老掉牙的开场白，拦在了阿峰的马车面前。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰拉停马不屑地看向那些山匪。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;车厢里，纤尘依旧闭着眼，沉着冷静不慌不乱。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;打着盹的苏妈妈突然睁开眼，她看了看自家小姐，见她家小姐气定神闲的模样，便也放下心来又打起了盹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;遇到山匪绝不是什么好事，这些人还可以跑，自己现在就是一个瘫子全身动弹不得，靠坐在车厢最后面的赵参将缺是提心吊胆的生怕自己的小命就丢在了这里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双心里也很紧张，她偷偷掀开窗帘的一角，往外看了看，这一看更是把她吓得不轻！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;我的个妈呀！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;十几个满脸横肉的山匪正向他们的马车靠近，韩双双的小脸顿时吓得惨白，手上不停地打着哆嗦，心想完了、完了，本来是想着去京都过好日子，这下好了，好日子还没过上，就要落入山匪手里了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小，小姐，那些山匪只要给点钱就会放我们过去，我们给他们点钱吧。”韩双双颤着声音说。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘想，多一事不如少一事，此地有山匪之事就事后给顾子毅休书一封，让他带兵前来剿匪便可，就对阿峰说：“阿峰，问他们要多少钱，我们给。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰也明白现在不是逞强的时候，毕竟赵参将还在车上，万一走露了风声，王爷的心思就白费了，便开口问道：“你们要多少钱？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;其中一个山匪说：“我们按货量抽水钱，要多少钱得看你车里有多少货，让弟兄们进车里看看就知道了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“上车不行，直接说价钱。”阿峰冷声道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见那些山匪不知死活，还在向马车靠近，阿峰的心里已经起了杀意，心想，若他们敢掀马车帘子，那他就没有再留下他们的必要。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你不让我们上车，莫不是车上有女人？那就留下一个女人，我们也让你通过。”一个流里流气的山匪，嘴里嚼着槟郎，呲着一口大焦牙说道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这个山匪说出来的话让纤尘很是反感，纤尘对待山匪也不是个心软的主，既然给了他们机会，他们没有珍惜，那就不要怪他们不客气了，“阿峰，你能解决吗？”纤尘淡淡的问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哼！”阿峰冷哼一声，不屑道：“小姐，这些不入流的家伙，别说就这十来个，就是再来几十个我也没把他们放在眼里。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“那好，你就当锻炼一下身体吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘见过阿峰与木鲁木图对战，他的实力纤尘心里有数，他不担心阿峰会败。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗖”的一下，阿峰腾空一跃飞离马车。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;马车的车厢轻轻抖了抖又恢复了平静。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“当”的一声脆响，是宝剑出鞘划破长空的声音，也是纤尘熟悉的声音，她知道是阿峰拔出了剑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这些山匪虽然都是练家子；但是在从小经过严格训练，再层层筛选出来的顶级侍卫阿峰眼里，他们就成了跳梁小丑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一阵风吹过，带着风吹树叶的簌簌声，剑是一把好剑乃是精铁所炼，人是一个挑剔的人只观脖颈，不浪费一点时间，树叶飘落剑身一分为二断落地上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;剑刃擦过脖间，一丝细口，一抹腥红，气绝毙命。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;嗖、嗖、嗖……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;只见剑影不见刀光，然，剑不寂寞，还有风在陪它。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;剑收，风停，人倒地，这里的山匪全数毙命在阿峰的剑下，无一人生还。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这便是实力的碾压，那些山匪与阿峰的实力悬殊太大，别无选择只能成为阿峰的剑下魂。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;马车外一片安静，连风的声音都没有了，纤尘才开口缓缓问道：“解决啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯。”阿峰嗯了一声，就跳回了马车。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“那我们就继续赶路吧。”纤尘的语气不急不缓，就好像他们刚刚遇到的不是山匪，只是一个小小的障碍物一样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;驾……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰扬鞭打马。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈闭着眼全当什么都没发生，赵参将悬着的心也落了下来，唯有韩双双好奇，再次忍不住掀开了窗帘向外看，这一看又把她惊得不轻！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;我的个神呀，那侍位还是个人吗？只一会功夫就那十几个五大三粗的山匪全杀死了！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这样的侍位，一般的人家怎么养得起？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双再次暗自己庆幸自己的选择，她觉得自己跟对了人，她笃定纤尘的父亲定是纪国朝堂之上的大官，她还不知道，像阿峰这样的侍卫，是专为纪国皇族培育出来的皇族侍卫，纤尘父亲官位再大也不配拥有。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在回京都的路上，纤尘他们也就遇到这一个小插曲，这一路下来都还算顺利，纤尘也早早休书一封告诉了顾子毅交州城外有山匪之事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;眼看就要到京都，天色已晚，他们在京都近郊的一个小镇住下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将还是像当初离开交州一样，一直瘫软着吭不出半点声来，由阿峰抱着进了房间，纤尘也跟了进去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天，她取出埋在赵参将哑门穴、里的银针。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348350, 1334318209659150336, '&nbsp;&nbsp;&nbsp;&nbsp;这一路走来，赵参将还算配合他们，做好了一个又哑又瘫的病人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天，纤尘突然将赵参将后脑哑门穴的针拔了出来，一时间赵参将也没反应过来，依旧木讷地躺在床上，他也不开口问纤尘又对自己做了什么，因为他知道自己即便是问了那也是白问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参不问，纤尘却自己说了出来，“阿峰，明天一早，我们就要分道扬镳，我提前拔了他哑门穴、里的针，他已经可以开口说话了，接下来的路我们不能再陪着你，你自己要多加小心。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘又从袖兜里取出一个小瓷瓶，将这一个小瓷瓶子递给阿峰，“这是他的解药，解药只有这一瓶，你好生保管。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“多谢纤尘姑娘，这一路阿峰给纤尘姑娘添麻烦了。”阿峰拱手谢过纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘虚扶一把，“阿峰，你客气了，你先看好他，我这就去安排晚膳。”说完便转身离开了这个房间。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰则在桌边坐下，拿着那个小瓷品把玩，完全无视床上躺着的赵参将，赵参将看着阿峰拿着那个小瓷瓶把玩，那小瓷瓶在他手里飞来转去，也不敢主动去找阿峰说话，深怕自己一开口就分了阿峰的心神，那小瓷瓶一不小心就落到了地上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不多会儿，韩双双端着饭菜进来，“公子，晚膳安排好了，小姐让我过来侍候赵公子用善。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯，好，有劳双双姑娘了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰随手就将那个小瓷瓶放在桌上，来到床边，一如既往地将瘫在床上的赵参将扶到床头靠好后，又对端着饭菜的韩双双道：“这里就先交给你，我这就出去吃饭了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯。”韩双双点点头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;从交州赶往京都这月余的时间里，每天都是韩双双前来给赵参将喂饭，每次韩双双来，阿峰就会出去吃饭，今天也不例外。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰与韩双双客套完后便出了房间，带上了房门，这一切看起来都与往常没有什么不同。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将他的眼睛就没离开过桌子上那个小瓶子，他见阿峰离去，竟然忘了拿桌上的小瓶心里忍不住一阵窃喜。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双一如既往地给他喂饭，他边张着口吃饭，边盯着桌上那个瓷瓶，深怕那瓶子滑落桌面，更怕阿峰突然进来将瓶子拿走。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他提心吊胆吃了几口饭，迟迟不见阿峰进来将那瓷瓶拿走，心想莫不是阿峰真将这个小瓷瓶给忘记了？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将回想往日，阿峰出去吃饭，约莫都要用到半炷香的时间才回进来，半炷香的时间不短，只要韩双双愿意帮自己，他们是来得及逃走的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“双双姑娘，救救我。”赵参将恳求。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这个一个月来，赵参将都像个哑巴一样，韩双双从未见他开口说过话，今天他这突然一开口，反倒将韩双双吓得不轻，手里端着的碗都差点打翻，惊慌失措地问：“你，你能说话啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“双双姑娘你别怕，我被那个女人下了针，她封了我的哑穴，我才一直不能说话来，这会针被拔了出来，我自然就能开口说话，你看到桌子上那个瓶子了吗？那是我的解药，你帮我拿过来。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双转身看向桌子，那上面确实有一个像放着药的小瓷瓶，赵参将见她只是看着瓶子却没有替他拿来的意思，便又道：“双双，只要你将那瓶子给我，我保证带你远走高飞。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;什么情况？你带我远走高飞？要知道我在交州时就没看上你，要不然当初也就不会拒了你，我卖身葬父好不容易攀上高枝，你带我远走高飞，你在做什么白日梦呢？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双什么话都没说只一脸鄙视地看着赵参将。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将见韩双双不为所动，便知道这个丫头野心不小，自己这个身份他根本就看不上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;心里一番合计：<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“双双姑娘，我知道你想要什么，你不就是想进入大户人家吗？想有机会当上大户人家的姨娘，我有个姨妈在镇南将军王府里当管事，镇南将军王可是朝堂一品大员，只要你帮我，我就让我姨妈把你弄进镇南将军王府里如何？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双在心里也合计了一番：<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;镇南将军王府确实很诱人，不过她野心没那么大，朝堂一品武将镇南将军王是皇后的亲哥哥，一人之下万人之上连纪武帝都会给他三分颜面，这样一个了不得的大人物，想必身边少不了一等一的精明丫鬟侍候，也少不了削尖脑袋想爬上他床的女子，她韩双双就一点魅惑人的小本事，就不要去镇南将军府里凑那个热闹了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;再说，她在与纤尘相处的这月余时间里，她能感觉到纤尘的为人，她不是那种对下人苛刻的主子，即便自己以后没那个命当上姨娘，她一直呆在纤尘身边做事，只要不背了她的意，她相信纤尘定然不会亏待自己。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双摇摇头，“赵参将，我不能帮你，我答应过效忠我家小姐，我绝不做那背信弃义之事。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双这话连赵参将都不信，“我呸，韩双双你什么样的人，我能不知道？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;当初你要不是嫌弃我手上没存款，还不是早爬上了我的床，你连魏孤青那样一个已婚的木头都能去勾搭，不就是想找个有钱的男人给你依靠吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那丫头许你什么好处了，你连一个朝堂上一品大员这样的男人都不要，要跟她？你开个价，只要你举手之劳将那瓶药递给我，你要多少钱我姨妈定会帮我付给你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;面对赵参将戳自己脊梁骨的话，韩双双自然心生不悦，她脸色也沉了下来，没好气道：“赵参将，我是想找个男人靠，可我要找我靠得住的男人，靠不住的男人倒贴给我，我还不接手呢！。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双没好气将碗凑到赵参将面前，愤然地问：“你还吃不吃？不吃我就端走了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将知道韩双双说的那个贴她的男人是谁，不就是在奚落他曾经想娶她，被她给拒绝了吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双油盐不进，赵参将狠狠剜了她一眼又轻蔑道：“韩双双，我这样年轻的男人你靠不住，那些老头你就靠得住啦？你这女人脸皮可真厚，不就是穷怕了，想去大户人家给人做妾不再受穷罢了，还把自己说得这样冠冕堂皇，真不要脸，也对，你要什么脸，你要脸就不会想到跪到大街上去假卖身葬父了！......”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双没想到，自己今天来伺候喂饭还喂了自己一肚子火来，她一刻也不想在赵参将的房里多呆，她也不管赵参将还吃不吃，索性收起碗就起身出去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;路过桌子时，她还故意将桌子上的瓶子碰到地上，一声清脆的瓷瓶声响起，瓶碎液流，赵参将的解药就这样没了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双心里有种报复般的快感，冷冷补上一句，“你这种人就一辈子做个瘫子吧！”便她头也不回愤然离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见那瓶子滚落地上摔了个岁岁平安，瓶子里的液体全数流到地上，赵参将急了老羞成怒，那可是他的解药，听那女人说这解药只有这一瓶，那以后他不就只能做个瘫子了？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;早知道韩双双是这么个无情的人，他就不该去求她，赵参将现在肠子都悔青了，他真想冲出去将那韩双双给掐死，无奈他还中着毒全身动弹不得，只能破口大骂——“韩双双，你这个不要脸的女人，你这个贱货……老子当初就该上了你，断了你这个下贱货的念想……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将一口下流话，骂起人来不亚于一个泼妇。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“啧啧…赵参将，你的嘴刚刚解放，就开始滔滔不绝地喷着粪。”阿峰嘴里叼着根剔牙的竹签，戏虐地看向赵参将，接着又不怀好意道：“看你这个样子倒是有些像市井里争风吃醋的泼妇，不知道的，还认为你被哪家姑娘甩了或者是被老婆带上了绿帽子呢！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将本想怼回去，一看来人是阿峰，这个人他惹不起，瞬间也没了脾气，将到嘴的话给吞了回去，委屈道：“那丫头把解药打翻了，我在生他的气。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哦...原来如此。”阿峰故做恍然大悟，点点头后便没有再做声。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;其实屋子里发生的一切阿峰全知道，这本来就是纤尘和他设的局。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在交州时，纤尘就从赵参将和韩双双诧异的眼神中看出了他们彼此想熟，她便设下了这个局，一来纤尘想试探一下韩双双，看此人到底能不能留在身边；二来，也是想看看赵参将还想不想逃，若逃了，他的退路在什么地方？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天这么一试探，纤尘和阿峰心里也都有了结果。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看来韩双双这个丫头纤尘还是可以继续留在身边的，至于那个赵参将嘛？文不能磨墨，武不能拿刀就是一个草包。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰一直纳闷，赵参将身为一个军人，胆子小得尿裤子，像他这样的人，怎么会被武将出生的曹将军看中，还提拔当了参将的？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天这局一出，他也得到了答案，原来这人就是个关系户。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军是镇南将军王一手提拔起来的武将，镇南将军王对曹将军来说有知遇之恩，这赵参将的姨妈又是镇南将军府管事妈妈的侄儿，他自然会提拔镇南将军府里的人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;只是，阿峰心里又有了疑惑，那赵参将知道曹将军勾结东阴人的事，难道就不会将此事告诉镇南将军王吗？还是镇南将军王本就知道此事，只是知道当不知道？', NULL, NULL);
INSERT INTO `book_content` VALUES (3348351, 1334318211835994112, '&nbsp;&nbsp;&nbsp;&nbsp;那日，顾子毅审问完赵参将时就猜到，在纪国真正与东阴人有所勾结的人应该来自宫里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘又何尝没有怀疑过曹将军他们？从曹将军和张县令他们双双服毒自尽那一刻起，纤尘就断定纪国和东阴人之间的事没那么简单。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她也猜到曹将军和张县令为何会双双服毒自尽，他们不过是想以自尽的方式来保全家人，这样就不难猜出他们背后的人在纪国势力非同小可，故而她才和阿峰设了这个局，就是想从赵参将的身上寻得一些蛛丝马迹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在从交州回京都的这段路上，纤尘故意安排韩双双一直照顾赵参将饮食，而且每次韩双双来，阿峰都会出去吃饭，每次他出去吃饭的时间都会花上半炷香的时间，这样一来，时间长了韩双双和赵参将便会习以为常。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;明天出发，他们一早就要分道扬镳，纤尘这个时候拔出赵参将脑子里的针，还将解药给了阿峰，这些看起来都是理所应当的事，韩双双和赵参都不会想到，他们今天闹的这一处，不过是自己不知不觉走进了纤尘和阿峰设下的局里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰没想到这局一出，牵扯到的人竟然是镇南将军王？这也太让人感到匪夷所思。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;镇南将军王是纪国正一品的大将军，在纪国是真正一人之下万人之上的存在，纪武帝对镇南将军王也是敬让有加，他的妹妹还是当今皇后，阿峰怎么都不会相信，曹将军他们背后真正与东阴人有所勾结的人会是镇南将军王。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰陷入苦思，久久不作声，房间里陷入焦灼的寂静中。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我的解药被她打翻了，我还，还有解药吗？”&nbsp;赵参将终于忍不住开口，打破了围绕在阿峰身边的那份焦灼的寂静。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哎……!阿峰叹了一口气，很多事都没有表面看起来那么简单，这一切恐怕也只有等主子回来后才查得出结果，他看了一眼床上的赵参将，手一摊道：“纤尘姑娘说了，现成的解药只有这一瓶。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰的样子一本正经的一点也不像在骗人，赵参将急得哇的一下就哭了起来，“我，我不会就这样瘫下去了吧？……呜、呜、呜……我瘫了以后该怎么办呀？……呜、呜、呜……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰这样一个铁骨铮铮的男儿，平日里最看不起的便是赵参将这样懦弱无能的怂包。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他眉头一锁不耐烦道：“你若配合我们王爷，做好证人，兴许王爷会找纤尘姑娘给你再配置一份解药，你若有所隐瞒还想逃跑，那一辈子就这样瘫着吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我配合，我定好好配合。”赵参将像只摇尾乞怜的狗，看上去要多可怜就有多可怜。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰不想再多看一眼这个没有骨气的怂包，旋即，闭上眼，捏着眉角道：“我要休息，不要发出声音来打扰我。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;赵参将立马闭上了嘴，连大气都不敢出，深怕自己呼吸重了也会打扰到阿峰。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;次日，纤尘起来已经换了一个人，她将炙好的花粉涂在自己脸上，将自己这张白里透红的脸涂得腊黄、腊黄的，这黄里还透着点黑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她又用药膏盖住了那双黛眉和樱桃小、唇的颜色，让人看起来她眉淡如水，唇白如纸，整个人看起来就像生着什么怪病一样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她的头发像男子一样高高束起，用一个布团一缠，像极了普通铺子里跑堂的伙计。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;唯有这身紫色的罗裙，还能看出她是个女儿身，只是她腊黄的脸在这身紫衣的存托下显得就更加的难看了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小，小姐你，你怎么打扮成这样？”苏妈妈进来替纤尘收拾行李时，被纤尘这个模样吓了一跳。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“苏妈妈，日后你便会明白。”纤尘边修饰自己的妆容边回着苏妈妈。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈愁眉苦脸地看了一眼还在认真修妆的纤尘，啧啧嘴埋怨道：“不知道你又再搞什么，把自己打扮得那么丑，看你以后怎么嫁人？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈说完嘴一翘，堵住气就去收拾东西，不去搭理纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘会心一笑，“苏妈妈，我不就是还不想嫁人才把自己弄丑的嘛？”她边说还边看着铜镜里的自己，对自己的丑样子似乎还很满意。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;对纤尘这样一位仙子般的美女来说，扮丑比扮漂亮难，她要让自己丑，丑得还要不着痕迹就更难，这个妆她可是天还没亮就起来捣鼓起的，捣鼓到现在出发的时辰都要到了她才捣鼓满意。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“说什么瞎话，你都已经过了及笄年龄，今年都二八啦，错过二八年再不嫁人就不好嫁了！”苏妈妈心里有气，她气得是纤尘这么不心疼自己，将自己一张俊脸糟蹋像个病人一样，她是真的担心，外人看了纤尘这个模样会怀疑纤尘有什么怪病从而错过好姻缘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘在铜镜前将自己看了又看，感觉看不出什么刻意的痕迹后她才走向苏妈妈，拉了拉正在忙碌的苏妈妈衣角，小女儿般撒娇道：“苏妈妈，你看自然吗？上过妆的痕迹明显吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐，你怎么会怎么作贱自己，人家上妆是把自己打扮漂亮，你看你上的什么妆？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在床边收拾着行礼打包的苏妈妈是真的生气了，她将纤尘的手抛开，停下手里的伙计，坐到床边撇过脸埋着头赌气不去看纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘知道苏妈妈对自己好，她能容忍自己做很多事，比如买下韩双双这样一个狐媚子，唯独不能容忍自己伤害自己，她看见自己练功时受伤留下的疤痕都会躲到一边偷偷落泪好一阵子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘也不瞒苏妈妈，她蹲到苏妈妈身边，像个做错事的孩子拉着苏妈妈的衣脚摇了摇，“苏妈妈，别生气了，听我给你解释。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈没搭理纤尘又撇过脸去，纤尘继续摇着她的衣角，“苏妈妈，你认为这次父亲招我回冉府，真是祖母病了想见见我这么简单吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“那还有其它什么原因吗？”此句一出，苏妈妈也不再赌气，立马关心起纤尘来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“苏妈妈，你还记得祖母当年说过的话吗？”纤尘问蹲在苏妈妈身前，抚着他的手问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈还在一本正经地回忆过去，纤尘就继续说道：“当年祖母就是怕我在姚氏的手里早夭，才让你将带我回沈家，祖母当年说的是：‘如果冉府太平她会亲自来接纤尘回家，如果冉府不太平，她宁可一辈子不见纤尘，她只要纤尘活着不见比见好。’如今父亲一封家书，就说祖母病重想见我，就招我回冉府这其中的深意你想过没？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈心里一紧，她的脑子笨，想不出什么深意来，经纤尘这么一分析她只觉得冉府这次招小姐回府定没安什么好心，于是握着纤尘拽着自己衣角的手，忙问：“小姐，那你觉得冉府打得是什么注意？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看到苏妈妈紧张自己的模样，纤尘心里一暖，禁不住轻抚了抚苏妈妈的脸颊，“苏妈妈，你都说了，我今年已二八了，那姚氏的女儿比我小两岁，她即将及笄，她从小便和九王爷定了亲，及笄后就会定日子成亲，父亲是二品文官，姚氏在外又是一副贤、良、淑、德无一不占，识大体的好形象，他们能容下，嫡长姐未嫁嫡妹就先出嫁这样的话柄给旁人吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈深吸一口气，“那小姐的意思是说，这次冉府招小姐回来，是想给你说亲？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘点点头，苏妈妈想了片刻，脑子方才开窍道：“那姚氏心如蛇蝎，她定不会给小姐找个好人家的，小姐你可得当心呀！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“自古儿女婚事父母之命，媒妁之言，那姚氏现在是嫡母，若执意将我嫁给什么歪瓜裂枣，我要反击都很难，现在唯有先下手为强，让大家都觉得我丑，又像有病的样子，举止也不像个女子，唯有这样才能打消很多人的念想。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;少了媒婆登门，姚氏想把我胡乱嫁出去也没那么容易，这样我们才能争取到更多斡旋的时间。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈恍然大悟，“小姐，还是小姐想得周到，都是奴婢欠考虑误会了小姐，还认为小姐是在作贱自己。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈猛然抬头，赶紧端起起纤尘的脸仔细看又看，“自然，这丑妆小姐画得自然，看着还真丑，浑然天成的丑。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈这一番点评把纤尘逗乐了，“呵呵……丑的自然就好，我们快些收拾完就出去吧，被让阿峰他们等太久。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;待纤尘和苏妈妈出客栈时，阿峰和韩双双已经在客栈门外的马车边等她们了，二人看到今天的纤尘都忍不住一惊。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰直接咽了咽唾沫，怀疑来人还是他在闲城看到的那个仙子吗？若不是纤尘向他打招呼“阿峰早，让你们就等了。”那声音还很熟悉，再又看到她身边的苏妈妈，阿峰定会认为自己不是眼花就是看错了人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双惊掉一地下巴，结巴地问道“小，小，小姐，你，你怎么啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰惊得也说不出话来，就等着纤尘如何回答韩双双，那知那纤尘拍了拍韩双双的肩头，轻飘飘地回了一句，“没什么，到时候你们就知道了。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348352, 1334318214323216384, '&nbsp;&nbsp;&nbsp;&nbsp;纤尘姑娘在搞什么鬼，她好端端一张倾国倾城的脸硬生生给画得奇丑无比不说，还一脸病态让人见了就想躲得远远的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她这是要干什么？是想让所有人都离她远点吗？阿峰是丈二和尚摸不着头脑，不明白纤尘为何要这样做。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“呵呵……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰突然觉得，纤尘丑得像一只泛了黄的老苦瓜，忍不住笑了笑，想来纤尘姑娘这样做定是有她的原因，不过他得将纤尘这举世无双的丑模样好好叙述一番，告诉主子，可惜主子没看到她这个模样，若主子见到了定也会觉得纤尘姑娘这模样又丑又好笑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这里离纪国的京都城不远，不多会，阿峰就驾着马车来到京都城门外百里开外的地方，按照纤尘的要求，她们要在这里下马车。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“纤尘姑娘，王城就要到了。”阿峰拉停了马。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这里是前往纪国京都城门的一条小路，非官道，来往的人少，纤尘带着苏妈妈和韩双双下了马车。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一番短暂的告别后，阿峰驾马离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐，我们不坐马车进城吗？”韩双双着远去的马车不解地问道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘看了韩双双一眼，不紧不慢答非所问道：“双双姑娘，我虽是正二品大行台尚书令冉大人的嫡长女，但是我也有多年未回过冉府，现在冉府的嫡母也不是我的亲生母亲，你可有准备好陪我回去面对嫡母的勇气？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;正二品大行台尚书令大人，天啦，这是多大的官呀？韩双双觉得自己马上就要掉进金窝窝，哪里还管得着什么嫡母不嫡母的？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;再说了，如果纤尘的嫡母没死，她会弄个丫头回府，还准备将这个丫头送上自己父亲的床吗？她这样做的目的不就是想气死那个上了位的嫡母。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;府里有一个嫡小姐愿意帮自己上位，韩双双觉得自己是傻子才会拒绝这么好的事，她在脑子里迅速将所有信息过滤了一遍，平衡着利与弊。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘停了片刻，见韩双双没有开口，心想许是她在犹豫又继续道：“如果你没准备好，或者是怕了，既然我已经将你带到京都，也不会不管你，我会在京都给你谋个求生的事做，我不会为难你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;扑通一下，韩双双就跪在了纤尘面前，“小姐，双双这一个月来一路跟着小姐，知道小姐是个心善又有本事不苛待下人的好主子，双双发誓一辈子效忠小姐，我既然已经卖身给你，自然就是小姐的人，小姐去哪儿我就去哪儿。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双说得丁丁然，纤尘浅浅一笑，她不太相信韩双双的誓言。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;誓言这东西很是奇怪，对有的人来说，它无比珍贵，轻易不会发誓，一旦许下了誓言便会用一生去遵守；对另一些人来说，誓言就跟放屁一样，甚至还不如放屁，放屁还会臭上一阵，誓言说过就过什么也不会留下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘对韩双双没报多大的要求，只要她不吃里扒外，不给自己使绊子，她就不会为难韩双双。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“双双，你起来吧。”纤尘扶起韩双双。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;接着纤尘又对苏妈妈和韩双双一起道：“我们马上就要在进城了，我先交代你们一些事……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘将自己办丑装的目的简单同苏妈妈和韩双双说了一遍，接着就叮嘱道：“总之，进城后我做什么你们都不要觉得太诧异，你们只需晓得我有分寸，我在自保，也是在保护你们，大家见机行事。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈和韩双双齐齐点头，表示明白，三人这才向纪国京都的城门口走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪国是大周十国国力最强的国家，这些年风调雨顺，边界也无战事，太平盛世百姓们安居乐业，国内也无叛乱流匪，守城的士兵对进城的人盘查便也就没那么仔细，甚至有的人他们连问都没问一句就放进了城。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;你不问我，我问你总是可以的吧？纤尘可不想这么默默无闻地进城。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“大哥，我给你打听一个事儿呗，你知道正二品大行台尚书令冉大人府邸怎么走吗？”纤尘拽着一个看起来像个小头头的守城士兵的衣袖问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那守城士兵看了纤尘一眼，便一脸嫌弃地后退了几步，手不自觉地掩住了口鼻，捏着声音问：“你是什么人，找大行台尚书令冉大人什么事？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘一拍大腿还跺了剁脚，活脱脱一个乡下傻妹子形象，大声道：“哎呀，你问我是什么人？我是她女儿呀，我找他当然是回家认爹啦！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那士兵一愣，旋即又后退两步，深怕纤尘衣服上的灰尘落在了自己身上，给自己带来了霉运一般，皱着眉疑惑地问：“你真是正二品大行台尚书令冉大人的女儿？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘一点也不介意那士兵对自己一脸的嫌弃，一本正经道：“真的，那是真真的。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那守城的士兵懵了，感觉像青天白日天上突然出现星星。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉大人家的嫡小姐冉花楹时常跟着九皇子出城游玩，她们是见过冉府小姐的，不说惊为天人，那也是一等一的美女，眼前这女子和美就不沾边就算了，那简直叫丑，丑得人神共愤不说还像是得了什么怪病一样，一脸的腊黄。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那士兵又将纤尘上上下下、左左右右、仔仔细细打量了一番，还是不确定地道：“你真是正二品大行台尚书令那个冉大人的女儿？”他还特别强调了“正二品大行台尚书令”这几个字。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我四岁便离开了家，这是我第一次回府，不记得回府的路那也是再自然不过的事，不知道兵大哥为何对我有所怀疑？”纤尘也开始质疑那位守城的士兵。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;与其说她是在质疑，不如说她是故意挑衅，纤尘接下来的动作让这位守城的士兵是大跌眼镜。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;噗…噗…噗噗……一连串擤鼻子的声音响起。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;只见纤尘按住自己一个鼻孔，用力擤出了一把鼻涕，那擤出来的鼻涕不偏不倚正好落在那守城的士兵脚边，差点就要擤在他的脚上，那士兵连忙往后跳了两步。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;接着就看到纤尘用手将残留在鼻边的鼻涕抹过，顺手就在自己身上擦了擦，动作一气呵成再自然不过。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;天啦！这样一个埋汰的女子，是正二品大行台尚书令家的小姐？打死那个士兵他都不敢相信。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那守城的士兵拧成一张麻花脸，嫌弃中带着恶心掩着嘴看向纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘则吸了吸鼻子，一脸无所谓的模样，厚颜一笑，“嘿嘿，不好意思，最近染了风寒。”她揉了揉鼻子又对那士兵打着包票道：“我可是如假包换的冉府大小姐。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“不可能，你这个样子怎么也不像冉府的小姐，连冉府的丫鬟都不像，姑娘，你可知道冒充朝廷大员家眷是会给自己惹上牢狱之灾的？”那士兵铁定了心，认定纤尘就是个来攀附冉大人的同乡，他善意提醒，想劝退纤尘死了攀附权贵的心。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘向那士兵翻了个白银，“你别看我土，谁家还没得个乡下亲戚，我从小在乡下长大，你看看，我穿的这身衣服价值可不菲，你看得出来吗？这可是蜀丝金陵缎的好料子，你要不信我，你可以让冉羽涅那家伙来城门接我”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那守城的士兵闻声向纤尘衣服上瞅去，他虽然看不出来，是不是什么蜀丝金陵缎，不过料子的质量和光泽看起来确实像是上等的布料。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;暴殄天物、暴殄天物呀！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;简直是暴殄天物，这么好的布料套在这个人身上，还被擦了鼻涕，那士兵为布料而不值，在心里又狠狠将纤尘嫌弃了一把，不耐烦道：“小姐，我不知道冉大人的府邸如何走，你自己去找吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“骗人，你骗人，冉大人是大官，他家的府邸你们这些当兵的能不知道吗？你就是不相信我，你就是不想帮我们乡下人。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘不嫌事大，那是扯开了嗓子吼着说，一下子城里城外的人都围了过来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双也还机灵，跟着吼道：“乡亲们，你们来帮忙评评理，我们乡下人怎么啦，我们小姐是尚书大人的嫡女都没嫌弃过乡下人，这位兵老哥，怎么就嫌弃我们乡下人啦，连指个路，这个顺手之忙都不帮。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;呜呜呜……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘怕哭花自己脸上的丑妆，就没用哭可怜这个把戏，竟没想到韩双双替她哭了，还哭得是伤心欲绝，楚楚可怜，人见人怜，她的演技一流，让纤尘都佩服得五体投地。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;围观的百姓们纷纷开始同情起纤尘她们，都开始指责那士兵狗眼看人底，自己也不看看自己是个什么人？大家不过都是平头老百姓而已……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;舆论的吐沫可以把人给淹死，那士兵急了，大喊“来人！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“到”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“到”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“到”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“到”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“到”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;五个早已围在他们身前的士兵，立马出现在那个守城小头头面前，“伍长大人有什么吩咐？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“去，去把那几个冒充尚书大人家亲戚的刁民给我绑到京兆尹去。”显然那个伍长已经愤怒了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原来这个人还是个伍长，这算是纪国武将里最小的职位了吧，纤尘站在那里，等那些人过来绑自己，去趟京兆尹事情可以闹得更大，她何乐而不为呢？', NULL, NULL);
INSERT INTO `book_content` VALUES (3348353, 1334318215732502528, '&nbsp;&nbsp;&nbsp;&nbsp;见纤尘被绑，苏妈妈一急也戏精上了身，她一屁股坐到地上，双手不停地拍着大腿哭嚎，“啊呦，我们小姐可怜哟，从小被冉大人丢在乡下，现在回个家怎么就那么不难哟，先是遇到山匪，这会是守城的大兵头，连个举手之劳都不愿帮我们，他们看不起我们这些乡下人哟，真是天杀的哟，我家小姐可是真真正正尚书大人家的嫡小姐，苍天大老爷呀，小姐没有冒充，你可得给我们做主哟……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈坐在地上撒泼就差没打滚了，她哭得是老泪纵横真像是受了莫大的委屈，韩双双也是哭得我见犹怜，纤尘感叹这两人演得都比自己好。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈和韩双双都狠狠赚了一把来往相亲们的同情心，大都开始指责那位伍长，唯有纤城越看越想笑，估计明星们笑场就是这个原因吧？因为知道是假的，知道是在演戏，偏偏这假的比真的还真，这让那些知道真相的围观吃瓜群众哪里还忍得住不笑出来？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;既然忍不住笑，那就要坦坦荡荡笑出来，可别让人看出什么端倪来，“哈哈哈哈……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘忽的一下，就大笑了起来，笑得在场所有的人都感到莫名其妙，她旋即一本正经胡说道：“太好啦，我太高兴啦，如果我去了京兆尹，爹爹一定会来接我们的吧？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘装着很期盼，很开心的样子，随即就向那些守城的士兵靠近了一步，“兵大哥，你们现在就把我们押到京兆尹吧！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘眼里满是期待。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“且慢！”那几个当兵就要开始绑上纤尘她们，被一个清脆的女声喊停。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;只见一位十五六岁的女子，眉目清秀，身着白衣，女扮男妆骑在一匹毛顺光亮的小鬃马上俯视着这里，那几个士兵闻声望去，一看是灵曦郡主便齐齐行礼道“参见灵曦郡主。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的目的就是把事闹大，最好闹得京都世人皆知；所以她此刻最想去的地方就是京兆尹，因为只有去了京兆尹，冉府有个在乡下长大的嫡小姐才能在朝堂之上传开。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;事情进展得很顺利，没想到半路杀出个郡主来，这个郡主和冉府的关系是亲是疏纤尘不知道，唯有走一步看一步。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我问你，你真是冉伯伯家的女儿？”那郡主边问也边打量着纤尘，没有趾高气扬，声音里还带着一丝同情。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;至少这郡主不让人讨厌。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯，如假包换。”纤尘重复着刚刚对那伍长说过的话。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“那我带你去冉府如何？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“多谢郡主，不过这位兵大哥不相信我，为了证明我的清白，也为了给这些慷慨正义的百姓一个交代，我决定和他们去一趟京兆尹，如果郡主大人真想帮我，可不可以劳烦郡主也跟我们去一趟京兆尹，再去冉府唤我父亲前来？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那郡主不解，“我直接去冉府叫你父亲前来不就完了，为何还先要跟你去一趟京兆尹又再去冉府呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘故做怯怯地道：“我，我们是乡下人有点害怕！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此话一处，那伍长顿时无语，心想我还没怎么你，你怕，怕个大头鬼呀？那伍长就忍不住狠狠剜了一眼纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看到这一幕，那郡主便了然于心，这些个士兵都是粗人，这丫头怕他们在路上欺负她们也是人之常情，便应道：“那好，我就先陪你们去一趟京兆尹。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;郡主其实不知道，纤尘只是在故意想拖延时间，如果现在郡主去找冉羽涅，她们被押去了京兆尹，说不定自己还没来得及开口说话就被及时赶到的冉羽涅接回了府，那自己又怎能让冉府的老底大白于天下呢？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;京兆尹的陈大人是个留着山羊胡子的中年大叔，眼睛特小，老鼠屎大小的眼珠子，闪着鼠精鼠精的贼光。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人一听是灵曦郡主来了，连忙弓腰驼背谄媚地跑去迎接，“没想到灵曦郡主会大驾光临京兆尹，这真是让我们京兆尹蓬荜生辉呀！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;京兆尹这马屁拍得？难不成他还希望京兆尹蓬荜生辉后生意兴隆吗？京兆尹的生意兴隆了那纪国京都的治安岂不是堪忧了？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哈哈哈……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘在心里笑了笑，这个不太会拍马屁却又很谄媚的京兆尹大人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;京兆尹陈大人的马屁仿佛对那灵曦郡主真没什么用，那郡主一本正经，脸上没有一点悦色，直来直往道：“陈大人，我这次来是因为京都的京兆尹是个守正不阿的地方。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“是、是、是，那是！”陈大人点头哈腰，咧着嘴一脸的谄媚之色。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;灵曦郡主也没看他只自顾自的继续，“眼前这位姑娘说，她是大行台尚书令冉大人家的嫡小姐；而这些士兵又都怀疑她是冒充的，至于这位小姐是真的嫡小姐还是冒充的嫡小姐，唯有等到冉大人来了才知道，我这就去冉府通知冉大人来，这人就先交给你了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说罢，灵曦郡主便出了京兆尹骑马离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;目送灵曦郡主离，陈大人才将注意里放在纤尘他们身上，他看了看纤尘她们又看了看那些士兵，心想，灵曦郡主带来的人，他也不好审，也不好不审，人家把人都送到京兆尹了，过场总是要走的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人端坐、台上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;啪……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;惊堂木一敲，“堂下何人还不快快跪下回话。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘和那伍长一行人随即全都跪了下去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“伍长，请你先将此事情的来龙去脉说与本官听。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那伍长便开始滔滔不绝将今天遇到纤尘一行人发生的是叙述了一遍。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人听了有点懵，什么情况，正二品大行台尚书令冉大人还有个丢在乡下的嫡长女？这丫头回府，冉大人既没派人去老家接，也没派人在城门口接，她离家太久找不到回家的路？？？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人心里无数个问号，这，这究竟是个什么情况？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人俯眼下去，忍不住深叹一口气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哎……！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这些士兵对这丫头有所怀疑那也是人之常情，瞧瞧这丫头？就像只裹在泥巴里的蚯蚓，土里土气还奇丑无比，如果不是她有那个胆子来京兆尹走一趟，陈大人都会怀疑她是想攀附权贵。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤才不管陈大人在想什么，她就扑闪着她那双看起来朴实无华的大眼睛，提醒着陈大人快，快来找我问话。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人这才注意到纤尘身上那极好的蜀丝金陵缎料子做成的衣裳，啧啧嘴，这衣服料子确实也是达官贵族才买得起的好料子，只是这么好的衣服料子穿在那个丫头身上可真真是糟蹋了！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘身上穿的这身衣服皱皱巴巴的不说，上面还沾染着各种油迹污渍，这真让人为那身衣裳心疼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;人是灵曦郡主带来的人，灵曦郡主他惹不起，大行台尚书令冉大人他也惹不起，台上的陈大人只得和颜悦色问纤尘，“姑娘，你说你是正二品大行台尚书令冉大人，冉羽涅的嫡长女，你可有什么证据呀？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“有的，自然是有的！”纤尘指着跪在她身边的苏妈妈手舞足蹈对陈大人说：“大人，你看，这位是苏妈妈，是我娘当年的陪嫁丫鬟，我娘可是交州一户有钱人家的女儿，我爹爹当年读书和上京赶考的钱可都是我娘家里出的，我娘是冉府嫡母大夫人，苏妈妈是我娘的陪嫁丫鬟我爹他不会不认得的，过会我爹爹来了他们自然会相认。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的声音清脆明亮，声音不大不小，却让台上的陈大人听了个真切又让围观的百姓听了个清楚。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人听到嫡母大夫人这里，眼里一下就放出了探索八卦般的光，他脖子仿佛被人提起向着台下拼命伸去，身子也不由自主向前倾，如果他的身前不是有桌子挡着，估计他早就冲到纤尘面前去了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他扬了杨眉，小眼珠子滴流一转，带着七分八卦，三分质疑问道：“姑娘，你说什么？冉大人的嫡妻，可是太医院院判姚太医的嫡女姚氏，你这意思？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘要的就是这个效果，现在不仅是陈大人，相信外面围观的百姓他们的胃口也被自己吊起来了把？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这便是她将冉府的过去抖落出来的机会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗨！”纤尘不屑地发出一声叹息，接着她就像个说书先生一样，手舞足蹈“那姚氏可比我娘晚了好些年进的冉府，我娘也是我爹明媒正娶的正妻，在我们交州乡下那姚氏后、进门就只能算是小夫人，在京都这里的叫法讲究，叫什么平妻，不过平妻她也是后、进门，还不得叫我娘一声姐姐你说是不是京兆尹大人？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人一心听着八卦，可没想着这丫头还会来问他，姚氏不仅是院判大人的嫡女，她女儿还是九王爷未来的妻，他可不敢乱说话，尴尬地僵了僵，“呃……这个嘛，呃……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;呃了半响，陈大人也不敢呃出个屁来，纤尘转身又看向殿外围观的百姓，“各位叔伯，大娘婶子，你们说我说得对不对？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的一句各位叔伯，大娘婶子一叫，一下拉近了她与那些百姓的距离，他们可不全都知道姚氏是何许人也，连连回道“丫头，是这个理。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;其中一位老妇还满脸关爱地道：“孩子，你爹既然是大官，你娘家也不缺钱，为啥你会像现在这个模样？你这样看起来可不像个大户人家的女儿，倒像是个生了病的跑堂丫头。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348354, 1334318217166954496, '&nbsp;&nbsp;&nbsp;&nbsp;朝堂大员的八卦大料可是极品大新闻，吸引力非同一般，这会子，京兆尹外已经围了里三层，外三层，人群将京兆尹围了个水泄不通，大家都是慕名来看二品大员家里的丑小姐，来听她爆料的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘也不负众望，“哎呀！”她一拍大腿，活脱脱一个农妇的形象，脸上还露着几分憨实直爽的傻笑，“我就说嘛，有句老话说得好，群众的眼睛是雪亮的，大娘，你的眼睛就是雪亮的，我可不就是在肉铺子里跑堂的丫头吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;接着，纤尘蕴酿了一番故做神秘地对大家道：“我给你们说呀，我娘说当年我爹爹读书时，那成绩好得可不只是我们交州第一，在纪国他都是数一数二的，爹爹上京赶考，考取了功名就留在了京都，把我娘和我还有我祖母都留在了交州。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;祖母想儿子，就带着我娘和我一起赶到了京都看儿子，哪知道我们来了京都才知道爹爹又娶了一个妻子，听说我爹爹那个新妻子还是个大官的女儿，长得也老好看了，可是我还没来得及好好看看那个妻子的漂亮的模样，我娘来京都没两天就死了，我也被送回了交州舅舅家。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘说到这里，情绪就低落了下来，顺带着围观的群众也心里一沉鼻子一酸，可怜纤尘是个没妈的孩子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哎……！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘垂头丧气地叹了口气，“原本我舅舅在交州开着几家肉铺子，他家的日子挺好过，没想到交州突然来了东阴人。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一说到东阴人，围观百姓身上的鸡皮疙瘩就起来了，那可是传说中的杀手组织，东阴人烧杀抢掠无恶不作，他们臭名昭彰纪国上下无人不知，前不久朝堂上四品官员文侍郎一家被灭门就是东阴人干的，他们还大言不惭留下血书为证，眼前这个丫头竟然是在东阴人横行的地方长大的，可真不容易呀！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;众围观百姓无一不为纤尘捏一把汗，庆幸她能在那么恶劣的环境里长大。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘将大家的情绪调动起来，又继续道：“至东阴人盘踞在交州后，那里的百姓常年被东阴人骚扰，生意越来越不好做，他们的日子也越来越苦，家里的负担也越来越重，这些年来我一直在舅舅家白吃、白喝，于心不忍便去了肉铺子里当跑堂伙计。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说到这里纤尘便将目光投向那位大娘，笑呵呵地道：“呵呵……大娘你真厉害，一眼就看出来我是个跑堂的！”她又向那大娘竖起了个大拇指。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘话里句句透着内涵，稍微有点脑子的人都能明白，纤尘是被她爹遗弃了的孩子，好心的百姓着急这丫头浑然不知自己已经被自己的亲生父亲遗弃。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那大娘看着纤尘憨实的模样，忍不住心里一酸，没娘的孩子太可怜了，“姑娘在老家没少受苦就吧？”那大娘问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘头摆得像拨浪鼓，“没受苦，没受苦。”她连忙摆摆手继续道：“我舅舅和舅妈都是一顶一的好人，他们可是把我当亲闺女来养，你们看。”纤尘扬了扬自己身上的衣服，“我身上的衣服，听说是什么蜀丝金陵缎做的，在我们交州这布料老贵了，舅妈硬是要给我置办这身好衣服，说爹爹是大官，要穿好些给父亲撑场面呢。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;京兆尹陈大人，一头黑线，心想丫头，你这哪里是给你父亲撑场面，你这分明就是在告诉大家你爹为了仕途抛弃贤妻，还把你遗弃到娘舅家，不给钱也还不管你的死活……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;你这是将你父亲的黑历史都抖落出来了,还抖落得坦坦荡荡让人找不出你是在说你爹半点坏话。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;丫头我都不知道该说你是憨实呢还是说你……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人无语，围观的百姓却只觉得纤尘是个老实憨厚的娃，只是她太憨实了，连自己爹爹将自己遗弃了都不知道，难免人群里有仗义的人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;有人便仗义直言，“姑娘，你爹把你一个人丢到交州那种不太平的地方，一丢就是十几年，不闻不问，他这是遗弃你了你知道吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;还有人善意提醒，“姑娘，你娘当初怎么来京都没两天就死了？她是怎么死的？你们有没有报官查一查？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;更有甚者还啧啧嘴道，“他那个爹，可真狠心，这算个什么爹，不管人家不说，连钱也没寄回去过，多亏他舅舅家是好人，要不这丫头活不到今天吧？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一时间，百姓们越说越义愤填膺，纷纷都替纤尘抱不平，陈大人满头恶汗，这悠悠之口，可不能再让他们继续说下去，再让他们说下去，冉大人不给自己穿小鞋，九王爷那里自己都不好交代。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人又狠狠将惊堂木拍到桌上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;啪……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一声脆响，惊得众人都颤了颤身子，闭上了嘴，看着公堂之上的陈大人，陈大人这才撇着嘴一本正经道：“公堂之上，肃静。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他又瞥了围观的百姓们一眼，见他们没再议论，才继续问道：“姑娘，你说你一直在交州，怎么又来京都了呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哦，那是我突然收到父亲的家书，家书里说祖母病重想见见我，我已经过了及笄的年龄，再过段时间若在老家已经婚配，就不好再回京都了，这不我就赶在婚配之前回来看一下祖母。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘说着就去翻找她的行囊，她在行囊里翻找着家书，故意将行囊口子大大打开，故意让大家看到行囊里的寒酸，看到里面就只有一件旧衣服。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“大人你看，这可是我父亲的亲笔家书，上面还有他盖的章子。”纤尘高举着这封家书，在头顶晃一晃的，就好像在示意大家，你们看，我是有证据的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那封家书也确实也吸引了无数人的注意力。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人立即吩咐人将纤尘手上的家书接了过来，仔细看了看，摇头晃脑像个夫子，“嗯，是冉大人的印章，这信里的字，笔走龙色行云流水，果真是好字。”&nbsp;陈大人不失时机地拍了拍冉大人的马屁。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;可是冉羽涅现在又不在场，这马屁拍出来只能让围观的百姓觉得恶心，更加觉得冉羽涅是个道貌岸然的小人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;百姓们听到那家书确实是冉大人所写的，大家又不淡定了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一群人中不知道是谁说了句，“字好心眼子坏有什么用？这样的人，女人嫁给他不如还不如嫁给一个挑粪的农人幸福。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哈哈哈……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这酸溜溜不恰当的比喻引来了众人哄堂大笑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;人群中不知谁说了句，“别笑，大家别笑，你们看，那丫的头的行囊里，只有一件换洗的衣服，里面连一件像样的首饰都没有，这是什么朝堂大官的女儿，这日子过得可比普通百姓家的女儿都不如。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“啧啧……谁说不是呢，真是死了娘的孩子没人疼。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;百姓的情绪再次激动起来，陈大人又是满头恶汗，心想着这灵曦郡主怎么还没将冉大人找来，这烫手的山芋自己还是早些丢出去的好。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这也不能怪灵曦郡主迟迟未将冉大人带来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;灵曦郡主与冉府姚氏所出的嫡女冉花楹不对付，冉府守门的小厮见是灵曦郡主前来找冉大人，问也没问她什么事，就说“老爷还在宫里，你要找就去宫里找吧。”将人给打发走了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;灵曦郡主也是个实心眼，果真信了那小厮的话，转身就去了皇宫。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;到了宫里灵曦郡主才发现冉夫守门的小厮在诓她，冉大人散完朝堂就早早回了府，她去冉府的时候，冉大人已经到家了，守门的小厮只是不愿意替她通报而已。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顿时灵曦郡主就火冒三丈，本想着不再去管冉府的事，这事反正已经交给了京兆尹，自有京兆尹派人前来通知。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;转而她又想想，如果那个女孩真是冉大人的亲生女儿，这事要是传进了宫里，看那冉大人在朝堂之上还怎么耀武扬威，看那冉花楹还得意什么？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一个邪恶的念想顿上心头，她心里的火气也消了下去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;现在散朝不久，还有些散朝后打堆闲话的朝臣还没有出宫，灵曦郡主就在宫门口等，等到一个朝臣就拉着那个朝臣的手，满脸焦急地问：“你看到冉大人了吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不管人家回答她是说看到还是没看到，灵曦郡主都会对他们说上一句，“有个乡下的丫头说是冉大人丢在交州十年的女儿，她从交州来京都找不到冉府就去了京兆尹，麻烦你见到冉大人替我转告他一下，让他去京兆尹看看那个丫头是不是他女儿。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;后来，灵曦郡主干脆见到从宫里出来的人就拉着人家问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;直到灵曦郡主说得口水都干了，才解气地离开。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;经灵曦郡主这么一闹腾，不多会这个消息就在宫里和朝臣之间传了开，唯有冉府还浑然不知。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一个平日里和冉花楹关系交好的小姐妹，从她下朝的父亲嘴里听到冉府的事，便匆匆忙忙去了冉府。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这个小姐妹是正四品忠武将军的女儿，名叫夏伊人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉府的小厮见了夏伊人满脸堆笑，热情地迎了来，“夏小姐你来啦，小姐在书房和老爷说话呢，我这就去给你通传。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348355, 1334318218593017856, '&nbsp;&nbsp;&nbsp;&nbsp;“不用了，我有急事找冉伯伯，我自己去找他们。”说着夏伊人就进了府，向着冉羽涅的书房跑去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;夏伊人和冉花楹交好，冉府她没少来，她对冉府也很熟悉，不需要下人带路她也知道冉羽涅的书房在什么地方。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她火急火燎向冉羽涅的书房跑去，跑到冉羽涅书房时她已是上气不接下气，她看到冉羽涅和冉花楹正在书房下棋，这下她就急了，“冉伯伯，花楹，你们怎么还有空在这里下棋？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅和冉花楹都诧异地看向气喘吁吁的夏伊人，不知道发生了什么事让这个丫头火急火燎的，冉花楹的手上正夹着枚棋子，柳眉微蹙问：“夏伊人你这是怎么了，发生了什么事把你急成这样？”接着冉花楹就吩咐下人，“快去给夏小姐准备杯茶水来，让她缓缓再说。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“喝什么茶？你们快去京兆尹吧，听说冉伯伯有个嫡女在乡下，从交州老家赶来了，因找不到冉府的路，就去问了城门的守兵，不知道怎么会是她就和那些守兵发生了争执，现在人被送去京兆尹了……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;夏伊人将她从他父亲那里和在路上听到的，关于冉府嫡长女的事情一股脑的说给了冉羽涅和冉花楹听。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅恍然大悟，他一拍脑门，怎么就把这事给忘了，他已经收到交州的来信，说冉纤尘已经在回京的路上，他还想过这几天安排人去城门口接人，结果这几天忙着交州兵权的事，将接冉纤尘回府的事给忘了个干净。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“快，快，快去备马车，我们去京兆尹。”冉羽涅和冉花楹上了马车。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹是个有心眼的孩子，在上马车之前便将自己头上和身上那些贵重首饰全都拆了下去，这样看起来人也朴实了许多。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“让让、让让……冉大人来了！”冉府的家丁狗仗人势，像只斗牛的猎犬凶巴巴的边旺旺边排开围观的百姓，硬是给冉羽涅扒开了一条道来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;周围的群众见到从马车上下来的冉羽涅，身高七尺，一身华服玉树临风，岁月在这个男人的脸上雕琢出了成熟的魅力，明明是个极好看的中年男子，偏偏围观的百姓个个脑海里都浮现都的是“道貌岸然、沐猴而冠”的模样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;百姓门异样的眼神，像小刀一样戳着冉羽涅的脊梁骨，冉羽涅不由自主心里就一紧，脸上却强撑着一份淡然。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;与他一同来的冉花楹还是看出了他的紧张，“爹爹，没事的，有我在，我们进去吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅看了一眼身边的冉花楹，这个女儿从来没令他失望过，她聪慧过人，深得皇上、皇后还有云妃的喜爱，有她在自己身边，冉羽涅仿佛有了主心骨一般，紧绷的心弦跟着也轻松了下来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说来也怪，一个父亲竟然将自己的女儿当成了主心骨，不过那也没办法，谁让他们家的这个女儿非常的出色，既漂亮，还会来事儿，还是皇上最宠的儿子康王殿下未来的正妃。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹今天穿的是一件油青色绣花百合花，面料普通的罗裙，她特地将自己的头面首饰取下，这样一来，她这身朴素得几乎像个平民。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她端庄大方，款步向京兆尹里走去，眉疏目朗，唇角微扬，面对围观百姓们异样眼光，她也能展出公式化的微笑，大方有度，礼貌周全，将“大家闺秀”这四个字展现得淋漓尽致，倒是赢得了不少的好感。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;有的人甚至觉得，住在府中的嫡小姐穿衣打扮尚且如此朴实，那住在老家乡下的小姐看起来也就没那么寒酸了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;京兆尹陈大人知道冉羽涅来了忙起身点头哈腰相迎，“冉大人、冉小姐快快请坐。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;眼尖的衙兵已经给冉羽涅和冉花楹搬来了凳子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹瞟了一眼那凳子，心想这又不是什么体面的事，坐什么坐，还嫌我们冉家不够丢人呀，坐在那里等着别人看笑话吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹即便心里厌烦极了这个陈大人；但是，她依旧端庄有礼，脸上略带微笑向陈大人福了福身，“陈大人，听说我姐姐从老家探亲回来，找不到回家的路就找到了你这里，真是给陈大人添麻烦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹开口一句“探亲回来”，就是在告诉大家，我姐姐不过是回乡下探亲回来而已，可不像有的人说的那样是她是被遗弃了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人不是傻子，他自然听得出来冉花楹的弦外之音，忙回应道：“是，是，是冉家小姐探亲回来就好，那你们就将她们领回家吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;接着陈大人又对纤尘她们说：“既然冉大人都来了，你们就跟着冉大人回府吧。”陈大人可是想尽快将纤尘她们打发走。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈抬头看向冉羽涅，心情复杂，如果可以，她这一辈子都不想再见到这个负了她家小姐的男子，如今，为了小姐，她忍着心里的恶心，饱含泪水地喊了一声，“老爷。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;紧跟着，韩双双也抬起头看向冉羽涅，她来冉府的心思本就不纯，她就是想爬上冉大人的床，想当上妾，从此过上不愁吃穿的好日子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她想看看这个男人究竟是老是丑？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这一眼，直接将韩双双看了个怦然心动。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅随然已步入中年是三个孩子的爹；但是，他高挑秀雅的身材，就像一具行走的衣架，身穿冰蓝绣团锦水纹缎的华服，更显逼人的权贵之气，剑眉星目鼻梁高挑，下巴微低，两片深红的唇含蓄内敛，举手投足间不失成熟男人的成熟魅力。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;男人真是越老越有味道，老腊肉还真比小鲜肉香，冉羽涅从骨子里散发出来成功男人的气息，成功迷到韩双双这个小迷妹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹见韩双双痴傻地看着父亲，以为这是姐姐多年未见到父亲的缘故，心想，兴许是姐姐多年未见到自己爹爹，不知道该如何称呼爹爹，想叫一声爹爹却又怕生，叫不出来，于是才会用如此痴傻的目光盯着父亲看吧？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹面露微笑，端着闺秀的良善向前扶起韩双双，“姐姐怎的如此看着父亲，从老家探亲回来怎的连爹爹都不会叫啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;陈大人看到冉花楹扶起的姐姐是韩双双，一下懵了，刚刚不是那个丑女说她才是冉家的嫡长女吗？怎么竟然是这个丫头？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不仅是陈大人懵了，就连外面围观的百姓都懵了，一瞬间这里的时间仿佛静止，大家都张着“o”形的圆嘴，却谁都没有发出声来，这里瞬间安静得可以听见针落地的声音。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小，小姐，我，我不是大小姐，她，她才是。”被冉花楹扶起的韩双双羞赧地指了指地上跪坐着的纤尘道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹一顿，哗的一下，人群刹那间就笑开了去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哈哈哈哈……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;笑声如潮，此起彼伏，带着嘲讽，打破了这里短暂的安静，时间也开始正常流转。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹顿时花容失色。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花就是太自信，殊不知自信和自负往往只有一步之距，她先入为主的认为抬眼看向父亲的韩双双就是她姐姐，跟本就没多看纤尘一眼，因为纤尘跪在那里，老老实实埋着头的样子就和她家的下人一模一样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她第一次被这么多人嘲笑，脸上是红了白，白了青，气得恨不得将今天潮笑她的人舌头都割了去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;片刻之后，纤尘才起身，大喊着“静一静，静一静……大家安静，别笑，别笑啦！听我说！”众人见纤尘起身有话说又才闭上了嘴，“你们不能笑我妹妹，我回家探亲的时候我才四岁，那个时候我妹妹还是个襁褓里的婴儿，我妹妹将我认错那也是很正常的事，你们不能笑她！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“傻丫头，你这亲探的时间可不短呀，这一探亲就探了十来年。”人群中不知道是谁说了一句。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哈哈哈……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;围观的百姓又哄然大笑了起来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘这话，表面是在帮冉花楹开罪，实际上就是在讽刺冉花楹刚刚说的探亲有多可笑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;人群中有不怕事的人忍不住了，“丫头，你傻呀？还帮他们说话，哪有探亲一探就是十几年的，你那叫探亲吗，你那分明叫遗弃！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说自己遗弃子女，冉羽涅不高兴了，他正想发火，质问是谁在乱嚼舌根子却被冉花楹拉住了袖子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹向冉羽涅摇了摇头，示意冉羽涅不要将事情闹大，那些百姓可都是光脚的，光脚的可不怕穿鞋的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅强压着怒火瞪了一眼纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘全当没看到冉羽涅瞪来的怒目，她心里合计着，可不要让这些人真当自己是个傻子，她要做的是让这些人觉得自己只是有点憨实，有点却心眼，绝对不是一个傻子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;要冉府真把自己当个傻子来治，反倒是对自己不利。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;想到办法的纤尘立马又开口道：“我不傻，我可聪明了，我跑堂的时候，掌柜的都夸我能干，从来没收错过一个铜板。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;人群中刚刚关心纤尘的那个大娘再次开了口，“那姑娘是不傻，那孩子就是实诚，太实诚了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;大娘这么一说，众人仿佛也觉得是这个理，这丫头就是太实诚，不知道人心邪恶这个东西，于是刚刚那说纤尘傻的人又改口道：“丫头，你不傻，就有点缺心眼。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348356, 1334318220014886912, '&nbsp;&nbsp;&nbsp;&nbsp;哈哈哈……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此话一出，人群又笑开了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这样的笑声让冉羽涅和冉花楹都不尴不尬，别看冉羽涅在朝堂上混了十来年，人已经被磨得圆滑善于伪装，不易喜形于色，然，他的脸还是黑了下来，冉花楹更是尴尬得羞红了脸直到耳根，她手里的绢帕被她绕来搅去已经揉成了麻花。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这么丢脸的事全拜冉纤尘所赐，冉羽涅怒目瞪了纤尘一眼，这一瞪，冉羽涅才发现纤尘的丑，他就在心里直喊娘，天啦，我的个娘呀，这带着三分傻气，丑得发苦的丫头真的是他冉羽涅的女儿吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;我的个娘呀，世上还有丑得这么倒人胃口的女子？冉羽涅难掩心里的嫌弃，狐疑地问苏妈妈，“苏妈妈，她真是我的女儿冉纤尘？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“回老爷，她就是小姐，夫人死后小姐就这样了。”苏妈妈按照纤尘事先给他说好的台词回答着冉羽涅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一提到纤尘死去的母亲，再看看如今的冉纤尘，冉羽涅心里微涩。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曾经他的尘儿也是冰雪聪明，四岁便能提笔写字，活波可爱，那时她是他的开心果；如今，他的女儿怎么会变成这个样子了？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;丑，实在是太丑了，这人受了打击变傻冉羽涅是能理解的，可是这受了打击变丑冉羽涅就不相信了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘早料到冉羽涅没那么好骗，关于她的皮肤，她也早叮嘱好苏妈妈如何去搪塞冉羽涅和冉府的人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“老爷，我们小姐回到交州就生了病，晒不得太阳，你也知道交州日头毒，小姐的脸被日头灼伤，也就这样了。”苏妈妈哽咽着说。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅将信将疑，将纤尘好好打量了一番，不看这脸上的肤色，单只看这脸形却也是个美丽的鹅蛋脸，与沈氏的脸型确有几分相像。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;知道冉羽涅还有所怀疑，纤尘不失时机地开了口，&nbsp;“呵呵……原来父亲也认不出我啦？还好我手上有胎记，娘亲当年对我说过我手上的胎记是独一无二的，丢了也不怕找不回来，想来父亲定认得纤尘手上的胎记吧？要不尘儿挽起袖子给父亲看看。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的声音响亮，让里里外外的人都听了个清清楚楚，大家都气愤冉羽涅这个父亲竟然连自己亲生女儿都认不出来，有些人也毫不客气地对他指指点点。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;面对众人的指指点点和异样的目光，冉羽涅顿感那些人的目光如釜底薪，自己已然成了那釜里的蚂蚱，再多呆片刻，自己就会被他们如炬的目光给烧死。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天丢脸可是都丢到外婆家去了，冉羽涅哪里还顾得上看纤尘手上什么胎记？不耐烦道：“不用了，先回府。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;幸好冉羽涅说不用了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘挽袖子那一刻才反应过来，自己只在脸上涂了丑装，她手臂的肌肤白皙，要是自己挽起袖子，露出手臂上的肤色，这肤色与脸上的肤色反差极大，旁人不会怀疑，她那个精明的二妹妹定是会有所怀疑的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅匆匆告辞京兆尹，便带人回府。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉府的家丁，再次扮演着斗牛猎犬的角色，凶巴巴旺旺着排开众人，硬生生给冉羽涅他们开出一条上马车的道来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;马车走，人群走，人群跟着马车走，看热闹的人不嫌事大，只嫌事不够看，看不够。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉府的家丁也驱赶过那些看热闹的人，无奈，那些人就像粘在身上的牛皮糖，赶都赶不走，几次驱赶无意，冉羽涅便发了话，“随他们吧，我们尽快回府便是。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;人群跟着冉府的马车也离开了京兆尹，开始还热闹非凡的京兆尹瞬间就恢复了以往的安静。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;京兆尹陈大人背着手，老鼠屎大小的眼珠子又闪着鼠精鼠精贼光，一捋他的山羊小胡须，自言自语道：“送走这些瘟神，我这里终于清静了。”&nbsp;他顿了顿又回望了一下身后的府门，突然又呵呵一笑，继续自言自语道：“冉府以后可真是有好戏看了！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉家主母姚氏，在外人面前向来是个成集贤良淑德为一身的好媳妇，好主母，为了不落下轻待非己出女儿的话柄，也为了将她的贤良淑德展现给外人看，她早早便带着下人来到冉府门口迎接纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏今天刻意穿了一件月青色水文缎绣团锦的正装，这身衣服素净不张扬，端庄且正式，既彰显了她当家主母的地位又不显浮华。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一身正装相迎，足已向世人展示她有多看中这个女儿。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅有了刚刚和冉花楹将纤尘认错的教训，这次他主动牵着纤尘的手来到姚氏面前，对姚氏介绍，“玉儿，她就是尘儿。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅话音刚落，姚氏脸上就堆上了她那标志性白莲圣母般的微笑，“尘儿，都张这么大啦，出落得……”姚氏本想说，出落得越发的精致了，定眼一看纤尘的那张丑脸，那“越发的精致”这几个字就硬是没憋出来，顿了顿又重复道“都出落成大姑娘啦！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“尘儿，这是你母亲。”冉羽涅也觉得纤尘丑的惨不忍睹，没多看她一眼只将脸撇向了别处。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“二娘好！”纤尘脸上露出憨实的笑，她清澈的眸子里看不出一丝的杂质，这声二娘她喊得浑然天成，理所应当，仿佛她原本就是这样喊的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不错，小时候她进冉府，父亲曾经就对她说过，姚氏也是他明媒正娶的妻子，以后见到姚氏也得叫娘亲。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那时的纤尘还是个粉嘟嘟软萌可爱的小女娃，忽闪小蝴蝶翅膀的睫毛，睁着萌死人不偿命的大眼睛，软软糯糯萌萌地问冉羽墨涅，“爹爹，那以后尘儿叫她二娘可好？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;当时，冉羽涅被这个奶乖女儿萌得心都要化了，他也没觉得有什么不妥，便同意了纤尘叫姚氏二娘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;只是，儿时那段时间姚氏与冉羽涅在闹脾气，她容不下纤尘的母亲，坚持自己为嫡，纤尘的母亲为妾，冉羽涅又做不通纤尘母亲的思想工作，家里的气氛一度很紧张，纤尘的母亲为了保护她，也不让小纤尘出自己的院门；所以儿时她也没在姚氏面前叫她过二娘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;二娘这两个字，如同一记耳光扇在姚氏的脸上，提醒着她只是个平妻二夫人罢了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏顿时僵在原地，她脸上的颜色极不好看，红一阵白一阵。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姜还是老的辣，不一会姚氏的脸上又恢复了她那白莲圣母般的微笑，大度地对纤尘说：“尘儿，如今冉府只有我一个嫡母，你母亲也已过世多年，你就叫我母亲可好？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏脸上挂着笑，心里却将纤尘的母亲沈氏狠狠的咒骂了一番，“那个该死的女人，就因为你的出现，让我莫名其妙当了二娘，你以为你死了就能给你女儿留下嫡长女的名分？你以为我会拿你女儿没辙？哼，我告诉你，她照样逃不出我的手掌心，看我怎么折磨你的女儿，我不会轻易让她死，她死了岂不是便宜了你，我要你在阴曹地府也看看我是怎么折磨你女儿的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“好的，母亲。”礼尚往来，姚氏向纤尘展出她那白莲圣母般的微笑，纤尘就回她一个人畜无害二哈般的憨笑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏没想到纤尘会答应得这么干脆，又顿了顿，吃惊地看了一眼纤尘，她脸上挂着那人畜无害二哈般的憨笑，眸子里透着孩童般的纯真，看不出一丁点的城府。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏看不出纤尘的城府，那是她道行不深，也是纤尘演得太逼真。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘也不在称呼姚氏是“二娘”还是“母亲”这上面计较，她的存在，就已经向世人证明了姚氏只是平妻中的二夫人，她何须去执着一个称呼，她顺着姚氏，也会降低姚氏对自己的猜忌和防备。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“这是你的庄姨娘。”冉羽涅指着一个毫无存在感的女子向纤尘介绍。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那女子诺诺地看了一眼纤尘，欠了欠身低声道：“大小姐好。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“庄姨娘好！”纤尘脸上依旧挂着她那人畜无害二哈般的憨笑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏看到纤尘这个模样，就忍不住心喜，没想到沈氏生的这个女儿会是这个样子，虽说算不得是个傻子，却也是个脑子不灵光的丫头，这样的傻丫头最好对付。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;府门外有百姓围观，也不是说话的地方，姚氏微笑着拉着纤尘的手，“乖女儿，走，母亲带你回府，母亲知道你会来，就已经安排人给你收拾出了一个院子，母亲这就带你去院子里看看。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏将纤尘拉回了府，众人也跟了进去，冉府的大门关上后，围观看热闹的百姓们也悻悻离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;跟在后面的冉花楹，若不是了解自己的娘亲，都会产生一种错觉，觉得那个丑女才是娘亲的亲生女儿。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏牵着纤尘就要往她那偏远的院子走去，突然纤尘停了下来，“母亲，父亲信上说祖母病重，我想先去看看祖母。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏的脸上不自然地笑了笑，“呵呵……你祖母呀，她现在身体好多了。”说完抬眼看了看冉羽涅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅心想，虽然让纤尘回府是他和姚氏背着老太太做的事，不过事后，他们夫妻两也给老太太说了此事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太知道家书已经寄走，他们两口子这样做的目的又是为了给纤尘找婆家，老太太便也没再阻拦，默许了他们撒谎拿着自己病重的谎言将纤尘叫回了府。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;母亲向来是为自己着想的，想必母亲也不会在自己女儿面前揭穿自己的谎言，于是冉羽涅便点了点头，“是该先去见见你的祖母，她老人家好可想你了。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348357, 1334318221457727488, '&nbsp;&nbsp;&nbsp;&nbsp;一行人浩浩荡荡去了老太太的院子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太的院子不大，简单干净整洁，纤尘他们到来的时侯，老太太正趟在摇椅上寐觉。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太年轻的时侯家里贫寒，时常在海边拾螺，卖了钱贴补家用，老了就落得一身风湿病痛，如今来了京都，享了儿子的福，太阳好日头又不毒的时侯，老太太就喜欢在院子里支把摇椅躺着晒太阳，这太阳一晒，他那把老骨头就没那么疼了，这太阳晒着晒着老太太就会寐上一觉。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;两个侍候老太太的婆子见到冉羽涅和姚氏他们进了院子，赶紧上前行礼，“见过老爷，见过夫人。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅摆摆手来到老太太身边，蹲下身子凑在老太太耳边轻声说：“娘，醒了吗？尘儿回来了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太睡觉轻，刚刚那两个婆子向冉羽涅和姚氏行礼时，她就已经醒了只是还不想睁开眼看他们罢了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太心想，这两人来自己院里也没什么旁的事，无非就是装模作样问个安而已。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太依旧寐着觉没那个精气神去搭理冉羽涅他们；但是，她一听到冉羽涅说“尘儿回来了”那精气神也跟着就来了，老太太猛地睁开眼，四下看了看，“尘儿回来了，她在哪里呢？羽涅快扶为娘起来！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;没等冉羽涅扶起老太太，纤尘立马上前蹲下身子，握着老太太的手，“祖母，尘儿回来了。”为了不让姚氏他们看出半点破绽，纤尘的脸上依旧挂着那憨憨的二哈模样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太看到丑模丑样的纤尘又见她肤色如病态，忙问道：“尘儿，你怎么了，可是生了什么病？为何你脸色如此难看？”也不等纤尘回答，老太太就着急地对冉羽涅说：“羽涅，你现在是正二品大员了，快去宫里请个太医给尘儿看看吧，她脸色这个样子我不放心！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“不用了老夫人，小姐没问题，小姐，小姐……”苏妈妈故意顿了顿，鼻子一酸，吸了吸鼻子，还没开口，老太太急了“她苏妈妈，尘儿怎么啦，你哭什么呀，你想急死我吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;自己这张病人脸，父亲见过，姚氏见过，唯有祖母见到后才关心自己是不是生了病，纤尘心里一半心寒一半温暖，她默不做声，将头埋在老太太怀里，握着老太太的手，感受着来自祖母掌心传来的热度，眼里有泪想要流出来，还是被她硬生生的给收了回去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈接着道：“老夫人，夫人死后，小姐太伤心，在回交州的途中染了风寒，一连好几天都在发热，我们身上的钱又不够，只能先赶回交州再给小姐治病，交州乱，大夫一般不上门诊病，我每天都带着小姐顶着日头去看病，一连就是小半月。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;至那以后，小姐就不抗晒，日头大，一晒小姐的脸就容易被晒伤，交州的日头有多毒老夫人您是知道的，不过这不是什么大问题，京都的日头小养人说不定过些日子小姐的脸就给养漂亮了呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈故意说着模棱两可的话，老太太不信，“我在交州生活了几十年，交州的日头我还不知道，最多就是给晒黑哪有晒黄了的？”听转而又看向纤尘，“尘儿呀，你告诉祖母你身体可有什么不适？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“没有，没有，主母，尘儿身体可好了，尘儿一个人就可以杀一头牛呢，唰唰两下就可以将牛肉从牛骨上剔下来，人家都赞尘儿身体比牛壮呢！”纤尘手舞足蹈比划了两下拿刀杀牛的模样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看到纤尘这个憨憨的模样，老太太心里就酸得紧。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这话怎么越听越不是滋味？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一个女孩子家家的去杀牛？老太太听着纤尘又是杀牛，又是剔骨的，总感觉这就不是女孩子该做的是，忙问：“苏妈妈，尘儿堂堂大行台尚书令家的小姐，怎么就去当了杀牛匠啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅也用质疑的眼神看向苏妈妈。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈吸了吸鼻子，眼泪像断线的珠子有一颗没一颗地滚落&nbsp;，“老夫人，东阴人在交州为非作歹，生意不好做，旁人不知道，你是清楚的，小姐的娘家舅舅开的是肉铺子，人手不够，小姐又不能吃闲饭，你说她怎么成了杀牛匠的？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;扑通一下，苏妈妈就跪在了老太太面前，声泪俱下道：“老夫人，我们小姐苦呀！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太心酸的眼泪终于还是忍不住落了下来，她抚摸着趴在她怀里的纤尘哽咽道：“好孩子，祖母知道你苦，你这次回府，祖母定会护你周全。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈这一哭太有感染力，弄得冉羽涅心里酸涩不说还心生愧意，也跟着红了眼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈擦了擦泪继续道：“老太太，我们家小姐性子直，一根肠子通到底，不会弯弯绕，舅老爷担心小姐太过憨直，我年龄又大了，他怕我们被人骗了去，就请了双双姑娘过来照顾我们。”说着，苏妈妈就将韩双双拉了过来，“老太太，你看就是这位姑娘，一路上小姐和我都多亏了有双双姑娘的照顾。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双敛着眼里的狐媚，恭恭敬敬向老太太行了个礼，用一口纯正的交州话喊了身，“阿婆，您好！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“好，好，好……”老太太不知该如何感谢韩双双，一连说了好几个好。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双纯正的交州话勾起了冉羽涅对故乡的怀念，他怀念故乡的海，也怀念和纤尘母亲在一起的那段日子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;没有对比就没有伤害，冉羽泥想到曾经纤尘的母亲对自己是百依百顺，想到她温柔贤淑的模样与现在无比强势的姚氏一比，心里就悔不当初。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;只是悔又有何用？纤尘的母亲已死，此情只能成追忆,只怪当初渣上头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“涅儿，双双姑娘帮你一路照顾女儿回府，你是不是也该感谢一下双双姑娘？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太一句话打断了冉羽涅的神游太虚，他向韩双双拱手施了一礼，“多谢双双姑娘照顾小女！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“老爷客气了！”韩双双回礼，抬眼妩媚地看了一眼冉羽涅，刹那间冉羽涅有种被电的感觉。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;转瞬间韩双双就收回了她的电眼，其他人未有人察觉，唯有冉羽涅心里已经泛起了涟漪。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏见老太太、冉羽涅、纤尘她们围做一团，有说不尽道不完的情亲，自己女儿常年伴在这老东西的膝下，也没见这老东西这么喜欢过自己的女儿，姚氏为冉花楹感到不值。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这个丑女一回来，那老东西就完全将自己和女儿都凉在了一边，仿佛自己和女儿就是这个家的外人，姚氏心里憋着气，脸上却依旧挂着那份白莲圣母般的微笑，“母亲，尘儿她们才回府，舟车劳顿还是让尘儿她们回院好好休息吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏话一出，冉羽涅也跟着附和“对，对，对，母亲还是让尘儿她们先回院洗漱休息，晚上我们给尘儿接风洗尘。”接着冉羽涅就对纤尘道：“尘儿，你随你母亲去院子里休息，为父还有些公事要做就不陪你了。”说罢，冉羽涅就直直去了书房。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏带着一行人来到纤尘的院子，这院子很偏僻离主屋很远，本是一处废弃的院子，院里屋子陈旧，姚氏安排人将这里简单打扫一番，算是勉强可以住下人来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏本也没想让纤尘长期在冉府住下去，这次叫她回来不过是想将她早早嫁出去，不要碍了她女儿的前途，毕竟在纪国嫡长女都未家，嫡次女就出嫁是会落人口实的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“尘儿，这个院子你喜欢吗？”姚氏问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“喜欢当然喜欢，这可比我在交州的房子大多啦，”&nbsp;纤尘脸上洋溢着发自内心的高兴，眼里都透着欢喜的光，看起来真像是非常满足的样子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;真是个没见过市面的孩子，姚氏对纤尘的表现很是满意。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;跟着一起来这个院子的人，无论主子还是下人都觉得纤尘果然是乡下来的土包子，没见过市面，这么一个破院子还喜欢得像个宝一样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏又继续道：“尘儿，你的院子我已命人给你打扫出来了。”她指着两个衣着整洁鲜亮，模样机灵的丫头对纤尘说：“尘儿，你看，那两个丫头别看年轻可都是冉府的老人了，做起事来麻利，母亲就将这两个丫头留在你院里给你当使唤丫头？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘点点头欣然接受，爽快得连半句推脱的话都没有，“好的，谢谢母亲。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘不是不知道姚氏安排这两个丫鬟在她院子里是什么意思，说简单点就是在她身边安插眼线监视她，说深点，姚氏将她的人安插在自己身边，也方便她日后对自己干坏事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她也知道，这两人姚氏要硬塞给她理由千千万，她无法拒绝，也没有必要拒绝，干脆爽快接受，还可以降低姚氏对自己的猜忌，何乐不为？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏没想到纤尘这么好说话，就这样接受了自己安排，一点拒绝的话都没有，心里又是一喜，心想果真是个脑子不灵光的丫头，看不出来门道，便又展出她那标志性白莲圣母般的微笑，向那两个丫鬟招招手，“月圆，月缺，你们两快过来见过大小姐。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那两个丫头闻声过来，齐齐向纤尘欠身行礼又齐声说道：“见过大小姐。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏很是满意，满脸带笑道：“月圆，月缺，以后你们就留在大小姐的院子里，可得把大小姐侍候好了。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348358, 1334318222854430720, '&nbsp;&nbsp;&nbsp;&nbsp;“是！”月圆和月缺二人齐齐欠身行礼应了姚氏，转而又向纤尘欠了欠身，“大小姐，婢子们定会全心全意侍候好大小姐。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘乐得合不拢嘴，“母亲，你真好，给我两个这么漂亮的丫鬟使用，她们穿得这么漂亮，你说我以后给她们安排个什么活干好呢？好像安排什么活都不合适她们，我都怕把她们身上那身衣服给弄脏了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘这句大实话一出，听得那些一路跟来的丫头婆子都忍不住想笑，个个又怕被主母责怪只得低着头窃窃地笑了出来，以防被憋成内伤。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一向极懂察言观色，深谙明哲保身，低调到透明的庄姨娘，都被纤尘这缺根筋的模样，逗得用绢帕掩着面抿着嘴笑了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯…嗯…”姚氏清了清嗓子，瞥了一眼身后的人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那些下人受到姚氏的警告，也不敢再出半点声来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的话什么意思？这两丫头衣服得太好，她不敢安排活计给她们做，言下之意是想以此为借口拒了自己给她安排的人吗？姚氏心里打鼓，她狠狠瞪了一眼月圆和月缺，这两个没长眼的丫头，这个时候摆什么大丫鬟的谱，穿什么新衣裳？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月圆和月缺也很无奈，她们本想着穿好点，给纤尘一个下马威，要她知道自己可是大夫人身边的大丫鬟不要没哪个眼力劲，她们可不是什么活都干&nbsp;的粗使丫鬟，没想到这下马威没摆成还搬起石头砸了自己的脚。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏为了硬将这两丫头塞给纤尘又展出她那白莲圣母般的微笑，“尘儿，你说什么呢？你是冉府的小姐，她们是下人，下人必听主子的话，你想让她们做什么，她们就必须做什么，有什么不好意思使唤的？她们若不听话，我就将她们‘卖到灯红酒绿阁’看她们还敢不敢不听你的话。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘要的就是姚氏这句话，这两丫头一来就给自己摆大丫头的谱，她偏偏要将她们当粗使丫头用，还要用的有据有理。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“真的吗，母亲？纤尘激动地问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏被纤尘突然的一惊一乍惊了一跳，僵了僵，脸上又才挤出个不自然的笑来，“真的，真的，你是冉府的小姐，可以随便使唤冉府的下人，这是规矩。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“谢谢你母亲大人，我也有可以使唤的丫鬟了！”纤尘似乎很激动，还给了姚氏一个拥抱。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏没想到纤尘会这样激动，她一口一个母亲，喊得她也很顺心，面对这位脑子里缺根筋的嫡长女，姚氏心里的戒备也卸下不少，不过监视她的一举一动还是很重要的，毕竟叫她回来是有目的的，可不能半路出现什么幺蛾子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;得了姚氏的话，纤尘转头看向月圆和月缺，“两位姐姐，尘儿口有点渴，你们可不可以给尘儿弄点水来喝；尘儿一天都没吃东西了，肚子有点饿，你们可不可以帮尘儿找点吃的来；还有，还有就是尘儿想洗个澡，你们可不可以……”纤尘话没说完就难为情的低下了头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这么多“可不可以”，难不成她以前就没使用过下人？冉府的下人门都忍不住嘲笑纤尘的土气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹都鄙视纤尘，觉得自己有这么一个又丑又土的嫡姐真是丢了她的脸，她到底是个聪明人，转而又想，她傻才好，冉府就只有她们两个嫡女，若她聪明了，自己岂不是遇到了强敌？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;丫头婆子们的窃窃私语姚氏自然是听见了的，只是她听见当没听见，脸上依旧展着那白莲圣母般的微笑道：“尘儿长途跋涉也是伐了，大家伙都回去吧，月圆，月缺你们侍候小姐沐浴更衣。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;众人离开纤尘的院子，姚氏直接去了书房找冉羽涅，“老爷，你也看到了，冉纤尘现在又丑又憨，妾身觉得她与我堂哥家的那个二娃真是天造地设的一对。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“不行，不行，你表哥家那个儿娃是个傻子，怎么可以和纤尘相配？”冉羽涅想都没想便一口回绝。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏立马冷下脸，“怎么就不行了，我堂哥是四品中书侍郎，二娃是他嫡子，这嫡子与嫡女，傻子和傻子配不是正好合适？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏在冉府，打开府门是贤良淑德，关上府门虽然不是个河东狮，却也是个强势的女人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;当初冉羽涅是借着姚家的势力才在京都站稳脚，他娶姚玉儿确实也是向姚家隐瞒了自己已婚的事实。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅心里对姚氏有愧，他一直觉得姚氏原本就是个贤良淑德的好媳妇，如今她变成这样，全怪自己当初骗了她，故而，在府里冉羽涅一直纵容着姚氏。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘变成今天这个样子，冉羽涅心里也有愧，她不想再将纤尘嫁给姚家那个傻子，拧着眉道：“玉儿，你说什么疯话呢？尘儿那是傻吗？她不傻，她只是有些憨厚老实罢了！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说完他突然又想起了什么，顿了顿继续道：“玉儿，当初我们不是说好的吗？等纤尘回来，就请罗大人、王大人、赵大人、文大人这几个官位低为人还可以的大人们的家眷来府上做客，不管怎么说我也是正二品大员，我女儿再丑，嫁给他们的儿子也是绰绰有余的，毕竟那些个大人们官位都比我低许多个等级。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏在心里向冉羽涅翻了个白眼，纤尘那个丑模样，能被这些大人家的公子看上？做你的春秋大梦吧，你当谁都向你冉羽涅一样，为了仕途不择手段，靠了老婆靠女儿？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏从头到尾想得都是将纤尘嫁给她那个傻侄儿，无论纤尘是丑是美，姚氏都不会让纤尘嫁给官宦子弟，尤其还是那种人品好的官宦子弟。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她恨纤尘的母亲，即便那个女人死了，她也恨那个女人，唯一报复那个女人的办法，就是折磨那个女人生下的女儿。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她那个傻侄儿不仅人傻，发起病来还很暴力，她堂哥府里的丫鬟被他那个傻儿子暴打，打伤打残废的也不只一个两个，她想，若冉纤尘嫁给他定会受尽折磨。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏当初就是怕冉羽涅看出她的想法，才搬出罗大人、王大人、赵大人、文大人这几位大人家的公子来，其目的也只是想说动冉羽涅将冉纤尘从交州叫回来而已。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;让人意外的是纤尘又憨又丑，这样一个丑憨货哪家官宦人家会娶进门当媳妇？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见冉羽涅脸色不太好，姚氏卷卷手里的绢帕，咬了咬唇，不甘心道：“老爷，尘儿那么丑，哪家公子愿意娶那么一个丑媳妇过门？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“丑怎么啦？丑那也是我冉羽涅的女儿，我可是朝堂正二品官员！”冉羽涅彻底黑了脸。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看来和他也没什么好商量的，这人还真当自己是颗葱姜蒜，姚氏瞥了冉羽涅，蔑视地冷哼一声，“哼，行，老爷都吩咐了&nbsp;，那妾身这两天就去张罗，请各位夫人进府游玩一事，若老爷没旁的事，妾身便告退了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏敢这样应就是笃定，那些官员府里的夫人们看了冉纤尘这个模样都会被吓跑，提亲，她们愿意吗？现在不用她出手阻止，冉纤尘那副尊容就已经将那些想借联姻攀附冉府的大人们拒之门外。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉纤尘的人已经回来了，要把她嫁给谁可由不得冉羽涅，姚氏怏怏离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅就当看不出来姚氏对她的蔑视，埋着头淡淡道：“嗯，那就有劳夫人了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此刻，姚氏已经走出了书房，冉羽涅最近很忙，交州那边县令和海防将军双双自杀，皇上一直想派人去接手交州事物，一直又都没选好人手。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;皇上一日不将交州那边的人手定下来，冉羽涅的心一日就是揪着的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;县令之位给谁？冉羽涅并不关心，他关心的是交州海防的兵权会落在谁手上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原本这些都不是他操心的事，按照以往的规矩，待三殿下将交州那边的事情理顺后，皇上便会招他回宫，三殿下回宫后皇上定会让他交出交州的兵权，这交州的兵权就会顺理成章地交给九皇子康王殿下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;让人万万没想到的是，半路杀出个程咬金来——<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;镇南将军王苏奎岚大将军王，上表朝堂，说曹将军是他的属下，自己治理属下无方，才导致属下犯错，愿将功赎罪亲自带兵驻守交州，护交州百姓平安。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏奎岚大将军王一个自荐，就是在和九殿下抢兵权，弄得皇上迟迟定不下来交州新将军的人选，冉羽涅在书房里来回踱步，在想明天在朝堂之上要怎么替九殿下赢得兵权。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅在书房愁天下之大事，纤尘苏、妈妈和韩双双三人则围坐在小桌边惬意地吃着梅花糕。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这梅花糕是月圆和月缺特地从厨房给她们端来垫肚子的吃食，现下纤尘又将这两个人打发去厨房给她烧洗澡水。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这梅花膏形如梅花，是用糯米制成，软糯香甜，韩双双往自己嘴里噻了一个梅花，边嚼边还边说：“小姐，我终于知道，当初您为什么一眼就看出我卖身葬父是假的了，你看你呀，装得可比我像多了，简直就看不出一丝破绽来。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;终于要和姚氏交锋了，纤尘有点小激动，“那是，她姚氏会装贤良淑德，我就会装憨，憨货对付姚氏那种聪明人，鹿死谁手就看我们谁的道行高了？你们直管好好看戏，看我是怎么帮她撕下她那维持了很多年的伪装。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姐，你也得多加小心，那韩氏就是一只披着人皮的狼，她贤良淑德的形象在大家心目中已久，一时半会可不好撕。”苏妈妈说着就向门口走去，“我去看看那两个丫头将小姐的洗澡水准备好没。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“放心，她们不会那么早回来的。”纤尘说。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘吩咐那两丫头去烧六桶开水，这六桶开水还不得让她们烧上一段时间？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;再说纤尘的听觉明锐，大白天的她还怕那两个丫头听了墙角去？估计她们刚爬到窗门口，纤尘就已经察觉出来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘一副淡然的模样苏妈妈却不放心，在门边向外望了望，见院外空无一人，又才走到了桌边，轻声说：“小姐，小心使得万年船。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;正说着，纤尘柳眉上扬，警惕地道：“有人来，而且不是月圆和月缺。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348359, 1334318224314048512, '&nbsp;&nbsp;&nbsp;&nbsp;韩双双立即起身站到纤尘身后，苏妈妈向门外走去，刚到门口，她就看到一个十一二岁的小女孩怯生生地在月亮门外探头探脑，东张西望。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“小姑娘，你找谁？”苏妈妈来到小女孩身边，纤尘和韩双双也跟着出了房门。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;小女孩见纤尘出来，明亮的眼睛探索地望向她，这小姑娘纤尘记得，她就是一路跟在庄姨娘身边和庄姨娘紧牵着手的那个小姑娘，想必这位就是她那庶出的三妹妹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;小女孩一身粉衣，俏脸还没张开如含苞待放的夏荷，头上扎着两个丸子髻俏皮可爱，忽闪着水灵灵的大眼睛，一只小手扣着下唇，歪着脑袋好奇地盯着纤尘看。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;小女孩好奇的看着纤尘，纤尘也好奇的看着她，这小女孩眉宇见透着几分与庄姨娘相似的柔美却没有半点冉羽涅的影子，这反倒让纤尘很喜欢。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉府的人个个都是人精，防人之心不可无，纤尘在这个小女孩面前也不敢不提防，她又展出那二哈般憨厚的模样，“小妹妹，你吃糕饼吗？”纤尘将自己手里的一块糕饼递给了那个小女孩。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;小女孩眼巴巴地看着纤尘手里的糕饼，其实她很想吃却又不敢接，小嘴动了动咽了咽口水，望着那糕饼摇头，“娘说，不能乱吃别人给的东西。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘和苏妈妈面面相觑没有多说，韩双双见她二人都没说话自然也没开口。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘知道，这是人家的娘教得好，这个府里的东西，可不就是不能随便乱吃吗？姚氏的父亲是太医院的院判大人，姚氏的女儿又深得祖父真传，在这个府里，若学不会管住自己的嘴，到时候自己怎么死的都不知道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她不吃，纤尘也不勉强，便问道：“小妹妹你是来找我的吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那小女孩点点头，脑袋歪来歪去盯着纤尘看了又看。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你找我有事吗？”纤尘又问，旋即就自顾自吃着梅花糕，任由那孩子随意盯着自己看。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;小女孩见纤尘吃得香甜，又忍不住咽了咽口水，纤尘见她实在是馋得紧，很想吃的模样，就将另一只手里的梅花糕递给了她，小女孩依旧摇摇头，懦懦地问：“你真是我的嫡姐姐吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯。”纤尘一本正经，憨乎乎地点点头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那小女孩歪了歪小脑袋疑惑地问：“那为什么你和花楹姐姐不一样？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哪里不一样啦？”纤尘问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;小女孩不答反问：“嫡姐姐为什么会住这个院子，为什么衣服比我的还脏？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;噗……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这是在嫌我衣服太脏呀，纤尘喷出一口糕饼星子，“我从很远很远的地方来，一路舟车劳顿没时间洗澡换衣服，等姐姐洗澡换好衣服，姐姐的衣服就不脏了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那小女孩若有所思，点了点头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘憨然一笑又问：“我这么丑你不怕我吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那小女孩再次摇摇头，“不怕，你不凶！”说完一转身撒丫子就跑走了，弄得苏妈妈和韩双双都觉得这丫头有些莫名其妙。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘望着小女孩跑远的背影，嘴角勾出一抹浅笑，&nbsp;“没事，那小姑娘是自己来的，她不过是对我好奇，来看看我罢了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原来如此，苏妈妈和韩双双都放下心来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;待月圆和月缺灰头土脸将六桶开水烧好，小心翼翼抬进纤尘的房间后，纤尘又吩咐她们打来冷水兑好洗澡水的温度。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的院子偏远，离开厨房和打水的地方都不近，这两个丫头将纤尘的洗澡水兑好后已经累得气喘吁吁。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;可事还没完。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘洗完澡又吩咐这两个丫头将桶打扫干净再去打来冷水，给苏妈妈兑好洗澡水。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这两个丫头先是不干，强调，“小姐，夫人派我们来是侍候您的，我们不侍候下人。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“谁说苏妈妈是冉府的下人了，她是我的亲人，她和我一样都是这个院子里的主子，你两若不想侍候就回去吧，我这里就不用你两侍候了，看来母亲就是在诓我，说什么我是主子让你们做什么你们都会去做，都是骗人的假话，我这就去告诉母亲，你们不听话。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;两个丫头一听，纤尘要去姚氏那里告状，还要将她们退回去，心里就急了，在来这个院子之前，姚氏是再三叮嘱她们无论如何都要想办法留在这个院子里，取得纤尘的信任，若她们才进这个院子就被退了回去，以后夫人还会重用她们吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;显然不会，夫人定会觉得她们没用，连这点小事都做不好，两个丫头忙给纤尘赔礼不是，“大小姐，您别生气，都是婢子们不懂事，我们现在就去给苏妈妈兑洗澡水。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;替苏妈妈兑好洗澡水，纤尘又吩咐两个丫头替韩双双兑洗澡水，月圆和月缺这两个丫头一连侍候了三个人的洗澡水。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她们从纤尘的院子里跑到厨房打水又从厨房将水打回院子，来来回回都不知道跑了好多趟，等韩双双洗完澡，她们将浴桶收拾干净就已经累得上气不接下气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月圆和月缺是姚氏身边的大丫鬟，平日里做的都是端茶送水，修花剪枝的轻活，哪里会做这种粗使下人做的活？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天她们不仅做了还做得很多，累得这两个丫头已经是腰酸背痛腿抽筋，还没等她们休息一会缓口气，纤尘又吩咐她们去洗衣服。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月圆和月缺都要累死了只得将姚氏搬了出来，“小姐，洗衣服这种活是粗使丫鬟做的，我们是夫人身边的大丫鬟，是不做这些粗活的。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她们心想，夫人身边的大丫鬟，谁敢使唤？老夫人都使唤不了夫人身边的大丫鬟，小姐你看在夫人的份上也不会再使唤我们做粗活了吧？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;偏偏纤尘是个缺根筋的憨货，她不明白大丫鬟是什么东西，问：“大丫鬟不是丫鬟吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“是。”月圆恭恭敬敬的答道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“那不就完了，都是丫鬟，那你们为什么不能洗衣服？不洗你们就回去吧，我的院子里可不要连衣服都不会洗的丫鬟。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看纤尘二哈般憨傻的模样又不像是在故意在刁难她们，这让月圆和月缺都不知道该怎么和纤尘理论。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月缺觉得自己很委屈，忍不住想要开口与纤尘讲讲道理，可她嘴还没开，月圆就拉了拉她，恭敬回纤尘道：“好，大小姐我们这就去洗衣服。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月缺杏眼圆瞪，樱嘴大张不可置信地看着月圆，月圆则向月缺使了一个眼色，月缺会意便跟着月圆拿着三人换下来的衣服去清洗了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;离开小院月缺就忍不住问：“月圆姐姐，你这是什么意思，怎么我们就这样妥协了？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月圆无奈地叹了口气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哎，你还没看出来吗？这大小姐脑子缺根筋，什么事情在她脑子里都是直的，她根本就不懂什么是大丫鬟，给这种憨货讲理，你能讲得明白吗？再说了，即便告到夫人那里，以夫人的为人她会帮我们说话吗？你都忘了，夫人叮嘱过我们什么？若我们将她的事搞砸了，她说不定真会把我们卖到‘灯红酒绿’那个地方，你愿意去吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一听到“灯红酒绿”月缺就后背生凉，那可是纪国京都最有名的妓、院，她可不想去那种地方，不情不愿惺惺地跟着月圆离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月缺终于明白一个道理，跟脑子有问题的憨货没道理可讲，原先她还想着自己是大夫人身边的一等大丫鬟，就凭自己这身份，这大小姐都会对自己礼遇有佳，没想到这大小姐脑子里缺根筋，完全没有大丫鬟和粗使丫鬟的区别，月缺很无奈，可怜自己太悲催怎么就摊上了这么个活计？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;晚膳时间将近，姚氏身边的容妈妈过来请纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“大小姐，今天晚上夫人特地为大小姐安排了接风宴，老身特地来请大小姐前去赴宴。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“好。”纤尘应了容妈妈，一手牵着苏妈妈，一手牵着韩双双，笑呵呵的带着她们两人一起去赴宴。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“咳…咳…”容妈妈轻咳了两声，“容妈妈，你是不是嗓子不舒服？快去看看大夫，我们自己去。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘装着听不懂容妈妈的轻咳是什么意思，还憨憨的叫她去看大夫。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;容妈妈顿时就觉得气堵得慌，无奈这小姐脑袋里缺根筋，容妈妈毫不掩饰地向纤尘翻了个白眼，面带嫌弃地对纤尘说：“大小姐，这是主子们的家宴，下人是不能参与的。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“她们不是冉府的下人，她们没有卖身给冉府，她们一个是我的家人，一个是一路护我周全的恩人，怎么会是下人呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘一句话将容妈妈堵了个哑口。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;容妈妈觉得自己今天就是秀才遇到兵，有理也说不清，她知道任由自己今天说破了嘴也说不服一个憨货，因为憨货的脑子和她们正常人就不一样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;算了，先容着她，等到了雅兰院自然有人教她规矩。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;容妈妈就这样苦着一张脸在前面带路，纤尘就这样兴高采烈牵着苏妈妈和韩双双的手，跟在容妈妈身后，向着正厅雅兰院走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;容妈妈将纤尘她们带走后，月圆和月缺都深深叹了口气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哎……！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哎……！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;两人都感叹这憨货小姐惹不起，连容妈妈都碰了一鼻子的灰。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月缺又叹口气，“哎，月圆姐，你说那大小姐要是个正常人该多好，至少她知道什么是大丫鬟；至少她知道不看僧面看佛面，看在夫人的面子上，也绝不好意思让我们去做那些个粗活！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月圆揉着自己酸痛的手臂，一脸的无奈，“谁说不是呢？你说这大小姐，说她傻吧，她还算不上，简单的是非道理她还是明白的；你说她不傻吧，她脑子确实又缺跟弦，说什么都是直愣愣的一点也不通人情世故。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;两个丫头又异口同声叹了口气，“唉……”感叹，这样一个憨货主子，难侍候哟！', NULL, NULL);
INSERT INTO `book_content` VALUES (3348360, 1334318225014497280, '&nbsp;&nbsp;&nbsp;&nbsp;112<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“算了，我们忍忍吧，反正她在府里也住不久。”月圆说。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月缺跟着点点头，二人便回了自己的房间休息。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘她们跟着容妈妈已经来到雅兰院的餐厅，冉府一家的主子们都已到了，齐齐围坐在桌边等着纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏和冉花楹见纤尘将苏妈妈和韩双双都带了过来，两个人同时都皱起了眉。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅也诧异纤尘将苏妈妈和韩双双带了过来，只是又见韩双双冉羽涅的心里已经泛起了涟漪，这对他来说又何尝不是一个惊喜？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双的那双眼，天生充满魅惑，墨黑的眸子里有娇羞、有柔弱、有纯情，还有浓得化不开的温情，早将冉羽涅的三魂六魄给勾了去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;有姚氏在，冉羽涅不得不压制着内心的心喜，要不然此刻他早就上前献殷勤了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘快步上前，不等他们先开口自己便抢先向桌上的长辈们一一问好：“祖母好，父亲好，母亲好，庄姨娘好！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姨娘在府里的地位就是个下人，庄姨娘没想到冉纤尘也会向她问好，突然有种被尊重的感觉，心里升出一股暖流，她本想起身向纤尘行礼就看见纤尘转身去牵了苏妈妈和韩双双。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘牵着苏妈妈和韩双的手，将她们拉到桌边，“各位长辈，苏妈妈和双双姑娘都不是卖身于冉府的下人，却一直照顾着尘儿回京，没有她们尘儿说不定就回不了京，便也见不到各位家人，她们都是有恩尘儿的人，父亲曾经就教导过尘儿要知恩图报，这顿接风宴尘儿觉得更应该是她们的答谢宴，祖母、父亲、母亲、姨娘你们说尘儿说得对吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘绝世无双的丑脸上唯有那双眸子好看，透着孩童般的单纯，二哈般的憨模样咧着人畜无害的憨笑，直叫人不好意思拒绝。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;京都是个最讲规矩的地方，在达官贵人家中，一些场合，就连妾氏都不能与家主同在一张桌上吃饭，何况是向苏妈妈和韩双双这样的下人，怎么可以让她们与府中主子们同桌吃饭？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏和冉花楹心里都非常排斥这两个人，然，纤尘说得又十分有理，人家是护送大小姐回府的恩人，一句谢恩宴让所有不合理都变得合情合理起来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏不做声，冉羽涅见姚氏不做声自己也不好意思开口，即便他现在很想韩双双与他同桌吃饭，庄姨娘更是不敢做声。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双刚洗完澡，三千青丝带着一点点未干透的湿气，随意洒落在她的肩后如墨色的缎面又如泻下的瀑布，精致的小脸蛋嫩得可以掐出水来，整个人都如出水的芙蓉丽色天然美得娇嫩不染尘埃，让默不做声的冉羽涅忍不住偷瞄了她一眼又一眼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅和姚氏两个当家人都不说话，气愤一下子有点僵。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;半晌都没人说话，冉老太太便开了口，她笑呵呵地帮腔道：“尘儿说得在理，她们不是冉府的下人，是帮了冉府大忙的恩人，我们还没感谢人家呢，这桌子这么大，我们冉府的主子又少，坐下来大家一起吃饭也热闹。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉老太太随意的一句话却被姚氏听出了不同的意思，这老家伙不就是在说他们冉府家丁不旺吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏自从那次小产后便失去了生育能力，无奈只好从姚家弄了个表妹过来，这表妹是姚院判一个妾室的侄女，名曰庄享月也就是现在冉府的庄姨娘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘家境不好，父母早世，后来由姑姑抚养长大，她这个姑姑只是姚家一个没有地位的妾，姑姑为了保住自己在姚家的地位便拱手将她送给了姚玉儿。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在庄氏进冉府前，她姑姑就带着还是黄花闺女的庄享月给姚玉儿承诺，若庄享月为冉府生出了个儿子，就直接送给姚氏做嫡长子，那孩子从此与她庄享月没有半点关系，若庄享月生的是个女儿就只是冉家的庶女。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;天不遂人愿，这么多年来，庄氏也只给冉府添了一个女娃而已。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏心里憋着气，恨恨剜了庄氏一眼，庄氏被姚氏的眼刀击中，懦懦地埋下了头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;毫无存在感的庶女冉剪秋，也跟着母亲乖巧地埋下了头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这会就听见冉羽涅顺着冉老太太的话说道：“母亲说的在理，既然不是冉府的下人，是尘儿的恩人，感恩是美德，那就请二位一起用个家常便饭吧！”冉羽涅这个时候装起了大肚，还鬼使神差地起身招呼着韩双双她们落坐。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅这通骚操作，气得姚氏心火上蹿，起身就要离去却被冉花楹拉住，轻声对她耳语，“母亲，她就是一个憨货，你何必和一个憨货计较，失了风度。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏刚刚的眼刀刚将庄氏刮了个不敢抬头，这会子她的眼刀就直接飞向了冉羽涅，冉羽涅脸皮厚被姚氏的眼刀击中，对姚氏尴尬地笑了笑，就对她的眼刀视而不见。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏耐着性子没向冉羽涅发火，心想，楹儿说得没错，她干嘛和一个憨货计较，反正这憨货也没两天好日子可过。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;既然已经容下了她们同桌吃饭，姚氏自然不会忘记伪装自己，她现在虽然笑不出来，不过也一改刚刚的不悦，招呼着她们，“既然老爷都发话了，大家就都坐下来一起吃吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;反倒是冉花楹端庄、大方、得体地起身招呼纤尘，“大姐姐，您来这坐。”冉花楹指了身边一个空着的坐位，示意纤尘挨着她坐。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“谢谢二妹妹。”纤尘自然不能驳了冉花楹的一番好意，欣然落坐。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“大姐姐远在交州父亲和母亲也时常牵挂大姐姐，妹妹知道自己在交州还有个大姐姐也是牵挂得紧，姐姐这些年在交州受苦了。”说着冉花楹就夹了一个鸡腿放进纤尘的碗里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘偏不吃冉花楹虚情假意这一套，她不客气地啃了一口鸡腿，油嘴，油嘴嚼着鸡腿肉，毫无闺秀的样子，对着冉花楹憨憨一笑，眼里放着求真般的光问：“真的吗，二妹妹说父亲和母亲时常挂念我是真的吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;咳咳……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹差点被自己的口水呛道，这憨货，还真把别人客套的话当真？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;没等冉花楹咳完，纤尘转而又将她那求知般真诚的目光投想冉羽涅，“父亲，二妹妹说的是真的吗，你真的挂念着尘儿吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双正好坐在冉羽涅的对面，此刻冉羽涅正在偷瞄韩双双，突然被纤尘的问话打断，心里一慌，想也没想就应了句“真的，真的。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“那你有多挂念尘儿？”纤尘追问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅仿佛觉得这个冉纤尘就是在与自己过不去，不让他好好瞧韩双双，不耐烦地看了纤尘一眼，“挂念又不是量词，我也说不上有多挂念。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这就是她的那个渣爹，连一句敷衍的温暖话也不愿意给纤尘，纤尘的心里凉到了冰点。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;对纤尘来说，你不让我心里痛快，我也要恶心恶心你。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“呵呵呵……爹爹挂念尘儿，尘儿就好开心。”纤尘发出人畜无害的憨笑，做出一副非常开心的模样，眼睛还故意在桌子上搜了搜，见桌子上没有鸡腿才对冉羽涅又道：“爹爹对尘儿好，尘儿也要对爹爹好，桌子上没有鸡腿了，尘儿就将自己碗里的鸡腿给爹爹吃。”&nbsp;说着就将自己碗里那个啃过一口的鸡腿夹到了冉羽涅的碗里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅顿时头大，看着碗里被咬下一口的鸡腿，仿佛还残留着纤尘的口水，心里就觉得十分恶心，十分窝火，这叫个什么事？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅想发火，冉老太太就瞪了他一眼，媳妇她管不到，这个儿子老太太还是管得到的，“这也是尘儿的一片孝心呀！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅被冉老太太这么一瞪，火气生生被憋了回去，硬是没发出来，想当初，他的尘儿也是个聪明的孩子，会变成今天这个模样，也怪自己，冉羽涅看着碗里的鸡腿左右为难，丢也不是，吃也不是。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘给了韩双双一个眼色，韩双双会意，这是纤尘给自己创造的一个表现机会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双立马出来救场，柔声说：“纤尘小姐，吃过的东西怎么可以再给别人呢？这样不礼貌。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哦！”纤尘故做恍然大悟，“二妹妹给我夹鸡腿，我以为鸡腿是最好的东西，桌上又没了鸡腿，我就将自己的鸡腿夹给父亲，既然不礼貌，我赶紧收回来。”说着纤尘就将冉羽涅碗里的鸡腿夹走，速度之快，动作之麻利，眨眼的功夫冉羽涅碗里的鸡腿又落到了纤尘的嘴里<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;如释重负。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见自己碗里的鸡腿被纤尘夹走，冉羽涅感激般地向韩双双点了点头，心里对韩双双的好感陡然上升到一个新台阶，不仅觉得韩双双人长得漂亮更觉得她格外的温柔体贴，她的声音悦耳得让他有种浑身都舒舒麻麻的感觉。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;旋即，冉羽涅就很很地瞪了冉花楹一眼，仿佛在说，没事你对尘儿献什么殷勤，不知道她脑子里缺跟筋呀，你看你弄得为父差点就下不来台。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹被瞪，心里自然不好受，她哪里会想到纤尘会将客套话当真，还会刨根问底，转儿她就瞪向纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘这会子正专心致志地啃着鸡腿，完全一副无事人的模样，冉花楹狠狠瞪出去的一眼落在纤尘身上，如打水的竹篮，落了一场空不说，还白费了干瞪眼的力气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“这个大姐姐还真憨，憨得不是一般般。”冉花楹气得翻了个白眼，低声咒骂了句，手里拿着筷子，心里却完全没了吃饭的兴致，桌上的饭菜进入她的嘴里也是味如嚼蜡。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;女儿不开心，当娘的自然也察觉得到，姚氏又反过来安慰冉花楹，“楹儿，她就是个憨货，你和憨货计较个什么劲？她就快嫁给你二表哥了，现在让她好好吃，等她嫁过去后，还不知道你二表哥给她吃什么呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹突然想起他那个傻子二表哥，逼着家里侍候他的丫鬟吃泥巴，吃猪食的样子，心里就幻想着她那个傻子二表哥也逼着冉纤尘吃泥巴，吃猪食的样子，心里的气一下子就消了下去。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348361, 1334318225710751744, '&nbsp;&nbsp;&nbsp;&nbsp;韩双双见纤尘戏演得逼真，看着冉花楹母女气得吹胡子瞪眼，却又拿纤尘没有半点法子的模样，就忍不住想笑，憋得一张小脸通红又怕旁人发现她的失态，心虚地将头埋了下去偷笑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;片刻之后，韩双双抬起头来，正巧看见冉羽涅正看着自己，四目相对，七上八下一阵心慌，如万马奔腾又如张草的泥菩萨慌神凌乱。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅的眼神含情默默，热烈似火，然，韩双双全然没有感觉到冉羽涅的温情，她慌乱地担心着自己刚刚的偷笑是不是被冉羽涅发现，她怕冉羽涅发现什么端倪影响了纤尘，慌乱中，她又再次将头埋了下去，不敢去看冉羽涅，掩耳盗铃般的认为只要自己不去看冉羽涅，冉羽涅就不会再看她。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;殊不知，冉羽涅此刻的头脑已经发了昏。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;现在，在冉羽涅眼里，韩双双的所有表现即便是那个忍不住的偷笑，都成了小女儿家的娇羞，看得冉羽涅是春心荡漾，成了涟漪一圈圈化开又一圈圈泛起，他现在的脑子里还能有什么其它的想法？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见韩双双羞涩地埋着头久久没有抬起，冉羽涅才得空大口大口吃起东西来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;桌上，老太太带着三分失望，七分心疼看着纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见她旁若无事，津津有味地吃着饭，啃着鸡腿，心里更是五味杂陈，看到桌上一大堆食物也没了胃口。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太是个知恩的人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;儿子能有今天的功名，有一大半要归攻于交州沈家，归功于沈家当年好心，不记回报的供自己儿子读书。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太年轻的时候家境贫寒，儿子想读书求去功名，家里没钱，投学无路，是沈家向他们敞开了私塾的大门。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;也是那个时候，开启了她儿子冉羽涅与沈家大小姐沈芳芳的缘分。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;白富美与穷小子的浪漫爱情故事曾经在交州也是一段佳话，殊不知，往往白富美爱上穷小子都没有好的结局，因为爱得痴也注定伤得深。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;儿子求娶沈家大小姐成功，沈家大小姐下嫁他们冉家，沈氏从来没有嫌弃过她这个穷婆婆，相反，沈家大小姐知书达理，对她这个穷婆婆敬爱有佳，婆媳两做起事来有商有量，和和睦睦，不像现在这个姚氏，仗着自己是院判的女儿，对自己也是各种瞧不起，说出来的话，明里暗里还带着刺。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太也不怪姚氏对自己不好，她知道，姚氏心里也有气，自己儿子当年也是连蒙带骗才将姚氏娶到手的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;自己儿子是个什么人？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;知子莫若母，老太太心里跟明镜似的，别看冉羽涅现在对姚氏百依百顺，若姚氏家里出了什么事，影响到他的仕途，或者有个更厉害的女人，能帮他的仕途再提升一个台阶，老太太敢肯定，她这个儿子也会毫不犹豫地抛弃姚氏。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太暗自生自己的气，气自己怎么就生了这么不是个玩意儿的东西？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太突然想到冉羽涅的父亲，那个当初为了吃上两口饱饭，狠心将他们母子两抛弃和青楼一位风烛残年的老妓、女过起了日子的男人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那个男人花光那个老妓、女的钱后，就又和一个卖小面的寡妇搞到了一起，寡妇门前是非多，那个卖小面的寡妇又是个骚狐狸，姘头不只冉羽涅父亲一个，一天几个姘头争风吃醋，嫉妒冉羽涅的父亲长得好看，便联手将冉羽涅的父亲拖到海里活活给淹死了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅的父亲是老太太心里永远的痛，那天她看到那个男人的尸体被打捞起来，竟然没有落下一滴眼泪。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哀默大于心死，老太太对那男人已经心如死灰，她没想到自己生的这个儿子，竟也随了他的那个不是个玩意儿的爹！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;可冉羽涅是她的儿子，面对自己的儿子，老太太能有什么办法？除了愧疚还是愧疚。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;同为女人的老太太，一想到自己的遭遇，心里无论是对死去的沈氏还是对现在的姚氏都感觉非常、非常的愧疚。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天，看到原本聪明可爱的纤尘，变成了现在这个模样，她愧疚的心就沉得气都喘不上来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你们吃吧，我身子不舒服，先回房了。”老太太放下筷子就对薛妈妈说“薛妈妈你过来扶我回房休息吧。”。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;薛妈妈是姚氏安排在老太太身边侍候的人，她看了一眼姚氏，见姚氏没有反对，就快步向前扶起老太太。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“母亲，可是身子有哪里不舒服，要不要儿子给您请个太医来瞧瞧？”冉羽涅关心道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“不啦，都是老毛病，我这腰呀坐久了就疼，我没事，就是想回去躺躺。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅纵使功利心很强，对女人来说是个十足的渣男，不过对她这个母亲还是孝顺的，老太太怎么也生不起自己儿子的气来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“祖母，尘儿也吃饱了，尘儿陪你一起回去吧。”纤尘扬手用手背抹了抹嘴上的油，顺势就起身来扶老太太。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太慈爱地拿出绢帕来替纤尘插去手背上的油，“尘儿，以后就不要用手擦嘴了，你是个大家闺秀，要学会用餐巾擦嘴，你今天才回府，长途跋涉也累了，吃好了就早些回院休息，祖母乏了今天就不用你搀扶。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;刚刚老太太在给纤尘擦手背上油的时候，纤尘就顺手替老太太把了一下脉，老太太身体也确实没什么大毛病。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘本想去给老太太看看她的腰病，既然老太太拒绝她搀扶，她也不好再坚持，来日方长，改天再去给祖母诊疗也不迟。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太走后，纤尘她们也准备离席。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“尘儿，等等为父。”猝不及防，冉羽涅叫住了纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“爹爹可是有什么事？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅用餐巾擦了擦嘴，起身理了理衣服，宽肩窄腰一身修长的冉羽涅就是一具行走的衣架，俊朗的脸上镶嵌的两瓣唇，虽性感非凡，却自带一份天生的多情和薄情。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“为父陪同你一起回院，为父白日里太忙，这会子得了空，为父也去看看你住的院子。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘脸上闪出一丝讥讽，转瞬即失，她还不知道他父亲脑子里想的是什么吗？他对韩双双放的电，她可都看进了眼里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏一听，冉羽涅要去纤尘的院子里看看，忙用餐巾点了点嘴，起身道：“我也陪夫君一起去吧！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅心里一阵烦躁，心想怎么那儿那儿都有你？你陪我去什么，我又不是找不到回房的路。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他又不敢真的在姚氏面前表现出来他的不悦，心里腹诽一通，脸上却和颜悦色道：“玉儿，我也只是去看看尘儿的院子，认个路，去去就回，你这一去，人一多难免耽误时间，你还是别去了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏在冉家是很强势的，他不怕冉羽涅说她给纤尘安排的院子不好，他也知道，冉羽涅不会对她的安排有微词。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉纤尘这个女儿若长得漂亮，兴许冉羽涅还会把她当成对自己有利可图的一枚棋子，对她好一些。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;如今的冉纤尘丑得毫无价值可言，对冉羽涅来说也可有可无，至于她的住所如何？只要能住人，想必是个柴房冉羽涅都不会多说一个字。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏刚刚不过也只是句客套话罢了，既然冉羽涅都说了她不用去，她便也不去了，省得看到冉纤尘那个憨货自己心里就堵得慌。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她做出一副善解人意的模样，“那夫君早去早回。”还顺手替冉羽涅理了理他的衣服领子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;可惜了，姚氏母女整个席面上都将注意力用在了纤尘身上，她两谁也没注意到冉羽涅对韩双双发情放电。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄氏闷不吭声吃着饭，这会子也吃好了，她的女儿冉剪秋也懂事地停下了筷子，见冉羽涅就要离去，庄氏忙起身向冉羽涅福了一礼，“老爷，天色不早了，妾身这就带剪秋小姐回房休息。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯。”冉羽涅并没有多看庄氏一眼，只从鼻子里嗯了一声出来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄氏小心翼翼地离去，纤尘看着她带着女儿落寞离去的背影，就知道庄氏母女在冉家其实过得不好，冉羽涅的心里根本就没有这对母女两。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;能走进冉羽涅心里的女人，要嘛有权有势能在事业上帮他一把，要嘛就要年轻漂亮，顺从乖巧能激起他的欲、望，像庄氏这样两头都不占的女子，注定在冉羽涅眼里没有存在感。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅陪着纤尘回院子，她的院子离雅兰院这边很远，路上冉羽涅先开了口，“韩姑娘，你是交州哪里的人？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅开口问的第一句话，竟然问的是韩双双！渣爹就是渣爹，真叫人失望。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他和纤尘十二年父女未见，他就没问问纤尘，女儿你在交州还好吗？可是受苦了？或者是女儿你们长途跋涉累不累，途中安全吗？……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一句对纤尘虚情假意关心的话都没有，一开口问的竟是韩双双，纤尘也不再对这个渣爹抱有任何希望。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她现在对冉羽涅连心寒都没有了，换而言之，纤尘对冉羽涅已经没有了任何感情，在她心里，冉羽涅就是个陌生人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘知道冉羽涅醉翁之意不在酒，想借着陪自己回院的时间泡妹子，暗自腹诽道：真是一把老干柴，见不得半点儿的火星儿。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双娇羞地答着冉羽涅的问题，他们就这样一个问，一个答，慢慢走着，期间韩双双还发出咯咯咯……勾魂的低笑声。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不知不觉，两人就走到了纤尘和苏妈妈的身后，落下一段距离。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双时不时抬眼看向冉羽涅，眉眼间的魅惑之力如同一把把穿心箭，射得冉羽涅心神荡漾。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今晚月明星稀，明亮的月，洒下一抹柔和的光，路边的一小片小树林将这份月光遮挡七分留下三分斑驳地洒在青石板小路上，带着几分夜的暧昧极适合幽会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅想在这样的月色里偷腥，纤尘又岂能随了他的意？', NULL, NULL);
INSERT INTO `book_content` VALUES (3348362, 1334318226448949248, '&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅在小树林的三分遮挡下，色心渐起，伸出手，想要将手搭在韩双双的肩上，若她没有反应，他就会顺带将她搂入怀中，再在她白花花的胸前捞上一把揩点油。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;脑子里想入非非，他的手就不自觉地抬了起来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;突然，纤尘猛然一个转身，高喊了声“爹爹。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;惊得冉羽涅的贼心七上八下地乱跳，半抬起的手僵在那里，放也不是不放也不是。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘装着什么也没看出来，继续道：“爹爹，我们都叫韩双双姑娘为双双姑娘，你一口一个韩姑娘，我们听着都好不习惯，你还是改口叫她双双姑娘吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“啊？”&nbsp;神经暂时短路的冉羽涅愣了楞，人僵在那里半晌没动。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;好不容易等他回过神来，韩双双已仿若不知的向前走了好长一段路，冉羽涅敷衍地应了纤尘一声，“好，好，为父以后就叫韩姑娘为双双姑娘。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘这才满意地回过头去继续走路。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅抚了抚心口，稳了稳心神又才一路小跑着追上走在前面的韩双双，“双双姑娘这个名字可真真是好听，可有什么来历？”冉羽涅没话找话。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯”韩双双低头，掩嘴发出一声柔柔的低笑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她顺着冉羽涅的话胡编道：“大人英明，还真是被大人给说中了，我出生的时候，一连几日爹爹出海都是大丰收，爹爹说是我的出生给家里带来了福气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;家里海货大丰收，他又得一闺女，好事成双，爹爹便给我起了双双这个名字。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双瞎掰一通，其实她给家里带来屁个的福气，她一出生母亲就死了，自己与爹爹相依为命，爹爹倒是个勤奋的人，她跟着爹爹也没挨过什么饿，不过清苦的日子她也不想再过下去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双人长得漂亮心性就高，一心想要嫁给有钱、有势的人，只是交州那个地方有钱、有势的人就那么几家，他们也看不上韩双双这样的渔民女子，以至于她都过了十八也没嫁出去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双爹爹死后，她和一个外乡来采购海货的商贾不清不楚裹了一段时间，原以为自己就要脱贫致富，从此过上好日子，哪知，那商贾是个怕老婆的主，将他安顿在外面又不敢带回家，她觉得自己飞升无望便又一个人跑回了交州，做起了卖身葬父钓大鱼的营生。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双之所以编那样的瞎话来糊弄冉羽涅，就是因为她明白一个道理，大户人家都迷信，官位越高的人越迷信，谁不喜欢吉利的事？她就是要让冉羽涅以为自己是个能给他带来福气的人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“呵呵……看来双双姑娘还是个自带福气的人儿呀！”冉羽涅很高兴，福气，他可不就是需要点福气吗？最近为交州兵权的事愁得他夜不能寐，他现在就是缺点福气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;情不自禁，冉羽涅的手又开始抬了起来，想拥韩双双入怀，他的手指头还未触及到韩双双的肩膀，纤尘又一转身大喊一声，“爹爹。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘再次惊得冉羽涅的老心脏七上八下地乱跳，手又僵在了半空。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘依旧就当什么都没看出来一样，一本正经地说：“双双姑娘还真是个带福气的人呢，我们在回京的路上全靠双双姑娘的好福气，什么车匪路霸，什么小偷小摸的危险，我们一个都没遇到。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哦，好、好、好，双双姑娘果真是个福星。”冉羽涅万分尴尬，咽了一口唾沫，眼巴巴地看着韩双双向前走去，盼着纤尘快点转过身去走自己的路。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;良辰美景，月朦胧影朦胧，韩羽涅再次快步跟到韩双双的身旁，重复着刚刚说过的话，“双双姑娘看来你真是个福星。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;机不可失，时不再来，已经两次揩油失败的冉羽涅决定这次速战速决，也不再和韩双双废话，抬起手就要去搂韩双双的小蛮腰。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“爹爹。”纤尘再次大喊一声。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哎呀妈呀，纤尘这响亮的一声对冉羽涅来说无疑像一记惊雷，吓得冉羽涅手一哆嗦，老心脏都要蹦出嗓子眼了，好不容易缓口气来，一半无奈，一半不耐烦地问：“你又想说什么呀？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“爹爹。”纤尘忽闪着很无辜的大眼睛，不明白冉羽涅为什么这么不耐烦，无辜地摊开手她道：“爹爹，我们已经到了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“啊，到了，这么快？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不是说给纤尘安排的院子偏远吗？怎么这么快就到了？冉羽涅很无奈，很沮丧，接着月亮柔和的光，纤尘仿佛能从冉羽涅的眸子里看到无比的失落。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她莞尔一笑，暗自腹诽那我就让你再失落些吧，“爹爹，母亲安排过来的两个丫鬟估计现在也已经睡下了，爹爹这个时候进院子恐怕有些不便，爹爹还是早些回去吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉女涅怎么会听不懂纤尘的话？女儿这是下了逐客令，姚氏又安排了人在这个院子，他即便是进了房间自己什么也做不了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;豆腐呀，白花花的豆腐呀，看得到摸不到心如刀绞！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅憋着蓬发出来的欲、火，心里很是难受，心里想着为什么这个院子不能远点再远点，不能偏点再偏点？要是再远些，再偏些，说不定他就吃上豆腐了，别的不说，韩双双的小蛮腰他总得搂上一把吧？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;悲催，太悲催了，他妈的，这个是什么事？一路上他连韩双双的手都没有碰到过，冉羽涅非常懊恼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他不知道自己今天是倒了什么霉？为什么他每次伸出手要去搂韩双双时，每次纤尘都能精准无误的打断他？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;因为纤尘的憨货模样，冉羽涅当然不会想到，纤尘是故意坏他好事的，他只觉得自己今天太倒霉！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的耳朵极其敏锐，每每她察觉到冉羽涅和韩双双他们的对话停顿中有异，纤尘就猜出了他这个渣爹想要做什么。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他想做，她偏不随了他的愿，故而每次纤尘都在冉羽涅想要揩油时及时转身阻止，关键她每次阻止得还恰到好处，这是纤尘自己都没想到的，她暗自佩服了一下自己又深深感谢了一盘自己那风华绝代的严师。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“老爷，我回去了，空了再与老爷聊家乡的事。”韩双双向冉羽涅福了一礼便进了屋，临走时还不忘再电上冉羽涅一眼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;抓心挠肺，心如猫抓。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;痒、痒、痒……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“好，你们也早些休息，双双姑娘改日我得空再来找你聊聊家乡的事。”冉羽涅眼巴巴地看着韩双双进了院子，万分不舍的怏怏离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈对着冉羽涅离去的背影啐了一口唾沫，嗔骂道：“我呸，聊什么家乡事？这分明就是一只见不得腥儿的老春猫。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅是个很会撩妹的人，要不然，凭他一个穷小子，怎么可能追到交州当时的旺族，沈氏家的嫡女？后来他又怎么能追到姚氏，这个纪武帝最看中的太医之女？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他功利心强，一般的女人他不屑泡，不过泡了不一般的女人，他也只敢在外面花，不敢将女人带回府。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;如果不是他感觉自己，那正二品大行台尚书令的位子已经坐稳，他也不敢在府里就这样明目张胆的和韩双双搞暧昧。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏不能再生孩子才给他纳了庄姨娘这一个妾，庄姨娘对他又十分冷淡，他对她也提不起半点兴趣来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双就不一样了，她年轻、漂亮，还是他的家乡人，临走时她对他放上的那点电，点燃了他心里的小火苗燎原了他的心。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;心如猫挠，痒得难受，冉羽涅只有去姚氏房里解痒，冉羽涅进了姚氏的院子，见到躺在床上的姚氏，肚兜遮体，春光若隐若现，他像只发情的公狗，直接扑倒姚氏身上，嘴里呢喃道：“夫人，我来了，想我了吧？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏一把推开他，“谁想你了，我要睡觉。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“不想我，为何还要跟着我去尘儿的院子里呀？”说着冉羽涅的手就已经将姚氏身上的小肚兜扯下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;小肚兜飘呀飘，床上的人而臊呀臊。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏红着脸，“我……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她一句“我不是没去吗？”话还没说出来，她的唇就被冉羽涅凉薄的唇全部覆盖。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅的舌在姚氏的嘴里疯狂扫荡，手在姚氏的身上疯狂游走，最后两人都满意地互拥对方而睡。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;次日，他们夫妻二人从昨日的满足中醒来，姚氏满心欢喜，他们夫妻之间已经很久没有这般和谐的浓情蜜意过了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;可怜的姚氏，一切都蒙在鼓里，冉羽涅昨晚的浓情蜜意，全是因为韩双双勾起了他的熊熊欲、火。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏羞答答地边替冉羽涅整理朝服，边叮嘱，“老爷，早点回来，妾身等你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗯，你和楹儿也好好准备一下，今天是靖王妃邀请女眷在他们府里游园赏花的日子，不要失了体面。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“妾身不想去，靖王妃邀请女眷们去她府里赏花，无非是想替他家靖王殿下拉些后援，我们的楹儿可是要进康王府的，这靖王妃将请帖给了我们恐怕也没安什么好心。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏嘴一翘，撒起了娇。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“傻瓜，知己知彼才能百战不殆！”冉羽涅竟刮起了姚氏的鼻子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏突然一个恍惚，感觉自己仿佛回到了从前，回到了冉羽涅疯狂追求自己的那个时候。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏还没回过神来，冉羽涅就在她脸上轻嘬一口便离开了房间，一个人先去用早善，赶着去早朝，留下姚氏站在原地久久回不过神来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这时容妈妈端着洗漱的水来到房中，“夫人，夫人今天还要去赴会，老身这就侍候夫人梳洗更衣？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;容妈妈的话将神游的姚氏喊回了魂。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;回过神来的姚氏转身看向容妈妈，脸上竟多了一份女儿家的娇羞，“容妈妈，你快给我梳洗，今天我要梳个特别好看的发髻，定不能在靖王府那群女眷面前给羽涅失了面子，还有我今天要穿那身蜀丝金陵缎水天纹的华服。”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348363, 1334318227182952448, '&nbsp;&nbsp;&nbsp;&nbsp;洗漱梳妆完毕的姚氏，吃了点清粥小菜，便换上了那身华贵出众的蜀丝金陵缎水天纹华服。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;高高的牡丹髻上珠翠缠绕，一只金镶玉的蝴蝶步摇步步生辉，步摇通体用黄金打制而成，唯有蝴蝶的眼睛镶着洁白无瑕的和田美玉，徐徐生辉。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏天生一副好皮囊，三十好几的年龄，风韵依旧不减当年，略施薄粉便是牡丹花开暗香来，深眸似水，眉梢眼角皆是春意，嘴角微勾掩饰不住今天的好心情。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一袭月白蜀丝金陵缎水天纹华服，套在身上曲线优美，端庄大方且富贵逼人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;靖王府里，前年大理国进贡来的大丽花在靖王妃的精心照料下开了花，这次靖王妃特邀朝廷大员的女眷们前去赏花。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪国人谁都知道靖王是纪武帝的嫡长子，是皇后唯一的儿子，他本应该是纪武帝几个儿子里最有可能继承纪国大统之人，可是偏偏纪武帝和皇后都对这个儿子不冷不热。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪武帝更是在云妃生下康王之时，就明确表示过，他会将纪国的将来交给康王。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原本看上去，康王成为纪国未来的皇帝是板上钉钉的事，可是，这些年来纪武帝又迟迟不立康王为太子储君，这就让靖王的心思活跃了起来，他想只要太子之位一日不立，那么他就有机会争取到这储君之位。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;成功娶到镇南将军王的小女儿，是靖王迈向储君之争的第一步。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;靖王这个王妃确实也没让他失望，朝堂上，靖王尽心尽力为纪武帝办事，想尽办法讨纪武帝欢心；朝堂下，靖王妃运筹帷幄，暗地里为他拉拢了不少支持者，就连一向比较佛系，对自己这个儿子不咸不淡的皇后也开始支持起靖王来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;也正因如此，朝堂上才有了两队人马争夺交州兵权一事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;早朝。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅像往常一样向着大殿走去，他发现，今天同僚们看他的眼神个个都很怪异，他在他们的眼神里看到了嘲讽，不屑，轻视，还有幸灾乐祸，当然也有同情。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一些同僚还故意躲他躲得远远的，就像他身子上长了虱子一样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;平日里那些跟他比较熟悉的朝臣，见着他也只是客气地向他问声好便礼貌离开，再也没了旁日里的热络寒暄。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅剑眉紧锁，不知道发生了什么事，抓住一个平日里喜欢贴着他的一个底品级的官员问：“姜大人，你们今天都是怎么啦，大家为什么都躲着我，是我身上哪里有问题吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;怎么啦？姜大人一愣，冉府的传言在大街上传得沸沸扬扬，这冉大人还问自己怎么啦？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姜大人觉得冉羽涅真是糊涂得可以，不过自己官位太低，他也不敢将大街上的传闻说给冉羽涅听，毕竟这是冉大人的家丑，俗话说“家丑不可外扬”，自己今天好心说给了他听，万一事后冉大人觉得自己知道了他的家丑，给自己穿小鞋怎么办？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;于是，姜大人向冉羽涅拱手行了个礼，客客气气道：“下官也不太清楚，冉大人还是去问旁人吧！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不太清楚？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他用什么不太清楚来敷衍自己？冉羽涅心火上蹿，闷哼一声“哼！”便拂袖而去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他知道姜大人在敷衍自己，他也知道再问旁人，结果也是一样，索性也就不问了，甩一甩袖去了朝堂大殿。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天的早朝无一例外，主题还是讨论交州兵权花落谁家。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一队亲镇南大将军的人马和一队亲九殿下的人马，这些天来为了交州兵权究竟是交给镇南大将军还是交给九殿下，已经在纪国的朝堂上争论了好些日子，<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这一话题，已经成了每天早朝必争的热点话题。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;日早朝开始。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;朝臣门向纪武帝高呼几声万岁、万岁、万万岁后，便是总管太监李公公一如既往，一成不变地捏着嗓子高喊：“有事启奏，无事退朝”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅依旧向往常一样第一个列队而出，向纪武帝行了一礼道：“禀皇上，老臣……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我呸，你个冉羽涅，你回去把你家里的那点破事弄好了，再来管朝堂之事。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一位五品的定远将军，还没等冉羽涅将他要禀报给纪王的话说出来，就粗爆地打断了他的话。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这个定远将军姓李，在战场上是员猛将，长得像李逵，虎背熊腰，满脸横肉，剑眉浓密，两只眼睛又圆又鼓，像镇宅的门神，自带几分杀气，让人望而生畏。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此人深受镇南将军王的器重，是个不怕得罪人的主，他虽是个五品将军，也没将比他官位高好几个等级的正二品文官放在眼里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他确实也不必将冉羽涅放在眼里，他的后台可是纪国特封的一品大将军镇南将军王，背后还有皇后替他撑腰，他怕冉羽涅个鸟毛呀？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅突然被怼，一时没反应过来，随口就问：“你这话什么意思？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哈哈哈……什么意思，看来冉大人还不知道呀，看来你也是一个糊涂蛋，你家那点破事大街上都传开，你还问我什么意？”这位李将军嗓门本就大，他再这一哈哈大笑，朝堂上就只听到他的声音。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;有个想偷偷提醒一下冉羽涅的官员，他的声音被李将军的高亢的嗓门声淹没，冉羽涅也只是看到了他的嘴在动，却听不到半个字来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;接着，就听道这位五大三粗的李将军文绉绉地冒出句“欲治其国者，先齐其家；欲齐其家者，先修其身；欲修其身者，先正其心；欲正其心者，先诚其意。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;话说至此，李将军一手插腰，一手大拇指在鼻尖擦过，从鼻子里喷出满含鄙视轻蔑的气息。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哼……！你冉羽涅靠着前夫人的帮扶才考取了功名，有了功名却将前夫人丢弃在交州老家，这是不仁；前夫人死后，前夫人所出的嫡女也被你丢到交州前夫人的娘家里，不管不问就是十几年这是不义；像你这样一个不仁不义，见利忘义的小人，就是无诚无意更无心之人，无心之人身不正，身不正之人如何有资格管理朝堂之事？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;错愕，一个大脑粗将军，今天竟然能如此条例清晰的将冉羽涅数落一番，真是让人错愕。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅没想到自己家里的那点破事都传到朝堂上了，一时羞愤的哑口。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;很显然，这番说辞是有人事先与李将军商议好的，要不然凭他那只会耍大刀的脑袋，怎么也想不到用这么文绉绉的方式来怼冉羽涅，还怼得他哑口无言。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅可是九皇子最得力的助力，将他怼翻，九皇子在朝堂上的势力就会大大减弱。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;朝堂上若冉羽涅倒了，这交州兵权不消几日便会落入镇南将军王之手，兵权落入镇南将军王之手，其实就相当于落入靖王之手。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;亲靖王的那些朝臣们像是得到某种信号般，齐齐开始攻击冉羽涅，弄得冉羽涅灰头土脸，恨不得在这朝堂之上找个地缝钻了进去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅万万没想到，冉纤尘这次回府之事，竟被朝堂上有心之人给利用了，她这次回府也给自己带来了前所未有的危机。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;当然，亲九皇子一边的朝臣也不是吃素的，大家也齐齐帮着冉羽涅说话，一时间交州兵权这个热点竟然被冉羽涅的家务事替代。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅在朝堂上还有人帮着说话，然，他的夫人在靖王府就孤立无援了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏今天盛装打扮去靖王府赏花，花楹知道康王不喜欢靖王，她怕康王多心，便没有陪同自己母亲一起去靖王府，而是将姚氏送到了靖王府门口，自己便去了姚家药铺。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;虽然靖王妃向四品以上的官员家眷都发了请帖，然，来的家眷都为在朝堂上支持靖王的朝臣家眷，支持康王那些朝臣的家眷为了避嫌都没来，姚氏的出现就成了她们唯一的一个代表。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏今天一身华服艳压群芳，就连比她年小十来岁的靖王妃都被她比了下去，引来众家眷的羡慕嫉妒恨。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这世上，总少不了一些喜欢邀功出头挣表现的人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一个夫人啧啧嘴道：“啧啧，这就是朝堂正二品大员的夫人？穿着一身华服，珠光宝气不知道的还以为是在她的府里赏花呢！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;酸真酸！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏深吸一口气故做镇定，强展出她那白莲圣母般的微笑正要开口解释，却又听见另一个夫人道：“谁说不是呢？不过人家是康王未来的丈母娘，自然要打扮得与我们不同。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不给姚氏开口的机会，一个夫人接着又说，“康王的丈母娘又怎么啦？丈母娘能胜过王妃吗？你们看我们的靖王妃多朴素，人家还是镇南将军王的女儿，她不过是个太医的女儿罢了，不就是自己的女儿和康王定过亲而已，就能把她显摆成这样？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“呵呵……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一个清脆的年轻女子的笑声突然传来，“听说姚夫人还只是冉府里的二夫人呢。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那女子的这句话就像是点燃导火索的火星子，瞬间就在这群女人堆里炸开了花。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;沈氏当年入府的事，知道的人不多，即便有些人知道，那也是捕风捉影到一些零零碎碎的东西，哪有昨天街上传的那么有内涵？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天，姚氏这个当事人在这里，这些妇人们难免不八卦。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我说姚夫人，你们当真将先夫人所出的嫡小姐丢在乡下不管不问十来年吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏脸上一僵，她没想到纤尘回府的这点破事，连这些常年呆在后院里的妇人们都知道了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看姚氏不说话，又有人开了口，“听说你们将先妇人所出的长嫡小姐丢在交州舅舅家，一丢就是十来年，一分钱也没给人家寄过，这是真的吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“啧啧，我还听说，冉府先妇人所出的那位嫡小姐，为了生计只能去肉铺子里跑堂？真真是可怜，他可是朝廷正二品大员的长嫡小姐，怎么沦落去给人家跑堂了？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“啧啧，谁说不是呢，没亲妈有后娘，哪怕是个嫡小姐命运也堪忧哟，真真是一个可怜的丫头。”又一个夫人符合着说。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;……', NULL, NULL);
INSERT INTO `book_content` VALUES (3348364, 1334318227887595520, '&nbsp;&nbsp;&nbsp;&nbsp;妇人们自说一片，七嘴八舌，完全不给姚氏说话的机会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏好是无奈，几次想要澄清，想要为自己辩解，这群妇人又都将她当成透明的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她们嘴里一口一个先夫人，一口一个嫡长大小姐，听的姚氏刺耳。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此刻，姚氏怒火中烧，血气上蹿，若这里不是靖王府，她定会撕烂那些个妇人们的嘴。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏知道今天靖王府不是久留之地，她忍着怒火，强挤出一个笑来，皮笑肉不笑，向靖王妃福了一礼，“王妃，臣妇偶感风寒，身子不适就先告辞了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见姚氏要走。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“呵呵……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那个清脆的年轻女子的笑声再次传来，“冉夫人这就要走了吗？我听说当年皇上御赐的订婚，好像是说，将冉府嫡女嫁给康王殿下做正妃，这下冉府有两个嫡女，不知道康王殿下最后会选择谁呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说话的这个女子不是别人，正是冉花楹的情敌，邵婷婷。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;邵婷婷是御史大夫之女，一直暗恋顾子琛，顾子琛对她却视而不见，她便对冉花楹怀恨在心。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;女人的妒嫉心就是这样莫名其妙，总是喜欢自以为是，以为自己喜欢的男子，他们的身边若没了其她的女人，他便会爱上自己，殊不知，若那男子不喜欢你，即便天下的女子都死绝了，那男子依旧不会爱上你，即便你们之间有了更深入的交流，对那男子来说，也不过是满足一下生理上的需求，要知道，男人是上半生和下半身可以分开思考的神奇生物，他心里没有你就是没有你，倒贴都没用。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;爱而不得的邵婷婷，好不容易逮着这个机会，就想着给冉花楹添添堵。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;涉及到自己女儿，姚氏那白莲圣母的形象也不再维持下去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她讥笑地看了看邵婷婷，“邵小姐，无论康王殿下选择谁，那御赐的正妃都是我们冉家的女儿，都和邵小姐没有半个铜板的关系，邵小姐就多操心一下自己的婚姻大事吧，我听说，你倒贴想爬上九殿下的床，却被九殿下一把丢出了门，看来你不仅永远也入不了九殿下的眼，估计以后想要再嫁人也难了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;自己那不堪的过去被人再次提起，邵婷婷瞬间就涨红了脸，噎得一时半会说不出话来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;其实，大家都知道九殿下顾子琛很喜欢冉花楹，邵婷婷也知道，她这样说不过是想恶心、恶心一下姚氏，让姚氏心里不痛快；可是没想到，姚氏没恶心成，反而让自己吃了瘪。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏不想与她计较，冷哼一声，“哼！”憋着气，转身就走了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;朝堂上冉羽涅也憋着气，可是他却是想走都走不了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪武帝顾昊天高高坐在龙椅上，看着台下的朝臣们打口水战，这些天，他听朝臣们争论交州兵权之事，耳朵里都听出了茧子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;好不容易，今天的朝堂上别开生面，没再争论交州兵权一事，纪武帝也起了看戏的好兴致。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;文武百官开始还左右分列而站，这会子，他们为冉府的那点丑闻吵得已乱做了一团，真是做到了你中有我，我中有你，大家互怼互掐，个个争得面红耳赤好不热闹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪武帝自始至终一言不发，津津有味地看着一场猴戏。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;自从飞鸽将顾子毅剿灭东阴人，挖出纪国两个吃里扒外勾结东阴人的蛀虫，这两条蛀虫又双双服毒自尽的消息带回京都后，京都朝堂就炸开了花。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;很长一段时间，纪武帝的耳朵里，都一直充斥着两股势力争夺交州兵权的声音。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;交州县令张赖强和交州海防将军曹武勇双双服毒自尽，交州的军政大权就空了出来，这县令一职无人争抢，然，这交州海防将军一职，却让这两股势争夺的火如荼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这第一股势力，自然是以亲镇南将军王苏奎岚大将军一派的朝臣，他们集体上表朝堂。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;要求纪武帝，将交州兵权交给苏奎岚大将军安排。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;理由是，苏奎岚大将军常年镇守南疆对海防这一块非常熟悉，再说交州本就是苏奎岚大将军的军事管辖区，再交给他管理理所应当。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这第二股势力，是以亲九皇子这一派的朝臣，他们也集体上表朝堂，兵权应该交给九殿下，理由很多，最重要的有两点：<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;第一点，九皇子是统管兵权的皇子，交州兵权交给他理所应当。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;第二点，自然是抓着曹将军就是苏奎岚大将军派去的人，却成了纪国的蛀虫，吃里扒外勾结东阴人这个小辫子不放，坚持拒绝再将交州兵权交给镇南将军王苏奎岚大将军的手里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏奎岚大将军也提出将功补过的方案，说自己愿意亲自驻扎在交州，弥补交州百姓，还交州百姓一个平安。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不过他这个方案还是被反对方驳回了，他们说南疆是交州的门户，苏奎岚大将军若离开了南疆营地，南疆的门户将变得薄弱，对纪国的边防维护不利。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天难得耳根子里没再被塞入兵权的声音，纪武帝心情大好，饶有兴致地看着台下大臣们的口水战。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一双老谋深算，洞悉一切的眼睛慵懒地微眯，嘴角勾出一抹不明深意的浅笑，良久，他才向总管太监李公公招手说了句“散了吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;总管太监李公公面带微笑向纪武帝深鞠一躬，接着他手里的浮尘一挥，捏着嗓子一本正经严肃高喊道：“退朝。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;众大臣闻声“退朝”又才反应过来，还有交州兵权一事未议，无奈纪武帝已经离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;皇帝都走了这群大臣们还在争吵，半晌才三三两两悻悻离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅离得快，动作快得像只老鼠，灰头土脸“嗖”的一下就蹿上了自己的马车，回了冉府。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;关上冉府的门，冉羽涅心中的怒火再也忍不住爆发了起来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏先他一步回了冉府，一个人坐在雅兰院正生着闷气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;雅兰院是冉府会客、聚会、用餐的正院，正对冉府大门，与冉府的大门就隔着一片绿院，此刻，雅兰院里能摔的东西都被姚氏摔了个干净。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅来到雅兰院，想拿东西摔都找不到可摔的东西，干脆对姚氏怒呵道：“你这是在发什么疯？有你这样败家的娘们吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我败家？我败家那也是因为你生了个好女儿，老娘的脸都被你那个好女儿给丢尽了，脸都没了这家败了也就败了！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏那火爆脾气一上来，根本就没将冉羽涅当回事，姚氏嚷嚷了半晌，将自己心里的怒火全发泄在了冉羽涅的身上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在吵架上，大部分的男人先天是不占优势的，冉羽涅就是那种勾心斗角还可以，一吵架就嘴笨的男人，他心里也有气，被姚氏噼里啪啦骂了一通后，心里的火气上拱，压都压不住。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;呀……！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅一张成熟的俊脸涨得通红，脖子上的青筋也涨得暴突，一股脑儿地将雅兰院的桌椅板凳掀了个干净。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;涨红了脸的冉羽涅，连带着他的眼珠子都布满了血丝，那模样像是要吃人，真是让人害怕极了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏还是第一次见冉羽涅发这么大的脾气，她身子一颤，嚷嚷的话也停了下来，心里七上八下，手里也哆嗦地卷着绢帕，战战兢兢地问：“老，老爷，老爷，你，你今天是怎么了？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅怒吼，“去把冉纤尘那个孽障给我叫来！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏一愣，缓了缓，正准备抬脚离去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这会子，两位去罗大人、王大人、赵大人、文大人几位大人府里发请帖的丫鬟进了雅兰院。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这两个丫鬟一大早便得了姚氏的命，去那几位大人家发请帖，姚氏要邀请那些大人府里的夫人们前来做客，没想到这两个丫鬟拿着请帖是尽兴而去,败兴而归，她们是一路吃着闭门羹回到冉府的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这两个丫鬟没长心，着急复命，直接闯进了雅兰院，进了雅兰院才发现老爷和夫人正在发脾气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;两个丫鬟想要退出雅兰院已经来不及了，姚氏已经看见了她们，“怎么会事？你们手上怎么还有请帖没发出去？”姚氏问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那两个丫鬟后悔不已，都怪自己没长眼，在这个时候进了雅兰院，忙跪下回话，“夫人，那些大人府里的夫人们，避我们都像在避瘟神一样，谁家也不愿给我们开门，守门的小厮都敷衍我们说最近他们府里的夫人忙都走不开身。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这两个丫头心里都在犯嘀咕，小心谨慎的回着话，深怕老爷和夫人的怒火殃及池鱼，自己无端招了祸。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅越发的生气了，“我说的话你都没听见吗？去把冉纤尘那个孽障给我叫过来！”他瞪向姚氏。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏则对那两个丫鬟道：“去把大小姐带过来。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅那双布满血丝的眼睛带着阴冷的煞气，吓得两个丫鬟身子一颤，战战兢兢连滚带爬，爬出了雅兰院，姚氏在后面提醒，“大小姐在老夫人的院里。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天，姚氏一回来就要去找纤尘，想要问她在京兆尹胡说八道了些什么？无奈，老太太一直护着纤尘，不让她出院子，姚氏才一口恶气，一直憋在心里。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348365, 1334318228588044288, '&nbsp;&nbsp;&nbsp;&nbsp;这下好了！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏估摸着，冉羽涅也是因为冉纤尘而生气，有冉羽涅替她出手教训冉纤尘，她也乐得轻松只需顺着形势煽风点火不怕那冉纤尘不脱层皮，姚氏憋闷了一天的坏心情现在也舒服多了，深邃的眸子里有抑制不住的幸灾乐祸。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那两丫鬟去老夫人院里叫了冉纤尘，没想到的是，那个平日里几乎不出院子的老太太，今天竟然也跟了来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“涅儿，怎么今天发这么大的火，可是发生了什么事？”老太太在纤尘和薛妈妈的搀扶下已经到了雅兰院门口，拖着嗓子问冉羽涅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅到底是个孝顺的人，见到自己老母亲前来，先忍了自己心头里的怒火，忙前去搀扶老太太，“娘，您怎么出来了，你的腰不是还痛着吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“今天好多啦，尘儿今个儿一大早就来给我按摩，我的这把老骨头被她按来捏去，没多会，就感觉轻松多了，腰也不那么疼了，就想着出来走动走动。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;雅兰院里，唯有刚刚姚氏坐着的那把椅子，还可以坐人，冉羽涅将老太太扶到那椅子上坐下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太坐下，还没来得及说话，就见冉羽涅一把抓住纤尘的衣服领子，将纤尘像提小鸡仔一样提了起来，嘴里还不停地念着“孽障呀，孽障，我怎么就生了你这个孽障？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说着，他扬起手就是一巴掌扇在冉纤尘的脸上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这一巴掌，扇尽了冉羽涅和冉纤尘的父女情，纤尘捂着脸，没有哭，甚至她的眼里连泪花都没有，淡淡然，看不出她眼底装着什么。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘知道，现在还不是她暴露自己的时候，她得忍，总有一天她会毁了整个冉府，她要让冉羽涅跪在娘亲的坟头前忏悔。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见纤尘憨乎乎的连哭和求饶都不会，冉羽涅的火气更重了，他随手拿起一个刚刚被他摔断了腿的板凳就要往纤尘身上挥去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说是迟，那是快。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太“噗”的一下就扑到纤尘身上，用自己瘦弱而苍老的身体护着纤尘，嚎啕大哭。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“作孽呀，作孽！我的尘儿如今都变成这个样子了，冉羽涅你还忍心打她？你的心怎么这么狠呀！我老婆子上辈子是做了什么孽，这辈子生了你这个畜生？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“娘，你不知道，这个臭丫头在外坏我名声，我今天不好好教训她，她就不知道什么是家丑不可外扬。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘被老太太护在怀里，冉羽涅无法再下手，气得只能对下人大喊，“来人将老太太拉走。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一群婆子丫鬟掰手的掰手，拉扯的拉扯，死拉活拽强行将老太太和纤尘拉开。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看到祖母如此维护自己，纤尘动容，祖母是她在冉府唯一的温暖，纤尘笑着对老太太说：“祖母，我没事。”说完，她就昂着头直视着冉羽涅，心里想着打吧，冉羽涅你打得越凶，我报复起来才越没有罪恶感。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;眼看冉羽涅又要向纤尘下手，韩双双和苏妈妈突然赶到。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“冉大人，冉大人，大小姐究竟犯了什么错，你一回来就要打她？你是不是也应该给大小姐一个解释的机会，这样不明不白被打，叫人于心何忍，她到底是先夫人留下来的唯一一个血脉呀！”韩双双说着就走到了冉羽涅面前，眸子里泛起了我见犹怜的泪花花，看得冉羽涅一阵心痛。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双和苏妈妈的出现让人意外，更让姚氏不悦，“韩姑娘，这是我冉家的家事，姑娘怕是没资格问。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哼！”苏妈妈向着姚氏冷哼一声，“大小姐是健健全全从沈家出来的，要是她有个什么事，你叫我们回去如何向沈家交代，我们怎么就没资格问啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏剜了眼苏妈妈，心想沈家，一个穷乡巴佬算什么东西？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这会子老太太也跟着道：“涅儿，你把话说清楚了，尘儿怎么外扬家丑啦？你说说，也让尘儿说说，如果你今天不把话说明白了，你若再打尘儿就将我这个老婆子一并打了吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“娘你……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅只觉得一阵头痛，他捏了捏太阳穴，对纤尘怒道：“孽障，你还不跪下。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;现在自己还要借居在冉府，她不得不服软，纤尘捂着脸，噗咚一下跪了下去，“爹爹，昨天还好好的，怎么今天就要打尘儿了，尘儿究竟做错了什么？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘看起来很无辜。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你……”看到纤尘这憨乎乎的模样，冉羽涅心里又是窝火，又是堵得慌，强忍着怒火颤着声音问：“我问你，你昨天怎么就进了京兆尹？你在京兆尹里都说了些什么？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我找不到回冉府的路，就问了一下城门口守门的士兵，那守门的士兵，说我是冒充朝廷大员家眷的刁民，当即就要把我绑了送京兆尹，还是一位郡主帮了我，那郡主替我们说了话，我们才没被绑着去京兆尹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;进了京兆尹，我自然实话实说不敢撒谎，还全靠那位郡主去通知了爹爹，爹爹才知道尘儿在京兆尹，才将尘儿接回府，我在京兆尹可没说半句假话，不信，你可以去叫京兆尹的大人来对质。”&nbsp;纤尘说得愚直。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;对质，对什么质？这种事还嫌脸丢得不够吗？冉羽涅瞪了纤尘一眼，转而他又想到一件事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;昨天将此事告诉他们的可是忠武将军的女儿夏伊人，那郡主又是谁？冉羽涅眉头一皱，“郡主，什么郡主，你说是个郡主来通知我的？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;难道不是灵曦郡主来通知冉羽涅的吗？那又是谁来通知的？怪不得她会在京兆尹里等了那么久，冉羽涅才来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘摇摇头，“尘儿不知道，尘儿只听那些大人们叫他灵曦郡主。”纤尘顿了顿，故做若有所思的模样，疑惑地问：“冉府离京兆尹并不远，为何爹爹让尘儿在京兆尹等了很久很久呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅若有所思，他想到退朝后，一些同僚告诉他，昨天，灵曦郡主就是站在宫门外找他，见人就说有很重要的事找冉大人，让大家将冉大人的女儿在京兆尹的事转交给冉大人，为何那灵曦郡主不来府里找自己，偏偏要去宫门外找人传话？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅觉得灵曦郡主是故意的，其心叵测。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他又看了眼跪在地上的纤尘，心想，人押去了京兆尹，京兆尹的陈大人没有不审的道理，指不定京兆尹问什么她就答什么，她在京兆尹的如实所答，就被有心之人利用，借此来故意打压自己。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;想到这里，冉羽涅青筋直冒，太阳穴突突的痛，懊恼自己怎么就没早些去京兆尹将她给接回来，让京兆尹里的人将他家的黑历史都问了个底朝天，偏偏他这个女儿又是个憨货，不知道撒谎绕弯子，就这样被人给利用了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他懊恼自己更气灵曦郡主，更头痛那个灵曦郡主，他不知道灵曦郡主为什么要故意给他使坏；但是他知道这个外姓郡主他惹不起。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;灵曦郡主何许人也？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她是曾经的西北将军王，司徒将军嫡出的小女儿司徒灵曦。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪国曾经有两大猛将，一位就是皇后的哥哥镇南将军王苏奎岚，一位就是灵曦郡主的亲爹司徒冷，这两位都是手握重兵战功赫赫之人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;边疆无战事后，司徒冷便将自己手里的十万兵权毫无保留地交给了纪武帝，并告老还乡，哪知，皇上舍不得司徒冷走，对司徒冷情深意重，不仅给了他封地还给他封了王，她的嫡女也享有郡主的称号。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这个师徒冷虽然早已不过问朝事，整天呆在家里成了个闲散王爷；但是纪国朝堂之上无人不知无人不晓纪武帝对他有多看中，冉羽涅心里有杆秤，他不敢贸然去得罪这个闲散的外姓王爷和他的女儿。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;唉……！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅一声叹息，都怪自己这个女儿是个憨货，要不然也不会让人钻了空子去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;再看冉纤尘现在这个憨模憨样的样子，冉羽涅又觉得有些愧疚，事已至此，打一个憨货也无济于事，他挥挥手“罢了，罢了，你回去吧，这几天不要让我再见到你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘起身离去，苏妈妈和韩双双也跟着离去，老夫人也被搀扶回了自己的院里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;最失望的要算姚氏了，她以为冉羽涅发那么大的脾气，即便不把冉纤尘打死那也要让她脱层皮吧？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;结果很让姚氏意外，这个冉羽涅雷声大，雨点小，一个巴掌就结束了，姚氏心有不甘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“老爷，你看，那些个大人的夫人们将我们的帖子都退了回来，这分明就是不给老爷面子……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏还想挑拨些什么，就听见冉羽涅深叹了口气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;唉……！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他有气无力地摇了摇手，“她们不会来了，她的婚事你自己看着办吧。”说罢冉羽涅就出了雅兰院去了书房，将自己关进了书房里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;没让冉纤尘脱层皮，姚氏心里虽有不悦；但是想到冉羽涅将冉纤尘的婚事交给了自己，也庆幸老天都在帮她，要是此刻冉羽涅回头，一定能从姚氏的眼里看到一丝狠毒和阴谋。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉纤尘闹上这么一出，现在好人家的公子谁还敢要她？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;把她嫁给自己那个傻侄儿，就成了顺理成章的事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;当天下午，姚氏就迫不及待派小翠去了一趟小姚大人的府邸，邀请她的堂嫂明天过府一趟。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;若不是碍于冉羽涅在家，姚氏现在就想将她那正四品中书侍郎堂哥姚显之的媳妇谢氏给叫过来，与她商量他家那个傻二娃娶亲的事。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348366, 1334318229301075968, '&nbsp;&nbsp;&nbsp;&nbsp;姚氏这个表嫂名曰谢丹梅，出生名门，家里只有她一个女儿，被父兄疼着长大，没什么心计，与姚氏表哥也算是青梅竹马从小一起长大，两人感情极好，膝下有两子一女，其中一子是个傻子，即便是这样，姚氏那个堂哥姚显之依旧爱她如初，至今没有纳妾，这也是姚氏最羡慕这个堂嫂的地方。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;次日，一大早谢氏就过了府。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;昨日，她得知姚氏想将冉家的嫡长女冉纤尘嫁给她那个傻儿子，早就乐得合不拢嘴，早就想赶快过来见见这个未来的儿媳妇，想着两家早早将婚事定了免得以后夜长梦多。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不管怎么说，他儿子也是个嫡子，即便自己儿子是个傻子，谢氏也固执的认为自己这个嫡子应该配个嫡女，如今配的还是朝堂正二品大员的嫡女，这能不让她开心不着急吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢氏心里欢喜，今天将自己刻意打扮了一番，毕竟是已经生了三个孩子的女人，谢氏的身材有些发福，皮肤白皙，柳眉杏眼，眉间嘴角挂得都是欢喜，一身绛红锦缎华服，富态雍容。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“好妹妹，妹妹有心了，外面都在传冉府那个嫡长女有点丑，可否叫她先过来一趟，让我看看她的模样？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢氏来得太早，姚氏还没来得及吩咐下人去将纤尘打扮一下，她就来了，于是便糊弄地打着哈哈道：“哈哈哈！嫂子，你看我家楹儿跟个天仙似的，她同父异母的姐姐能丑到哪里去？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;我们家那个冉纤尘呀，人长得一般，不招摇，是个心善的孩子，正合适你家二娃。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;再说了，像咱们家二娃那样的公子，若真娶了个长得漂亮的仙女，那也不安全，你说对不对？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他呀，就是需要一个像我家冉纤尘那样的，心地善良，任劳任怨的姑娘做媳妇，她婶子你说是不是？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏巧舌如簧。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢氏心性简单觉得姚氏说得也不无道理，“对，对，姚妹妹说得对，多亏了姚妹妹替我家二娃着想。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她拉过姚氏的手，将姚氏的手紧紧握在手心里，满心感激，眼眶莹润的全是饱含感激的泪花花，“真是谢谢玉儿妹妹了，你叫我说什么好呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此刻，谢氏是打心底感激着姚氏。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢氏为自己那个傻儿子是操碎了心，满心的心酸无人能懂，她就盼着能有个心地善良的姑娘能替她好好照顾自己那个傻儿子，百年之后她也可以了无牵挂地埋进土里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见谢氏对自己千恩万谢的模样，姚氏就想，这嫂子还真是个没长脑子的人，好糊弄，她就不明白了，自己那个堂哥仪表堂堂怎么就看上了眼前这个什么都不出众的女人？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏一直就嫉妒她这个堂嫂子，嫉妒她什么都不出众却有男人视她如珍，如宝，爱她如初？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她在心里狠狠将谢氏鄙视了一番，脸上却依旧挂着她那白莲圣母般的微笑，“嫂子若没问题，我们就挑个日子将亲事给定下来吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢丹梅虽然脑子不够聪明；但是，她却是个细致的人，“妹妹，还是将冉家嫡长小姐叫出来让我看看吧，这样我心里也踏实些。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;婚姻之事讲究父母之命媒妁之言，虽然姚氏很想将冉纤尘嫁给她那个傻侄儿，不过那也要对方的父母同意不是？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏本想先糊弄谢氏将婚事定下来，人家非要先见冉纤尘，姚氏也没话说，于是，她对容妈妈使了个眼神，吩咐道：“容妈妈去将大小姐叫过来吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏的眼神是什么意思？容妈妈自然是懂的，夫人的意思就是要她将冉纤尘好好打扮一番再带进来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;容妈妈刚退出雅兰院，就看见纤尘端了一个盖着三个盖子的托盘过来，她赶紧上前阻止，她不能让纤尘就这个丑模样进了雅兰院。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;大小姐现在这个丑模样定会吓到谢氏，到时候夫人的如意算盘就会落空，容妈妈小跑着来到纤尘面前，伸手一拦，“你不能进去。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;容妈妈气势逼人，一身横肉挡在纤尘面前，大有一夫当关万夫莫开的架势，纤尘也不恼，她笑嘻嘻地看向天，“容妈妈你看天。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;天有什么好看的？容妈妈迟疑，然，她还是忍不住抬头望了望那碧蓝如海的天空，突的，容妈妈只觉膝盖一疼再又一麻，噗通一下，她不由自主的就跪在了地上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“容妈妈，没想到你还会给我行大礼呢，起来吧，我要去见母亲，手里又有东西就不扶你了。”纤尘说完头也不回便向着雅兰院走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;容妈妈倒是想起来，可是现在她起不来呀，膝盖又疼又麻，她只能跪在地上嚎嚎，“夫人正在和堂夫人说话呢，你不能进去打扰。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘脸上闪过一抹邪笑，就在容妈妈抬头望天的时候，她精准地向容妈妈的膝言穴上弹去了一颗小石子儿。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;膝言穴受创的容妈妈，不在这里跪上一炷香的时间她那个膝盖怕是起不来，旋即，纤尘脸上那抹邪笑就消失得无影无踪，若无其事地端着托盘就进了雅兰院。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“母亲，听说来客人了，我是来给你和客人送吃食来的。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉纤尘怎么这个样子就进了雅兰院？姚氏心中不悦，黛眉紧锁，“尘儿，你怎么来啦，容妈妈呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“容妈妈在外面呢，我听说母亲在帮尘儿找婆家，尘儿就想着过来看看，我还带了极好的美食，过来孝顺母亲，感谢母亲为我操劳替我找婆家。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;接着，纤尘又转而看向谢氏，“母亲，这位夫人就是母亲为尘儿找的婆家吗？她就是尘儿未来的婆婆吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢氏见了纤尘的丑模样，十分嫌弃，她丑且不说，看她那又黄又黑的肤色，就像是得了什么怪病一样，看得谢氏赶紧拿出绢帕掩着口鼻，深怕有什么病不小心过给了自己，一张不太出众的贵妇脸，眉毛、眼睛、鼻子都皱成了一团。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏拧眉看着纤尘，心想，冉纤尘是怎么知道我在给她找婆家的？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这还多亏了昨日，姚氏派去请谢氏的那个丫鬟月稀和月圆、月缺是好姐妹，（冉府侍候夫人房里的丫鬟赐姓都是月字开头）她见自己好姐妹这些天做了不少重活，心生怜惜，得知夫人就要将大小姐嫁给小姚大人家的傻子了，心里一高兴就马上找到自己的好姐妹将这个消息告诉了月圆和月缺。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月圆和月缺得到此消息后都高兴得不的了，觉得自己的苦日子就要到头了，她们的这番话正好被躲在暗处的韩双双给听了个完整。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双能听到这番话可不是什么巧合。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏安排了两个丫鬟来监视纤尘，纤尘便安排韩双双监视那两个丫鬟，监视与反监视，纤尘想着只要姚氏派来的那两个丫鬟有异，她便能推断出不日姚氏就会对自己有所动作，从而提高警惕，她竟也没想到，这反监视会有这么大的一个收获，给了她一个提前做准备的机会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏见冉纤尘一副恨嫁的模样，心里的疑惑也丢掷脑后，曾经她还愁着，若谢氏那边说妥了，迎亲那天怎样才能把冉纤尘给骗上花轿，如今看来没那个必要了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这丫头已经过了及笄的年龄，长得又这么丑，她怕也是担心自己嫁不出去吧？要不然，这个憨货怎么会突然开了窍，特意来讨好送吃食？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏心中暗喜，转眼又看了看满脸都写着嫌弃的谢氏，打着圆场道：“嫂嫂，娶媳妇娶的是德，你看我们家尘儿多孝顺，二娃不就是需要个贤良淑德的正经媳妇吗，漂亮的女孩多的是，可是像我们家尘儿这样，一个身份高贵又孝顺的孩子哪里去找呀？你看，这孩子多实心眼，第一次见面，就想着亲自给你做吃食了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢氏虽然依旧嫌弃纤尘的丑模样，不过不得不说姚氏说得也有几分道理，她再次看向纤尘时，她那眉毛、眼睛、鼻子皱成了一团的脸，稍稍舒展了些，她依旧用绢帕掩住口鼻道：“你那肤色好怪异，你不会是有什么怪病吧？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;什么都不重要，健康最重要，他们小姚大人的府上，可不会娶一个有病的姑娘进府，谢氏不弯弯绕，直接将自己心里的担忧问了出来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏看了一眼丑陋的纤尘，挤出了一个尴尬的笑来，“嫂子，你这是不相信我喽，我家纤尘若是身体有问题，我还会把她说给你们家吗？放心吧，她身体好着呢，她的脸是被海上的日头灼伤的。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢氏将信将疑，“那就让我们先尝尝你的手艺吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;雅兰院的正厅里，姚氏和谢氏并排而坐，坐在厅里旁侧的椅子上，椅子的中间隔着个放茶水果盘的小桌子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“好的夫人。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘一边应着谢氏，一边将托盘放在姚氏和谢氏之间的小桌上，她先揭开了一个盖子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一盘像屎坨坨一样的东西，蜿蜒盘旋在盘子里，无论是颜色还是形状都像极了一坨新鲜的屎，上面还隐隐冒着热气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏和谢氏看到这盘里的东西，忍不住胃里一阵翻滚，当即就干呕了起来。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348367, 1334318230756499456, '&nbsp;&nbsp;&nbsp;&nbsp;纤尘端着盘子嘴角勾笑，带着三分戏虐和七分憨实的笑，“夫人，这盘吃食是将烤好的红薯，混合着新鲜的猪血，碾泥蒸制而成，它的名字叫‘至始至终’，始通屎字。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说着，纤尘就用手指在那个黄黄的还带点黑黑的软泥上抠下一坨，放进嘴里咋吧咋吧道：“好吃，真的好吃，甜甜的还有点血的香味。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;接着，纤尘又舔了舔手指间那残留的一点点黄色，转而看向姚氏和谢氏，对她们道“母亲，夫人，你们要不要也尝尝？真的很好吃呢！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏和谢氏早已恶心得五脏六腑都如排江倒海般翻滚，二人干呕着，慌忙摆手，“不要、不要、不要……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘又揭开了第二盘的盖子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;当这盘盖子被揭开的那一瞬，姚氏和谢氏顿时就花容失色，吓得“啊……啊……”地惊叫。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘全然不理会她们惊吓的模样，自顾自地说道：“这盘吃食呢，叫‘有苦有甜’。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说罢，纤尘就麻利地将被酒侵泡得二晕二晕的菜花蛇提到了手上，快速对着那条菜花蛇的胸膛破去，开膛取胆。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;蛇胆取出后，她又在盘子旁装着蜂蜜的小蝶里蘸了蘸，将蘸好蜂蜜的蛇胆直接递给了谢氏，“夫人，生活就如同这个蘸了蜂蜜的蛇胆，有苦有甜，蛇胆又是好东西，你吃下它吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘将蛇胆递到了谢氏眼前。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此刻的谢氏哪里还受得住？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“啊……”的一声尖叫，慌乱摆手，“不要，不要，我不要……”如临大敌，连滚带爬，跌跌撞撞跑出了雅兰院。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;旋即，纤尘又看向姚氏，眼里带着深冷的邪气，看得姚氏牙齿都在打颤，“母亲，母亲本事大，上天入地无所不能，尘儿就将这盘‘上天入地’送给母亲。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘揭开了最后一盘的盖子，这盘里一半是地里钻的蚯蚓，一半是天上飞的蝗虫。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;两个物种都是活的，蚯蚓不停地在盘子里扭呀扭，蝗虫被折了翅膀和大腿，在盘子里爬呀爬。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏已经被吓得七晕八素，她也想起身跑出去，跑出这个雅兰院，离纤尘这个疯子远点，可是此刻，她的脚不知为何就是不听使唤，仿佛被什么东西焊在了地上，一动也不能动，更不要说是迈动步子跑了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她偏过头去，不敢去看纤尘，更不敢去看那盘子里又是蠕动又是乱爬的虫子，闭着眼，嘴里大喊着：“疯子，疯子，冉纤尘是个疯子。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;如果姚氏此刻敢睁开眼看看纤尘，定能在她眸子里看到一份彻骨的寒意，稍纵即逝。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“都送给母亲吧！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哈哈哈……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘大笑，带着一丝报复的快意，就像泼水一样，将那盘子里的蚯蚓和蝗虫全数泼到了姚氏的身上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“啊……”的一声尖叫，划破长空，带着内心深处的恐惧与惊吓，片刻，姚氏就被吓晕了过去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢氏冲出雅兰院，像见了鬼一样，发疯似的向冉府大门跑去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;因为跑得太快太急，慌不择路没看脚下，眼看就要跑到冉府大门了，她一只脚在台阶上踩了个空，一个趔趄摔了一跤，五体投地摔了个嘴啃泥。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这会子，跟她一起进冉府的丫鬟小菊才追上了她，慌忙上前扶起道：“夫人，夫人您怎么了，怎么跑得这样急，婢子在后面追都追不上。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看到小菊熟悉的面孔，谢氏的心才稍微稳了稳，她慌忙回望身后，见身后什么都没有这才缓了缓气，正要开口对小菊说些什么，就听见姚氏惊心动魄的尖叫声，顿时心里又是一紧，来不及多说只道：“快，快，我们快离开冉府！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一路跌跌撞撞上了自家的马车，谢氏依旧惊魂未定，边往马车后面望，边吩咐车夫“快点，快点回府。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;马车轱辘转动起来，将冉府远远抛在身后，谢氏才稳下了心神。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“臭丫头，你上个茅房怎么用了那么长时间？”谢氏没好气地瞪了一眼丫鬟小菊。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;小菊埋下头，歉仄地道：“对不起夫人，婢子这两天肠胃不舒服。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢氏不是一个苛责下人的主子，她知道小菊这两天闹肚子也没再埋怨小菊，而是深深地呼出一口浊气后就开始细细琢磨今天的事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;越琢磨，谢氏心里就越气愤，最后她气得一口银牙咯咯做响，恨不能将那姚氏一口口咬碎了去，碎得连一颗骨头渣子都不给她留下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我呸！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;若不是因为在自己的马车上，谢氏真想狠狠的碎上姚氏一口唾沫。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她在心里暗骂，“姚玉儿你个下贱胚子，尽然想将一个疯傻的丫头嫁进我们小姚府，你这分明就是在坑我，我已经有个傻儿子了，若再娶个疯媳妇回来，我这个家还要不要啦？你这个蛇蝎毒妇安的是什么歹毒心肠？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢氏就是个被宠惯了的小女人，心里一有委屈就会掉金豆子，她在马车上强忍着内心的委屈，没有哭出来，眼眶里的泪花花莹润得已经快要溢了出来，刚下马车，她就看见上早朝归来的夫君正好也在门口。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“夫君。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一口夫君一出，谢氏眼里满眶的泪花花就再也忍不住，变成了泪珠儿噗唰唰地直往下落。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏的堂哥，纪国正四品中书侍郎姚显之是个宠妻狂魔，见自家这个小媳妇委屈吧啦的样子满心怜惜，“夫人，夫人这是怎么啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谢氏毕竟也是大家闺秀，她知道即便自己现在再委屈，有些事也不便在门口说，于是只关心道：“夫君怎么今天又这么早下了朝？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚显之贴心地替谢氏擦去脸颊的泪水，“今儿还跟昨个儿一样，大家又揪着冉羽涅的那点家中破事做文章，正事又没来得及说，皇上就走了，我们也就回来了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;两人回到房后，谢氏才将自己今天在冉府发生的事说给了姚显之听。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说完谢氏就问：“夫君，你说，我们家已经有个傻儿子了，那冉家嫡长女不仅丑还是个疯子，你说那姚玉儿这样做究竟安的什么心？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚显之坐在桌边，手指在桌上敲了敲，“丹梅，大房那边的人鬼心思多，我们现在已经独立成府，以后还是少与他们交往的好。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚显之是个有自己主见的人，他在朝堂上从来就不想站队，却因为姚玉儿的父亲是自己大伯的缘故，看在同族的份上，他又不得不在朝堂上支持冉羽涅，支持冉羽涅就是站队九殿下，这下好了，他有了不支持冉羽涅保持沉默的借口。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;被惊吓晕过去的姚氏，直到纤尘放进雅兰院的鸡，将姚氏身上的蚯蚓和蝗虫都吃了个干净才醒来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;容妈妈膝盖无力无法起身，跪在院子外不知道院子里发生了什么，担心着姚氏怒喝着纤尘，“你把夫人怎么，你这个憨货究竟把夫人怎么啦？……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘也不管她，全当容妈妈是只锁在笼子里的狗，反正也碍不了事就等她瞎旺旺。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;从晕死中醒来的姚氏，神志一清醒就赶紧看了看自己的身上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;虫子呢？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那个憨厚泼到自己身上的虫子呢？？？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏发现自己身上完全没有半点虫子的痕迹，她有些恍惚。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;幻觉。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;是幻觉吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她明明记得，冉纤尘泼了自己一身的虫子，现在怎么连半条虫子的影子都没看见？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏不死心，起身掸衣服。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这时，她才发现自己刚刚搭在腿上的左手，手心里湿漉漉的，抬手一看，咿……好恶心，好像是鸡屎。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;自己手上怎么可能有鸡屎？姚氏疑惑，不确定地将手抬到鼻边嗅了嗅，哇，好臭！果真是鸡屎！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏嫌弃地甩了甩手，想都不用想，这鸡屎定是冉纤尘那个憨货干的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她暴跳如雷，目眦尽裂，浑身炸毛，咬牙切齿破口大骂，“冉纤尘，你这个挨千刀的小杂种，你等着，老娘定会慢慢折磨死你，老娘会让你求生不能求死不成，老娘要让你这个死丫头像你那个土鳖娘一样不得好死……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“你在骂什么呢？姚玉儿，我怎么就没发现你还是个市井泼妇？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;容妈吗还跪在院子外，见冉羽涅回来也没法通知姚氏，眼睁睁看着灰头土脸退朝回来的冉羽涅，将姚氏刚刚骂出来的话听了个完整。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅今天又被同僚拽着纤尘那点破事怼，虽然他今天已经有了心里准备，但是，谁被怼心里会不窝火？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他一路窝着火回到冉府，刚进府就听到姚玉儿在泼妇骂街，那沈氏再土，曾经也是他的结发妻子，那冉纤尘再憨那也是他的女儿。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏背后这样骂自己的妻女，冉羽涅的一张老脸还是黑成了炭，双眼冒着火星子，仿佛要将眼前的一切都烧死。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏被突然回府，还怒火中烧的冉羽涅吓了一跳，她自己刚拱上来的怒火瞬间也被吓了回去，立马抽泣了起来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏的眼泪那是说来就来，一副委屈巴巴的模样，哽咽道：“老爷，老爷，你可回来了，冉纤尘她，她……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她抹了一把脸颊的眼泪，本想继续再说些什么，突然感觉脸上一凉，顿感不妙，忐忑地将手抬入眼前一看。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348368, 1334318232153202688, '&nbsp;&nbsp;&nbsp;&nbsp;鸡屎，怎么就忘了，自己手上还有鸡屎？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一阵恶心袭上姚氏的心头，她忍不住胃里的翻滚，打着呕跑出了雅兰院，向洗水池那边冲去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅心烦又将自己关进了书房，他越想越悔。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;早知道会有今天这个结果，他当初就不该同意姚氏的提议将冉纤尘招回府，任由她在交州自生自灭就好了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏将自己的手、脸和身上都统统洗了个干净，换了一身干净的衣服又才向书房走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;进了书房，姚氏就万分委屈道：“老爷，老爷，冉纤尘她，她……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“不要在我面前再提那个憨货，还不是都怪你，你非要让我把她给招回来，这下好了，她一回来，我就成了全朝堂的笑话！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏的话还没说完，冉羽涅就暴跳如雷地打断了她，一抬手还将书桌掀翻在地。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏一惊，知道自己的夫君定又是在朝堂上失了面子，她顾不上诉自己的苦，忙安慰道：“老爷，老爷，都是妾身不好，妾身当初也是一番好意，妾身也不知道她会是现在这个样子，老爷，妾身也悔不当初呀！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏本想上前去安抚一下冉羽涅，就见冉羽涅指着门口对姚氏说：“出去，你出去。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“老爷……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏是真心担心冉羽涅，想陪着他，不过正在气头上的冉羽涅已经快要疯了，对着姚氏咆哮道：“滚……！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏吓得一哆嗦，慌忙、委屈又不甘地离开了冉羽涅的书房。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏心里委屈又觉得今天冉纤尘做的事太过异常，本想找冉羽涅说解说解，却没想到冉羽涅今天就跟吃了火药似的，她什么还没说，冉羽涅就炸了毛。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹虽还未过门嫁给康王，不过她已是铁板钉钉的康王妃，深得云妃的喜欢。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;眼看即将入夏，雨水不断湿气又气重，云妃最近心情烦闷食不下咽，康王知道云妃喜欢冉花楹，那晚，冉花楹在家吃完冉纤尘的接风宴，次日一大早，她就被顾子琛接进了宫，去照顾云妃，陪云妃聊天解闷。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;自己的女儿不在身边被接进了宫，自己的丈夫又将他自己关进了书房里，姚氏想找个说心里话的人都找不到。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;烦闷的姚氏，憋着委屈和怒火躲在自己的院子里默默落泪。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;朝堂之事已经传进了云妃的耳朵，这会，云妃便对冉花楹说：“楹儿，得你这两日的纾解，我的身子已经大好，听说你父亲在朝堂上遇到了点事，你快回家去看看你父亲吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;得了云妃的话，冉花楹又火急火燎地从宫里赶回了冉府。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;回府的冉花楹，第一时间便去看了自己的父亲，她在冉羽涅那里了解到朝堂之事，这会子又来到姚氏的玉兰院。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看到自己女儿回来，姚氏又才找到了倾述的对象，她将今日冉纤尘的古怪行径同冉花楹说了一遍。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;听完姚氏的叙述，冉花楹秀眉紧拧，双手环胸在姚氏的房里来回踱了几步，思考片刻后便对姚氏说：“母亲，听你这么说来，我觉得那冉纤尘定有问题，为以防万一，我们还是早日把冉纤尘打发出去的好。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哎......！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏默然垂头，深叹口气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“我也想尽快将她给打发出去，可是你看她那又丑又憨的模样，现如今谁家还敢上门提亲？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;楹儿，你是没看见，她今天可真真是把你那堂婶吓得魂都要没了，你堂婶这人心眼子小，这次被吓，她怕也是不会上门来提亲了。”姚氏像泄了气的气球没了精气神。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“娘，你是不是只想将冉纤尘嫁给我那傻子堂哥？”冉花楹问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏最是了解自己这个女儿，她的这个女儿是她的骄傲，是纪国上下无人不知的天之骄女，她猛然抬头望向冉花楹，问：“女儿，你可有什么法子？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏这女儿虽然还未及笄，年龄不大心智却异常聪慧，似有颗七窍玲珑心，然，却不然，冉花楹的心不是什么七窍玲珑心，而是颗蜂窝煤心，不仅心眼子多还很黑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“娘，那女儿就帮你把他们生米煮成熟饭，到时候堂婶他们想不要都不行了。”冉话楹说话间，眸子里带着狠戾。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;谁能想到，这样的一句话，是一个还未及笄的女孩子说出来的？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹的脸上是与她年龄不相符的成熟，圆圆的杏眼本应该似泉水般清澈透明不染尘埃，却是一潭寒潭深邃黑暗见不到底。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏看着自己这个摇曳多姿，顾盼生辉，一颦一笑皆是风景的女儿问道：“楹儿，我们要怎么做？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“娘，这个给你。”冉花楹从袖带里拿出个香饼来递给姚氏。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这是一个安睡香的香饼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏接过香饼，凑到鼻前闻了闻，有五石散的味道，顿时心生大喜，看来这个女儿是懂她的，要不然她就不会将掺了五石散的香饼随身带在身上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;五石散，是用钟乳石、紫石英、白石英、石硫磺、赤石脂五种矿石研磨成粉混合而制，故而叫五石散，此药服用后，全身烦热躁动，自己就会宽衣解带想要与异性、交、合，唯有那些意志坚强的人，放可用冷水来抑制体内的燥火。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;五石散是一种春药，试问哪个大家闺秀会将一个用五石散做成的香饼无缘无故带在身上？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚是知道，冉花楹能将五石散带在身上，就说明她早已起了毁掉冉纤尘的心。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;母女同心，姚氏心喜的同时更多的是欣慰。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“接下来，你自己知道该怎么做了吧？”冉花楹无平无仄的声音里，透着浓浓寒意，让人心惊连姚氏都不由自主打了个寒战。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“女儿，你也讨厌她吗？”姚氏看着手里的香饼试探性的问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原本对付冉纤尘这个憨货，她觉得自己一个人就够了，姚氏从未想过将冉花楹牵扯进来，更没有想过女儿会帮她。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“谈不上讨厌，只是她的出现就是个错误，她就不该活在这个世上，我其实是想将这个错误终结；不过看在母亲的面子上，就给她一个活着的机会，让她嫁给我那个傻子堂哥。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;风轻云淡。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一句淬满蛇蝎毒液的话，就这样风轻云淡被冉花楹说了出来，冉花楹就好像在说，今天的天气真好一样这么简单自然。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此话一出，姚氏却是像受到了莫大的鼓舞，欢喜道：“楹儿，你放心，你那个祖母不仅偏心还是个老糊涂，对你那个又丑又憨的大姐姐喜欢得紧，也护得紧，每天叫去与她同吃同行，她认为那冉纤尘天天跟她一起同吃就安全了？娘手里有了这个香饼，看那老糊涂还怎么护那个憨货。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹给姚氏的香饼是掺了五石散的安睡香，只要临睡前将此香饼点燃，五石散的味道挥发在空气中，人吸多了一样能达到春药的作用，若不交、合便浑身燥热难耐。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“楹儿，点燃这香饼不是问题，可是，现在最大的问题是，如何将你那个傻子哥哥弄进冉纤尘的房里？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏心里犯了难，因为她知道谢氏现在一定还在生她的气，一时半会她也登不了小姚大人家的府门。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“这有何难？娘，你忘了吗？康王送给我的那个暗卫？他可是纪国的金牌暗卫，武功了得，去趟堂婶家将那傻哥哥虏来不是问题。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏恍然大悟，突然有一种奸计得逞的快意，“还是我家楹儿本事大，我知道那暗卫，他可是我们纪国一等一的高手，有他办事我也放心。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏脸上洋溢起发自内心的欢喜，慈爱地拉过冉花楹的青葱玉手，在她手上欣慰地拍了拍，“楹儿，康王将他都赏给你了，可见康王有多喜欢你，只要我家楹儿幸福母亲就开心了，这一切就都交给母亲吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;出于一个母亲对自己子女的保护，姚氏还是希望自己女儿的手上能干净些，即便她知道，她这个女儿的手早已不再干净，她手上早已沾了鲜血。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“母亲，这事就交给你了，最近因为交州兵权的事康王有些烦闷，我得多陪陪他。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说完，冉花楹就离开了姚氏的院子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹和姚氏在京都谋划着怎么陷害冉纤尘，同在一个屋檐下的冉纤尘浑然不知，没有半点反应，然，远在交州的顾子毅，却是眼皮突突地跳了几跳，接着就一连打了好几个喷嚏。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿嚏……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“王爷，你是不是染了热风寒，交州不同京都虽还未进五月，晌午却也是酷暑难耐，早晚温差又大，若王爷染了热风寒就缓几日再去西方营地吧。”跟在瑞王身边的魏参将关心道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅摆摆手，“没事，没事，兴许是太阳太晃眼。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿嚏……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;又是一个喷嚏喷出。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅依旧摆摆手，“没事，不防事，那西方营地接壤厉国，是交州的边防重点，有一万八千士兵在那里坚守，我得尽快过去看看他们。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这时，一只白鸽煽动着翅膀噗、噗、噗……飞停在顾子毅一行人面前，顾子毅一抬手，它便停在了顾子毅的手上。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348369, 1334318233612820480, '&nbsp;&nbsp;&nbsp;&nbsp;顾子毅从白鸽的脚上取下信，将其打开，是阿峰的来信，他快速浏览了一遍，剑眉微蹙面露疑惑，随即又是眉心舒展，露出难掩的笑意如一池春水荡开了花。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他们的王爷，何时有过这样春意盎然的笑？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海诧异，心想王爷这一脸的春花开，可都写在了脸上，不用想，此信定是阿峰写的，信里的内容定是和纤尘姑娘有关。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅对纤尘有意，方海还是从阿峰那里知道的。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那日初见，纤尘一袭紫纱罗裙罩身，飘飘似仙，美如画，笑时如百合花开，纯洁高雅，对敌时又如木兰在世，巾帼不让须眉所向披靡，那样曼妙的一个奇女子惊艳了方海的眼。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海向阿峰打听纤尘，阿峰却只回了他一句话，“她是王爷的女人。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;也是，那样一个奇女子，也唯有他们的王爷配得上她，从此方海便将芳华埋葬，埋在心里的最深处不去打扰。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一颗真心祝福着他的王爷和纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“王爷，看你笑靥如花，信里是不是提到纤尘姑娘了？”方海打趣道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“去，去，去，不告诉你。”方海和阿峰即是顾子毅的下属，也是他生死之交的兄弟，面对方海的打趣，顾子毅脸上难掩心喜。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海得寸进尺继续道：“怪不得，我说吗，天天日头都这么大，天天温差也这么大，为啥偏偏今天王爷会连着打喷嚏呢？原来是有佳人在想你了！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;囧……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;好囧！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰的信上只字未提纤尘想他的话，顾子毅一囧，旋即就将信合上，在方海脑门子上敲了敲，“想什么呢？少胡说八道，还不去牵马？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;方海眉眼间露出我懂，我懂，我都懂，我不说就是了，那种让人浮想联翩的坏笑，笑嘻嘻地跑去马厩牵马。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他懂个屁，顾子毅很无奈，看着那个没正形的方海摇头。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;跟了顾子毅一段时间，魏参将对顾子毅也有了更多的了解，他终于明白战神的军团为什么战无不胜，那不仅是因为他对士兵好，更是因为顾子毅军纪严明，公平公正。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;将士不患死而患不公，顾子毅公平对待每一个将士，不偏袒任何一个人，无论是嫡系还是关系户还是普通草根士兵，他都一视同仁，赢得了不少将士们的心，魏参将更是庆幸自己没跟错人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;交州兵防分东西两块营地，因为交州东边邻着闲城虽有东阴人烧扰却也无边境纷争，所以东边军营里只有两千人守卫。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;交州西边接壤厉国，两国边境相邻时有摩擦，故而，西边营地驻扎了一万八千人，在交州，西边营地才是交州兵防的重中之重。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;东西两个营地的士兵加在一起有两万余人，这也是为什么在纪国朝堂之上，两大势力争夺交州兵权的原因。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曹将军自杀，为避免西边营地发生变故，顾子毅必须快速赶去西边营地，他要去安抚那里的将士一刻也不能耽误，他将阿峰的来信小心翼翼地揣入怀里，骑上马，高喊一声，“走。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一队人马跟在他后面去了西边营地。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;入夜。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;安营扎寨之后。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅躺在自己的帐子里又才将那封信打开，他将信里每一个字都好好看了一遍。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;阿峰的来信其实很简单，信里的内容大致就说了纤尘这次回到交州后，装憨卖傻，将冉家的陈年旧事都抖落了出来，不仅惊动了京兆尹，还惊动了整个朝堂，弄得最近朝堂上只要冉羽涅一开口，旁人就拿他的陈年旧事做文章，因为冉羽涅的个人原因也弄得九殿下这边在争夺交州兵权上很被动。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;信里还说了，纤尘一回京都就将自己弄得很丑，让人不忍直视……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅手里握着信，想着纤尘，想着她为何要将自己弄丑，他目视前方，好像纤尘就站在他的面前一样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他自言自语呢喃道：“尘尘，你为何要将自己弄丑，你为何要将冉府的陈年旧事抖落出来，你究竟想要做什么？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;海风袭来伴着幽幽的月色，吹得营帐内呼呼做响，营帐外月朦胧影朦胧，是个思念佳人的好时机。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;躺在营帐里的顾子毅头枕在手上，如星辉般的眸子透过营帐的窗看向天上的月，那轮月好似变成了纤尘的脸，佳人如月面如霜，银辉洒下似有千千结。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅对着天上那轮圆月在心里默默地问，“尘尘，你究竟要做什么？你将冉府的老底拔出，就不怕冉大人会丢人吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一个激灵，顾子毅若有所悟，纤尘定是故意让冉大人丢人的，她装憨也好弄丑自己也罢，这都是她的一种自我保护。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅隐隐觉得纤尘有危险，虽然他不知道纤尘为什么回京都，也不知道她回京都是要做些什么？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;但是，他知道，纤尘需要保护，于是他一个鲤鱼打挺，起了身，连夜给阿峰回了信。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅信上的内容很简单，就是吩咐阿峰去找五殿下，让五殿下想办法以侍卫的身份，将阿峰安排进冉府保护纤尘，还委托自己的五弟弟照顾好纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子毅无法想象，当阿峰拿着他的书信去找五皇子顾子祺时，熙王殿下顾子祺当时有多么的诧异，多么的不可思议，多么的匪夷所思！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子祺眉清目朗的凤眼瞬间变成铜铃，一张妖艳如花的俊脸瞬间花容失色，惊掉的下巴半晌才收了回来，他没想到平日里外酷内酷不近女色的三哥哥会让自己去照顾冉府那个又憨又丑的大小姐。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“阿峰，我三哥哥他没问题吧？冉府那个大小姐听说又丑又憨走在街上安全无比，这样一个安全形的女孩子还需要本王的照顾，你的保护吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“王爷，你照做吧，冉姑娘是我家王爷心里的女人，她不能有事。”阿峰声音不大却字字有力。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;顾子祺咽了咽口水，心想，他这个三哥哥审美真是与众不同，口味重到不可理喻。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;稍做思遐，他便有了新想法。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;想想他三哥哥是什么人？文能安天下，武能打天下，这样的一个男人不爱美人爱丑女，那只能说明那个丑女有什么过人之处，于是乎，顾子祺好奇心起，对纤尘有了探宝一样的热情，答应了顾子毅的请求照顾纤尘，保护纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;京都冉家。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘每天早上起来，就会被冉老太太叫到她院子里去，不是替老太太揉背按腰，就是给老太太聊聊家乡事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;常年受腰痛的折磨，老太太身形有些佝偻，一头银发简简单单盘在脑后，慈眉善目，和蔼可亲，自从纤尘回了府，每每她都盼着纤尘进她的院子，见到纤尘就是满心欢喜。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一双苍老的手总喜欢拽着纤尘不放，除了睡觉的时间，其它时候老太太都不离开纤尘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘知道，冉府姚氏强势，祖母势单力薄，她唯有用这种方式才能护住自己，一股暖意灌满心田。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在冉府，祖母给了纤尘唯一的亲情温暖，也唯有祖母是她在纪国的牵挂，也是她心里唯一的柔软。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说来也怪，前两天纤尘把姚氏吓了个魂飞魄散，这两天也不见姚氏前来寻事挑衅。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉府一片祥和，纤尘却在这片祥和下感觉到了汹涌的暗潮。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;没人来找她挑事也好，纤尘也落得轻松，吃了睡，睡了吃，这日子过得也还惬意。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;白日里睡太多，晚上就睡不着，晚上精神奇好的纤尘，无所事事就想到了上房揭瓦。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;对，就是上房揭瓦，她要看看这若大的冉府，在满天星辉的照耀下，可有什么秘密值得窥探？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;其实，纤尘想上房揭瓦窥探秘密，并不是她一时心血来潮，而是她来冉府的第一个晚上，探查冉府暗卫的分布情况时就发现了异常。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那日，纤尘穿上夜行衣跳上冉府的房檐，她发现守护冉羽涅书房的一个暗卫形迹可疑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那暗卫看起来功夫不差，为不打草惊蛇，那晚纤尘只得远远地跟在那暗卫身后。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;只见他十分警惕地观察着四周动向，鬼鬼祟祟走进庄姨娘的院子里，东张西望片刻后才推开了庄姨娘的房门。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘躲在假山的背后，半晌也不见那暗卫出来，她半蹲着的腿都麻了，好奇心作祟的她便蹑手蹑脚凑近了那扇门，附耳在门上，她便听到了庄姨娘娇羞的低吟和一个男子粗莽的喘息声。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘被这声音羞得脸红，不用猜也知道，庄姨娘正在给她那个渣爹头上种青青草原，纤尘向着那扇门默默地翻了个白眼便悄无声息的离开了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;若与庄姨娘欢好的那位暗卫只是个普通暗卫倒还罢了，偏偏那个暗卫还是冉羽涅重金聘请的金牌暗卫，主要守护冉羽涅的夜间安全。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;夜间，好多见不得人的事，不都是在夜间发生的吗？如果那个暗卫能为自己所用，那自己在夜间岂不是就多了一双眼睛？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;有了这个想法，纤尘便想着怎么去巧妙捉奸。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘将自己的功夫与那暗卫的功夫比较了一下，确认自己的功夫在那暗卫之下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;暗卫的耳朵极度敏锐。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那夜，若不是那暗卫与庄姨娘正到了情深不知处，难以自拔的地步，估计她附耳凑近门口的那一瞬，那暗卫就已经发现了她。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348370, 1334318234309074944, '&nbsp;&nbsp;&nbsp;&nbsp;皓月当空，群星争辉，虫鸣蛙叫，这是夜的热闹，纤尘将值夜守在门外的丫鬟月圆弄晕，换上夜行衣准备去撞个大运捉个奸。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她一展轻功，纵身一跃便上了房顶。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;什么情况？刚一跃上房顶，纤尘又发现了异常，旋即，她就跳下了房顶回到了自己屋内。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;幸好纤尘这个小院偏僻，她刚刚的上蹿下跳并没有被人发现。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉府里怎么又多了个强大的暗卫？那暗位气场强大，如冬日里的寒风，迫人的气息蔓延到了她这个偏僻的小院。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;明明，前些天她都没有发觉这个暗卫的存在，今天二妹妹从宫里回来，那暗卫就出现了，这是巧合吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;应该不是，那暗卫守护的地方不是冉羽涅的书房和院子，他守护的地方正好是二妹妹的院子，难道那个暗卫是二妹妹的暗卫？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘竟没想到，冉花楹手里还有一个这么强大的暗卫保护着她。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;今天的冉府有个高手守护，看来上房揭瓦是没机会了，暗路走不通那就走明路，纤尘干脆换上自己的女儿装，大摇大摆走出了自己的院子，直接向着庄姨娘的院子走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘的水兰院也极为偏僻，离纤尘住的这坐没名的院落不远，他们之间就隔着一潭莲池，穿过莲池的九曲回廊就是庄姨娘的院子，院子隐没在一排竹林里真真是个偷情的好地方。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘对今天能否顺利捉奸并没抱多大希望，她其实是在守株待兔。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘发现有两日那暗卫都没来了，她猜测今天那暗卫来的可能性很大，因为她觉得偷腥这种事，应该是越偷越有兴趣，一日不见就应该如隔三秋。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;思索着，她人就已经到了庄姨娘的院子外，放眼望去，整个院子四周都是空空荡荡，门口连个值夜的丫鬟都没有。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纪国大户人家的院子里，都是有值夜的丫鬟，方便主子夜里有个什么事好随叫随到，就连她的院子里月圆和月缺都要轮流值夜。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘的院子里怎么会没个值夜的丫鬟？这让人生疑。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘仔细回忆了一番，好像，上次她跟踪那个暗卫来到庄姨娘的院子时，庄姨娘的院子里就没有值夜的丫鬟。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;也许庄姨娘的院子真的就没有值夜的丫鬟，也许是被她提前支去了别处，总之没有值夜丫鬟最大的好处就是方便行事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那个暗卫的实力纤尘清楚，纤尘可不敢冒然进庄姨娘的院子里去听墙角，她从地上寻得一颗石子儿，石子儿掷于手间，“嗖”的一下弹出。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;啪……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;小石子儿打在庄姨娘卧房门上，房门上留下了一道石子划过的痕迹，惊醒了房中人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“谁，谁，谁呀！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;是庄姨娘的声音，声音里带着做贼心虚的颤抖和警惕，只见后窗一个黑影跳了出来，刹那间就在这夜色里消失得无影无踪。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;黑影跳出了那扇窗，纤尘就顺着那黑影跳出的那扇窗，钻进了庄姨娘的卧房。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她坐在卧房的床上看着门口的庄姨娘。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘穿着还未系好带子的亵衣，微弓着身子，脸贴在门缝往外看，她看了又看，好半晌也没见门外再有任何声响，便放下心来转过身子准备上床睡觉。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘突然看到冉纤尘做在自己床边，吓得心脏突突乱跳，感觉都要跳出嗓子眼了，惊慌中的庄姨娘嘴都有些不太利索了，捂着心口问：“大，大，大小姐，你怎么来了？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“姨娘好，我睡不着觉就出来走走，见你窗子没关，就进来看看是不是有小偷进了你的房间。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘向庄姨娘展出她那人畜无害二哈般的模样，她可不想真把庄姨娘给吓到了，从而失去一个谈交易的机会。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原来如此，庄姨娘看了看纤尘，心想她就是个憨货，掩耳盗铃般的认为男女之事她应该不懂？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘稳了稳心神，一步一缓向纤尘走去，“大小姐说得是哪里的话？冉府里暗卫那么多，怎么可能有小偷进来，这么晚了大小姐还是早些回院休息吧。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“姨娘，你快过来。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘真诚地向庄姨娘招了招手，脸上依旧是那憨货的模样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘深吸一口气，咬了咬唇，心里莫名的惴惴不安，她缓缓向纤尘走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见庄姨娘走近，纤尘温柔地去拉庄姨娘的手，指着床上留下的合欢液道：“姨娘，你看，我发现小偷留下的东西了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘看到床上湿漉漉的一团，心里就一紧，脸色煞白，牙齿紧咬着唇，有些尴尬，小脸绯红一片。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘无视，庄姨娘的尴尬，她继续道：“姨娘，我知道那个小偷，偷的不是东西，他偷的是人，而且还是监守自盗，你说对不对？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“嗡”的一下，庄姨娘的脑子如惊雷乍响，她脑子一晕，吓得不知所措，唯有恐慌和害怕。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;虽然不是捉奸在床；但是床上遗留的东西那也是铁证如山。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘闭了闭双眼，一副要狡辩却又做贼心虚的模样，煞白的脸，颤抖的唇，语无伦次，“你，你不许胡说，我现在就可叫人来，说你无端闯入我的卧房，企图对我不轨。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哈哈哈……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘忍不住笑了，“庄姨娘，你说说，若你将人叫来了，你说我一个憨货企图对你不轨，可信度高些呢？还是我拿着这个床单告诉他们，我看见有个黑衣人从姨娘的房间蹿了出去，更有说服力呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘默不作声，心里想着怎么对付冉纤尘这个憨货。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘却玩味地将唇凑近了庄姨娘的耳后，带着三分恐吓道：“姨娘，你说这事若是被父亲知道了，你给他脑袋上带了一顶绿帽子，父亲会怎么处罚你呢？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;晴天霹雳。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘吓得一哆嗦，双腿颤得如同在筛糠。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;在纪国妾的地位不高，庄姨娘既不是良妾，也不是平妾，她只是个普通的侍妾，地位就和冉府的下人一样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;侍妾与旁人通奸，这事若让冉羽涅知道了，定不会给她活的机会，那冉羽涅对自己所出的女儿冉剪秋也没有半点关爱，庄姨娘怕了，她怕冉羽涅不会放过自己，更怕冉羽涅连自己的女儿也不会放过。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她身体像失去了重心一样，一下就瘫坐到了床边，不可思议地盯着冉纤尘，疑惑不解地问：“你不是个憨货吗？你怎么连这种男女之事都知道？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;至于纤尘为什么连这些男女之事都知道？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那是因为她有个什么都不忌讳的师父，从她第一次初潮开始，她师父便给她科普了男人和女人生理上的不同，还给她科普了生小娃娃的一些知识。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;起初，纤尘听到师父说这些的时候，一张小脸滚烫，害羞得恨不能钻到地缝里去，后来师父告诉她，医者无忌，要她正确看待男女的不同，慢慢的，她也就释怀了，现如今，她才能这般脸不红心不跳，坦然地和庄姨娘说着床单上的事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;面对庄姨娘质疑她是个憨货，纤尘没有正面回答，她对庄姨娘展出一个真诚的微笑，“姨娘，你要相信我，我对你没有恶意，我也不会揭发你的，只是你们这样做就是在引火自焚，你和他还是早早断了的好。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘欲擒故纵，好心相劝让庄姨娘对自己放下戒备。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“断不了，我们之间断不了啦，我们本青梅竹马，他说等他攒够了钱，就来向我姑姑提亲娶我，偏偏老天弄人，我姑姑为了稳住自己在冉家的地位，就将我送给了姚氏，姚氏便将我送给了你的父亲当侍妾，替冉家生儿子。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘漠然地说着话，空洞的眸子里是深不见底的落寞和绝望。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“大小姐，你知道吗？我不想当冉府的姨娘，我也不想给老爷生儿子，我甚至不想老爷碰我，他每碰我一次我都觉得自己脏，好脏，我想过自杀，可是他对我说，如果我死了他也不会独活，于是我们选择了这般苟且地活下去。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“他是因为你才来冉府做暗卫的吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘一句简单的问话，让庄姨娘瞬间就警惕了起来，那原本空洞无神的眼睛聚焦到纤尘脸上，她盯着纤尘不可置信地问：“你怎么知道他是暗卫？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘浅浅一笑，“庄姨娘，我看到他从窗户里跃出，一看便知道他身手了得，那样的身手是常年习武之人才有的，冉府暗卫众多，身手再高也难次次躲过暗卫的眼睛，可你们这些年来却一直相安无事，就只能说明一件事，他熟悉冉府的暗卫情况，他也是名暗卫。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘的一番解释再次让庄姨娘目瞪口呆，“大小姐，你不是憨货对不对？你不憨，其实你很聪明对不对？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘莞尔一笑，“庄姨娘，我可没说过我是个憨货哟。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘尴尬一笑，“对，大小姐自己是没说过自己是个憨货，都是我们自己眼拙，不知道大小姐是藏巧于拙。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘似乎脑子突然开了窍，隐隐觉得纤尘这样做定和姚氏有关，她今晚来她院子绕这么大个弯子定也是有事找她，于是道：“大小姐，你今晚来找我有何事？”', NULL, NULL);
INSERT INTO `book_content` VALUES (3348371, 1334318235013718016, '&nbsp;&nbsp;&nbsp;&nbsp;姚氏棒打鸳鸯活活拆散了庄姨娘和那个暗卫，有情人不能眷属，这让人很遗憾？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘也是碧玉佳人，鹅脸黛眉，杏眼高鼻，樱桃小口娇艳欲滴，不得不说纤尘觉得今夜她看到的庄姨娘，即便是双瞳无神，那也比白日里看到的庄姨娘好看了许多。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她就像是朵昙花，她的芳华，她的美丽只为夜里来的那个有情人而绽放，夜过日出她便枯萎，躲在这个偏僻的院子里能不见人便不见人。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘有些同情庄姨娘，她也明白了庄姨娘在冉府这么些年，为什么存在感那么低，那是因为，她的美好不屑让冉羽涅来欣赏，她的暗香只为一人，那人便是她的情哥哥。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“姨娘，如果有一天，你们有远走高飞的机会，你们愿意离开冉府，离开纪国吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘动了恻隐之心，她想帮这对苦命鸳鸯，她觉得，他们这样偷偷摸摸也不是长久之计，她希望他们有一天能光明正大的在一起，而她能给他们的便是让他们在闲城有一席容身之地。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘无力地叹了口气，幽幽地道：“哎！谈何容易？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;短短的四个字，道尽了庄姨娘心里的苦楚，暗淡而空洞的眸子里像是无尽的深渊，深渊里满载的是对现实的无奈和绝望。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“兴许真有这么一天呢！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;此话一出，庄姨娘的眸子里瞬间有了一丝的光亮，旋即又暗淡了下去，她苦笑了笑，“大小姐，那就是下辈子的事了，希望下辈子我和钱哥哥能有机会光明正大的在一起，我不再被当成个物件送出去。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;心酸的眼泪模糊了庄姨娘的眼，揪了纤尘的心，她没想到自己今天来捉奸，逮得竟是对苦命鸳鸯。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;人就是自私，为了自己的利益不惜牺牲别人的利益，庄姨娘的姑姑是，姚氏也是。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘想帮助这对苦命鸳鸯脱离苦海；但是，她不是万能的佛，事情八字还没有一撇的时候她不会说出来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;明明今晚是来捉奸的，是想拿这件事做筹码与庄姨娘和那暗卫交易，要那个暗卫为自己所用，事到如今纤尘却忍不下心来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“庄姨娘，有句话叫人定胜天，我命由我不由天，不到最后一步都不要放弃，兴许希望就在明天，兴许你们今生就能光明正大的在一起；不过你和他在冉府，以后还是不要再发生今天这种事了，冉府的暗卫里有个比他还厉害的暗卫，你们不一定逃得过他的眼睛，做事还是小心谨慎地好。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘说完起身便要离去，她今天不仅没拿庄姨娘和那个暗卫的奸情来要挟他们为己所用，她更是在庄姨娘的面前暴露了自己。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她怕吗？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她不怕，兵来将挡水来土掩。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;自己现在以丑和憨闻名纪国京都，声名狼藉，想必也无人愿意上门提亲，只要自己没嫁出去，她就能呆在冉府，她就有时间去拔下姚氏的伪装。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“大小姐，你今天来是不是有什么事？”庄姨娘见纤尘没有做答便又问了出来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘迈动的步子停了下来，她看向庄姨娘，莞尔一笑，“本来是有事的，现在没事了。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“大小姐，你想要对付姚氏对不对？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘突然一问，纤尘瞳孔猛然紧缩，心里暗潮澎拜，脸上却是云淡风轻。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不等纤尘再次抬步，庄姨娘又道：“大小姐，钱大哥是冉羽涅花重金请来的暗卫，他有他的原则要遵守；但是我保证，只要你不去刺杀冉羽涅，其它的，你要做什么他都不会为难你。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这是庄姨娘在向她示好，多一个朋友少一个强敌总是好事，纤尘对庄姨娘浅浅一笑，“好，姨娘你好些休息，今晚尘儿未来过你的院子，你也未见过尘儿。”说完纤尘便离开了庄姨娘的卧房。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘回味着纤尘的话也明白了纤尘话里的意思，顺其自然一切如常，她知道纤尘不会出卖他们。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;次日，一夜未眠的庄姨娘寻着机会便去找了她的情哥哥钱坤。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;钱坤也惴惴不安担心了一夜，昨日那声门响太过蹊跷，他跑出了庄姨娘的院子后又才发觉有异，他想再次返回庄姨娘的院子时又察觉到二小姐的暗卫回来了，而且那个暗卫还发现了他，他担心若此刻自己回去反而会弄巧成拙于是他守在冉羽涅的房门口守了冉羽涅一夜，他想着，若庄姨娘真有什么意外定会惊动冉羽涅，若冉羽涅这里风平浪静那庄姨娘那里也不会有什么大事。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;钱坤八尺男儿，年龄与庄姨娘相当，剑眉星目，身材结实一看便知道是个练家子，浑身散发着暗卫独有的冷峻与罡煞之气，走路步步生风，他见庄姨娘来了便迎了上去，二人见面，青天白日不敢太熟络，长话短说，庄姨娘将昨夜他走后，纤尘就进了她卧房的事说给了钱坤听。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;钱坤听完薄唇紧抿，若有所思，“月儿，看来冉府这个大小姐不一般，冉府这滩浑水我们就不要去蹚了，山雨欲来风满楼，冉府的天空就要刮风了，月儿，也许我们脱离冉府的机会也要来了！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;钱坤心里已然有了决定，他不仅不会为难纤尘，相反他还会帮纤尘，因为他觉得帮纤尘就是在帮他们自己。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘现在还不知道，自己身边就这样多了一个盟友。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;金风未动蝉先觉。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘隐隐感觉到姚氏今天就会对她下手，她与往常一样，白日里便去陪伴祖母，晚饭后就回了自己的院子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;夜的到来，平日里侍候纤尘洗漱睡觉的都是苏妈妈，今天，月圆和月缺却是意外地热情，殷勤地打来热水，点好香，催促着苏妈妈赶快离开，好让大小姐睡个安稳觉。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;人说，“事出反常必有妖,人若反常必有刀,言不由衷定有鬼”，看来姚氏今晚就会对自己下手，安睡香里淡淡的茉莉香味飘来，五石散的味道若隐若现，纤尘嘴角勾出一抹冷笑，成竹在胸，她已经猜到姚氏今晚要对自己做什么。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“苏妈妈，我困了现在就想睡觉，你就不用侍候我洗漱了，你回去休息吧，你们都回去休息吧，今晚就留月缺值夜。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;苏妈妈迟疑，纤尘一个眼神便让苏妈妈安了心，她跟着月圆和月缺出了房间。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;放有五石散的安睡香，需要吸入一段时间才有效，纤尘关好门，对门外的月缺说：“月缺，我睡了，不要发出声响来打扰我听到没？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“好的小姐。”月缺应着，一切进行得都那么顺利，月缺心里有窃喜也有害怕更多的是紧张，她默默地守在门口，掰着手指打发着时间。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;半炷香后，安睡香应该起效了月缺便进了纤尘的房间，“大小姐，你睡了吗？大小姐……”月缺蹑手蹑脚走到纤尘床前，隔着单薄的蚊帐，月缺看到躺在床上的纤尘一副燥热难耐的模样胸前亵衣松开一抹柔软呼之欲出，月缺快速将自己的鼻子捂住逃离了房间，深怕自己也中了毒，清白不保。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;确认纤尘已经中毒，月缺便跑出了院子，在院子的月亮门外学着布谷鸟叫了几声&nbsp;，“布谷、布谷、布谷……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;片刻后，小树林发出细细嗦嗦的声音，一个黑衣人扛着个麻袋从小树林出来，那黑衣人见了月缺，他们互相点点头，那黑衣人就直接将麻袋扛进了纤尘的房间。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;麻袋里的人昏昏欲睡，黑衣人往那人的嘴里塞了一个药丸，旋即，麻袋里的人就清醒过来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;清醒过来的男子上身没穿衣服，下身也只穿了个小裤衩，醒来就一直嚷嚷着：“热，好热呀！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;黑衣人猥琐地对那男子笑笑，“热，就去床上，床上那个美女可以让你凉快，凉快。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“美女…凉快，凉快…我要凉快…”醒来的那个男子傻里傻气，直愣愣地向着床上的女子走去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;当那男子的手刚触碰到床上女子的身体时，一股凉意袭来缓解了他浑身的燥热难耐，于是，男子贪婪地拔去女子的衣服，床上的女子很快也有了反应。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;黑衣男子退出房间将门关上，&nbsp;“看好他们，我这就去回禀小姐。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月缺点点头坐在门口守着不敢懈怠，黑衣人出了院门就狠狠啐了口唾沫，&nbsp;“娘的，让我堂堂一个金牌护卫干这等龌龊事，这他妈还是人干的事吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;抱怨归抱怨，一眨眼的功夫那黑衣人就消失在了夜色之中。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;入夜，冉羽涅的书房依旧亮着灯，韩双双端了碗冰镇红糖冰粉去冉羽涅的书房，“老爷，大小姐知道自己惹您生了气，都不敢来见您，她特地做了我们交州家乡的冰镇红糖冰粉给您，希望你能消消气。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;原本提起冉纤尘，冉羽涅就没有好心情，见来人是韩双双，他的脸色就变了，脸上立马堆起善解人意的笑，“这怪不得尘儿，都怪她娘当年走的时候对她打击太大，老天弄人呀，活生生将一个机灵的小丫头变成了一个憨货！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;哎……！说着，冉羽涅就是一声长长的悲叹。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“老爷，您不怪大小姐就好，快来尝尝这冰镇红糖冰粉的味道好不好？”韩双双滴滴娇，娇滴滴的声音听得冉羽涅心潮澎湃。', NULL, NULL);
INSERT INTO `book_content` VALUES (3348372, 1334318235739332608, '&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅一把抓住韩双双的手，贪婪的眸子直勾勾地盯在韩双双俏丽的脸上，一刻也不愿落下。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;他将韩双双手里的冰镇红糖冰粉放到书台上，眸光却始终落在韩双双的身上，没有片刻的移开。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅嘴角勾出一抹暧昧的浅笑，枯木逢春，贪婪的眼，凉薄的唇似要将韩双双吃干抹尽，他用力将韩双双往自己怀里一拽，一个趔趄，韩双双就跌入了冉羽涅的怀里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;初夏时节，女子们的衣群已经轻减了许多，韩双双胸前的柔软撞到冉羽涅结实的身板上，如白面馒头受到了挤压，那呼之欲出的香艳让冉羽涅欲罢不能。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双自己也羞红了脸，她想要挣脱冉羽涅的怀抱，冉羽涅却将她搂得更紧了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“老爷，不要……”韩双双嘴里说着不要，手却不由自主抱上了冉羽涅的腰，像只受惊的小兔子将头埋进了冉羽涅的怀里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;女人就是喜欢欲擒故纵，就是喜欢口是心非，然，有些男人就是喜欢吃这一套，冉羽涅就是其中一个。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅心情愉悦，欲的小火苗在他丹田点燃燎原了他的身，他缓缓埋下头，就要去寻韩双双的唇，突然听见书房外，容妈妈火急火燎的声音，“老爷不好啦，老爷，大小姐出事啦！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“什么，大小姐出事了？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;韩双双一把将冉羽涅推开，“老爷，小姐会出什么事？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;好事被破坏，冉羽涅刚燃烧起来的欲、火被强行熄灭，烦躁的怒火油然而生，他一个箭步冲出书房，黑着一张脸愤然呵道：“容妈妈，你说什么呢，尘儿出什么事啦？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“哎呦，老爷，奴婢说不出口呀，你快跟奴婢去看看吧，晚了就来不及啦！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;容妈妈怎么会直接说出来，她的目的就是要将冉羽涅引到纤尘的院子里去，她要让冉羽涅看场好戏。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;见容妈妈如此焦急，冉羽涅才相信冉纤尘是真的出事了，无奈地向书房回望了一眼，便跟着容妈妈去了纤尘的小院。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;书房里的韩双双则是一副事不关己云淡风轻的模样，嘴角的笑意有些风情更有些诡谲。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅赶到的时候，姚氏，冉花楹，庄姨娘还有府上一些下人都已经围在了纤尘的院子里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不得不说，冉花楹配的五石散药效真强，冉羽涅赶到的时候，都还能听到房间里女子的娇、喘和床晃动发出的嘎吱、嘎吱的声音。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉羽涅一阵羞愤，青筋直冒，气得像只没头的苍蝇在原地打转，“畜生，畜生，简直就是个畜生呐！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏和冉花楹脸上有奸计得逞的快意，庄姨娘紧抿着唇双手揉着绢帕脸上似有一层担忧，众下人们则是一副幸灾乐祸看好戏的模样。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;不远处的纤尘，将这一众人等的表情都看在了眼底。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一个苍老的身影跌跌撞撞出现在了众人的视线里，那是冉家老太太的身影，冉家这位老太太腿脚不好使，一般都不出自己的院子，这会子她也赶来了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏母女大费周章连冉老太太都惊动了，她们这是铁了心要毁纤尘的清白要让纤尘嫁给那个傻子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她们就是要让老太太也看到这一幕，让她亲眼看到自己宠爱的孙女与那个傻子做了苟且之事，这样老太太就无力反对姚氏将她嫁给那个傻子。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;老太太泪流满面，懊悔地捶打着自己的胸口，“尘儿，我的尘儿呀……”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;看到祖母伤心，纤尘的心像似被一双无形的手揪着，钝痛难耐，她从黑暗中走了出来，“祖母，爹爹，母亲，你们这么多人围在我的院子里做什么？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月亮门旁，纤尘、苏妈妈还有韩双双，她们赫然在目地站在那里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;众人奇奇看向她们，众人脸上的错愕与惊讶无以言表。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;房间里女子的娇、喘声依旧，男子的喘息声依旧，房间外纤尘衣着整洁，站在月亮门旁，一时间，这个院子里的空气都凝结了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“大姐姐，你怎么在这里？”冉花楹开口，打破了这里凝结的空气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘淡定自若又略显讶异地反问：“二妹妹，我在我的院子里有什么问题吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹被噎，贝齿紧咬着唇没再说话。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;姚氏黛眉紧锁，心想着冉纤尘在这里，那房间里的女子又会是谁？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;庄姨娘担忧的心也放了下来，脸上尽是轻松。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;唯有祖母，激动地冲向纤尘，紧抱着纤尘，将纤尘的脸、肩、手摸了又摸，看了又看，“尘儿，尘儿你没事吧？让祖母好好看看你有没有事？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“祖母，我没事。”纤尘一手搀扶着冉老太太，一手替冉老太太擦去脸上的泪水。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;她一副浑然不知的模样，万分不解地看向众人，“怎么，今天这么多人都进了我的院子，是我院子发生了什么事吗？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;众人还来不及反应就听到——<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;啊……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一阵低吼，如猛兽泄尽了力气。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;嗯……<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一阵低吟，如得到了前所未有的满足。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;两个不堪入耳的声音传来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;众人的目光再此看向房门，既然大小姐不在房里，那么，那扇门里的两个人究竟是谁？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;只要房里的那个女子不是自己的女儿，冉羽涅就全然没了顾忌，他猛的一脚踹开房门，“来人，去将床上的狗男女给我绑过来。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“是。”家丁门蜂拥而上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;从冉羽涅踹开房门的那一刻起，床上的二人就已经清醒过来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;清醒过来的月圆发现自己一丝不挂，一个赤身裸体的男子正瘫软无力地趴在她的身上，她“啊”的一声尖叫，将身上那个男子一把推到了地上。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那男子是个傻子，掉到地上屁股一疼，以为自己被欺负了，光着身子起身就要去还手打月圆，这时，家丁们正好赶到，将那傻子钳制住。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;男子赤裸着身子，外面有冉府的女眷，家丁们给那男子果上一层遮羞布，便带了出去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;这会一群婆子们进房，将房间的那个女子也给带了出来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;那男子冉羽涅一眼就认出来他是谁，小姚大人府的那个傻子二娃，“二娃，你怎么跑我们府上来啦？”冉羽涅问。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;二娃傻乎乎地又叫又哭，“放开我，放开我，我要娘亲，我要娘亲！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;女子披头散发，衣衫不整，被婆子们死拉活拽给拽了出来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“月圆？你是月圆？”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘一句你是月圆，又成功将大家的注意力引到了那个女子身上，只见那女子披头散发，将头埋得很低，拼命地摇着头，“不是，不是，我不是！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“把她的头给我抬起来。”冉羽涅怒道。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;一个婆子逮着月圆的头发，将她的头发往后一扯，月圆头皮吃痛，头自然就抬了起来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“月圆，真的是月圆！”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;众人目瞪口呆，不可置信，石化在那里。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月缺更是惊恐地瞪着眼看向月圆，不敢相信那个女子真的是月圆，半炷香后，她明明确认了床上的女子是纤尘，她才去发信号的，怎么这会子那人就变成了月圆？月缺不敢相信自己的眼睛。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“怎么会是月圆这个死丫头？”姚氏疑惑，双手紧拽，怨毒地看向月缺。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月缺一个激灵，手脚微颤，手心冒汗，她的精气神就像是被什么东西给抽空了一样，虚弱地后退，退到一颗树边瘫软地靠在那颗树上眼里尽是恐惧。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹的脸上有蛇蝎般的毒辣闪过，成事不足，这两颗棋子也没了留下去的必要。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月圆可是夫人身边的大丫头，眼高于顶，今天竟和一个傻子媾合上了？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;昔日里被月圆欺负过的下人，瞬间有种报复性的愉悦心态，大有感谢老天替他们出了口气的感觉。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;曾经喜欢过月圆的家丁，却被月圆嘲笑他们是癞蛤蟆想吃天鹅肉，如今他们看到这只天鹅，肉也已经不香了。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月圆身子还在哆嗦，眼泪却扑簌簌的往外流，脑子里唯有一个“死”字。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;是的，她没脸再活下去了，姚氏交代的事她们没有完成，自己清白被毁她哪里还有活下去的道理？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月圆家里还有一个年幼的弟弟和一个老母亲，她就这样死了她不甘心呀，可是不死，她又有何面目再活到世上？<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;再见了母亲，再见了弟弟，若有来世我定不助纣为虐，做那些伤天害理的事，这一切都是我自己咎由自取，我的报应！<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;月圆的泪如雨下，绝望中的她突然就冲破了婆子们的钳制，一头就要往那门口的石柱子上撞去。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;说时迟，那时快，纤尘一个箭步冲向前，抓住了月圆的胳膊，就在月圆即将撞到石柱子时，月圆被纤尘拉停了下来。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“月圆，你怎么可以轻身呢？你死了，事情就说不清了，你们为什么会在我的房里做出那种事？这让人匪夷所思，你们是你情我愿呢，还是另有隐情？你们得给我一个交代，否则我就要抓你们去报官。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;纤尘一句报官，把姚氏吓得后背生凉，身子一哆嗦连连退了好几步，这官一报，京兆尹一查，便能将幕后的她给查出来，姚氏有些后怕。<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;“娘，别怕，冉纤尘那个憨货她报不了官，父亲是不会让这样的家丑传出去的。”<br/><br/>&nbsp;&nbsp;&nbsp;&nbsp;冉花楹扶着姚氏，在她耳边低语宽慰着姚氏。', NULL, NULL);
